(function() {
var ch_1_Verses = [
  {num:1,words:[["O a'u,", "I,"], ["o Nifae ,", "Nephi,"], ["na fanaua e matua lelei ,", "having been born of goodly parents,"], ["o lea na aoaoina ai a'u teisi i le poto uma o lo'u tamā;", "therefore I was taught somewhat in all the learning of my father;"], ["ma ona ua ou vaai i puapuaga e tele i le gasologa o o'u aso,", "and having seen many afflictions in the course of my days,"], ["e ui i lea,", "nevertheless,"], ["sa alofagia tele a'u e le Alii i o'u aso uma;", "having been highly favored of the Lord in all my days;"], ["ioe,", "yea,"], ["ona ua ou maua se malamalama tele o le agalelei ma mealilo a le Atua,", "having had a great knowledge of the goodness and the mysteries of God,"], ["o lea ou te faia ai se talafaamaumau o a'u taualumaga i o'u aso.", "therefore I make a record of my proceedings in my days."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["ou te faia se talafaamaumau i le gagana a lo'u tamā,", "I make a record in the language of my father,"], ["ua faia i le poto o tagata Iutaia ma le gagana a tagata Aikupito.", "which consists of the learning of the Jews and the language of the Egyptians."]]},
  {num:3,words:[["Ma ua ou iloa ua moni le talafaamaumau ua ou faia;", "And I know that the record which I make is true;"], ["ma ua ou faia i lo'u lava lima;", "and I make it with mine own hand;"], ["ma ua ou faia e tusa ma lo'u iloa.", "and I make it according to my knowledge."]]},
  {num:4,words:[["Ma sa oo i le amataga o le tausaga muamua o le nofoaiga a Setekaia ,", "For it came to pass in the commencement of the first year of the reign of Zedekiah,"], ["le tupu o Iuta,", "king of Judah,"], ["(sa nofo lo'u tamā,", "(my father,"], ["o Liae,", "Lehi,"], ["i Ierusalema i ona aso uma);", "having dwelt at Jerusalem in all his days);"], ["ma o lena lava tausaga na o mai ai perofeta e toatele,", "and in that same year there came many prophets,"], ["ma vavalo atu i tagata e faapea e ao ina latou salamo,", "prophesying unto the people that they must repent,"], ["po o o le a faaumatia le aai tele o Ierusalema .", "or the great city Jerusalem must be destroyed."]]},
  {num:5,words:[["O le mea lea,", "Wherefore it came to pass that my father,"], ["sa oo ina ua alu atu lo'u tamā,", "Lehi,"], ["o Liae , sa tatalo atu o ia i le Alii,", "as he went forth prayed unto the Lord,"], ["ioe,", "yea,"], ["ma lona loto atoa lava,", "even with all his heart,"], ["mo ona tagata.", "in behalf of his people."]]},
  {num:6,words:[["Ma sa oo, a'o tatalo atu o ia i le Alii,", "And it came to pass as he prayed unto the Lord,"], ["sa oo mai se afi faaniutu ma ua nofo i luga o se papa i ona luma;", "there came a pillar of fire and dwelt upon a rock before him;"], ["ma sa vaaia ma faalogoina e ia mea e tele;", "and he saw and heard much;"], ["ma ona o mea sa ia vaaia ma faalogoina, sa galulu ma tetemu tele ai o ia.", "and because of the things which he saw and heard he did quake and tremble exceedingly."]]},
  {num:7,words:[["Ma sa oo ina toe foi atu o ia i lona lava fale i Ierusalema;", "And it came to pass that he returned to his own house at Jerusalem;"], ["ma sa ia faapa'ū o ia lava i lona moega,", "and he cast himself upon his  bed,"], ["ona ua lofituina o ia i le Agaga ma mea na ia vaaia.", "being overcome with the Spirit and the things which he had seen."]]},
  {num:8,words:[["Ma a'o faapea ona lofituina o ia i le Agaga,", "And being thus overcome with the Spirit,"], ["sa segia o ia i se faaaliga vaaia,", "he was carried away in a vision,"], ["sa vaai ai lava o ia ua avanoa le lagi ,", "even that he saw the heavens open,"], ["ma sa manatu o ia sa vaai o ia i le Atua o afio i lona nofoalii,", "and he thought he saw God sitting upon his throne,"], ["ua siosiomia i 'au agelu e lē masino e peiseai o pepese ma vivii atu i lo latou Atua.", "surrounded with numberless concourses of angels in the attitude of singing and praising their God."]]},
  {num:9,words:[["Ma sa oo ina vaai atu o ia i se Toatasi ua afio ifo mai le taulotoaiga o le lagi,", "And it came to pass that he saw One descending out of the midst of heaven,"], ["ma sa vaai o ia ua sili atu lona pupula nai lo le la i le aoauli.", "and he beheld that his luster was above that of the sun at noon– day."]]},
  {num:10,words:[["Ma sa vaaia foi e ia ni isi e toasefululua o mulimuli atu ia te ia,", "And he also saw twelve others following him,"], ["ma o lo latou pupula sa sili atu i lo fetu o le vanimonimo.", "and their brightness did exceed that of the stars in the firmament."]]},
  {num:11,words:[["Ma sa latou afifio ifo i lalo ma maliliu atu i luga o le lalolagi;", "And they came down and went forth upon the face of the earth;"], ["ma sa afio mai lē na muamua ma tu i luma o lo'u tamā,", "and the first came and stood before my father,"], ["ma tuu mai ia te ia se tusi ,", "and gave unto him a book,"], ["ma fetalai mai ia te ia e tatau ona faitau e ia.", "and bade him that he should read."]]},
  {num:12,words:[["Ma sa oo ina ua faitau o ia,", "And it came to pass that as he read,"], ["sa tumu o ia i le Agaga o le Alii.", "he was filled with the Spirit of the Lord."]]},
  {num:13,words:[["Ma sa faitau o ia,", "And he read,"], ["fai mai:", "saying:"], ["Oi talofa,", "Wo,"], ["oi talofa,", "wo,"], ["ia Ierusalema,", "unto Jerusalem,"], ["aua ua Ou vaai i au mea inosia! Ioe,", "for I have seen thine abominations! Yea,"], ["ma e tele mea sa faitau i ai lo'u tamā e uiga ia Ierusalema —e faapea o le a faaumatiaina,", "and many things did my father read concerning Jerusalem—that it should be destroyed,"], ["ma e o nonofo ai;", "and the inhabitants thereof;"], ["e toatele o le a fano i le pelu,", "many should perish by the sword,"], ["ma e toatele foi o le a ave faatagataotaua i Papelonia.", "and many should be carried away captive into Babylon."]]},
  {num:14,words:[["Ma sa oo ina ua uma ona faitau ma vaai lo'u tamā i le tele o mea tetele ma le ofoofogia,", "And it came to pass that when my father had read and seen many great and marvelous things,"], ["e tele mea sa alaga atu e ia i le Alii;", "he did exclaim many things unto the Lord;"], ["e pei o le:", "such as:"], ["Ua silisili ma ofoofogia au galuega,", "Great and marvelous are thy works,"], ["Le Alii e le Atua Malosi Aoao! Ua maualugā i le lagi lou nofoalii,", "O Lord God Almighty! Thy throne is high in the heavens,"], ["ma o lou mana,", "and thy power,"], ["ma lou agalelei,", "and goodness,"], ["ma lou alofa mutimutivale ua i ai i luga o e uma o nonofo i le lalolagi;", "and mercy are over all the inhabitants of the earth,"], ["ma,", "and,"], ["ona e te alofa mutimutivale,", "because thou art merciful,"], ["e te lē tuua i latou o e e o mai ia te oe ia fano i latou!", "thou wilt not suffer those who come unto thee that they shall perish!"]]},
  {num:15,words:[["Ma sa faapea le ituaiga o gagana a lo'u tamā i le viiga o lona Atua;", "And after this manner was the language of my father in the praising of his God;"], ["ona sa olioli lona agaga,", "for his soul did rejoice,"], ["ma sa tumu lona loto atoa,", "and his whole heart was filled,"], ["ona o mea sa vaaia e ia,", "because of the things which he had seen,"], ["ioe,", "yea,"], ["na faaali mai e le Alii ia te ia.", "which the Lord had shown unto him."]]},
  {num:16,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae, ou te lē faia se tala atoa o mea ua tusia e lo'u tamā,", "do not make a full account of the things which my father hath written,"], ["ona ua tusia e ia le tele o mea sa ia vaaia i faaaliga ma miti;", "for he hath written many things which he saw in visions and in dreams;"], ["ma ua tusia foi e ia le tele o mea sa ia vavalo ma tautala atu ai i ana fanau,", "and he also hath written many things which he prophesied and spake unto his children,"], ["o le a ou lē faia i ai se tala atoa.", "of which I shall not make a full account."]]},
  {num:17,words:[["Ae o le a ou faia se tala i a'u taualumaga i o'u aso. Faauta,", "But I shall make an account of my proceedings in my days. Behold,"], ["ou te faia se otootoga o le talafaamaumau a lo'u tamā,", "I make an abridgment of the record of my father,"], ["i luga o papatusi na ou faia i o'u lava lima;", "upon plates which I have made with mine own hands;"], ["o le mea lea,", "wherefore,"], ["a uma ona ou otooto o le talafaamaumau a lo'u tamā ona ou faia lea o se tala o lo'u lava olaga.", "after I have abridged the record of my father then will I make an account of mine own life."]]},
  {num:18,words:[["O lea,", "Therefore,"], ["ou te manao ia outou iloa,", "I would that ye should know,"], ["ina ua uma ona faaali mai e le Alii i lo'u tamā, o Liae,", "that after the Lord had shown so many marvelous  things unto my father,"], ["le tele na'uā o mea ofoofogia,", "Lehi,"], ["ioe,", "yea,"], ["e uiga i le faaumatiaga o Ierusalema, faauta,", "concerning the destruction of Jerusalem,"], ["sa alu atu o ia i tagata,", "behold he went forth among the people,"], ["ma amata ona vavalo ma tautino atu ia te i latou e uiga i mea sa ia vaaia ma faalogoina.", "and began to prophesy and to declare unto them concerning the things which he had both seen and heard."]]},
  {num:19,words:[["Ma sa oo ina faatauemu tagata Iutaia ia te ia ona o mea sa molimau atu ai o ia e uiga ia te i latou;", "And it came to pass that the Jews did mock him because of the things which he testified of them;"], ["ona sa molimau moni atu o ia i lo latou amioleaga ma a latou mea inosia;", "for he truly testified of their wickedness and their abominations;"], ["ma sa molimau atu o ia o mea sa ia vaaia ma faalogoina,", "and he testified that the things which he saw and heard,"], ["ma mea foi sa ia faitauina i le tusi,", "and also the things which he read in the book,"], ["ua faaali manino mai ai le afio mai o se Mesia ,", "manifested plainly of the coming of the Messiah,"], ["ma le togiolaina foi o le lalolagi.", "and also the redemption of the world."]]},
  {num:20,words:[["Ma ina ua faalogo mai tagata Iutaia i nei mea sa latou feitai ia te ia;", "And when the Jews heard these things they were angry with him;"], ["ioe,", "yea,"], ["e pei lava ona sa latou faia i perofeta anamua,", "even as with the prophets of old,"], ["o e na latou tutuli esea,", "whom they had cast out,"], ["ma fetogi i maa,", "and stoned,"], ["ma fasioti;", "and slain;"], ["ma sa latou saili foi lona ola,", "and they also sought his life,"], ["ina ia latou aveeseina. Ae faauta,", "that they might take it away. But behold,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["o le a ou faaali atu ia te outou le i ai o le alofa mutimutivale agamalu o le Alii i luga o i latou uma o e ua ia filifilia,", "will show unto you that the tender mercies of the Lord are over all those whom he hath chosen,"], ["ona o lo latou faatuatua,", "because of their faith,"], ["e faamalolosi tele ai i latou e oo lava i le mana e laveaiina ai.", "to make them mighty even unto the power of deliverance."]]},
];
renderVerseSet(ch_1_Verses, 'ch1-verses');

var ch_2_Verses = [
  {num:1,words:[["Aua faauta,", "For behold,"], ["sa oo ina fetalai mai le Alii i lo'u tamā,", "it came to pass that the Lord spake unto my father,"], ["ioe,", "yea,"], ["i se miti lava,", "even in a dream,"], ["ma fetalai mai ia te ia: Amuia oe,", "and said unto him:"], ["Liae,", "Blessed art thou Lehi,"], ["ona o mea ua e faia;", "because of the things which thou hast done;"], ["ma ona sa e faamaoni ma tautino atu i lenei nuu mea na Ou poloaiina ai oe,", "and because thou hast been faithful and declared unto this people the things which I commanded thee,"], ["faauta,", "behold,"], ["ua latou saili e aveese lou ola.", "they seek to take away thy life."]]},
  {num:2,words:[["Ma sa oo ina poloaiina e le Alii lo'u tamā,", "And it came to pass that the Lord commanded my father,"], ["i se miti lava,", "even in a dream,"], ["e tatau ia te ia ona ave lona aiga ma o ese atu i le vao.", "that he should take his family and depart into the wilderness."]]},
  {num:3,words:[["Ma sa oo ina usiusitai o ia i le afioga a le Alii,", "And it came to pass that he was obedient unto the word of the Lord,"], ["o le mea lea na faia ai e ia e pei ona poloaiina ai o ia e le Alii.", "wherefore he did as the Lord commanded him."]]},
  {num:4,words:[["Ma sa oo ina alu ese atu o ia i le vao. Ma sa tuu e ia lona fale,", "And it came to pass that he departed into the wilderness. And he left his house,"], ["ma le fanua o lona tofi,", "and the land of his inheritance,"], ["ma ana auro,", "and his gold,"], ["ma ana ario,", "and his silver,"], ["ma ana mea taua,", "and his precious things,"], ["ma sa lē avea e ia se mea,", "and took nothing with him,"], ["vagana ai lona aiga,", "save it were his family,"], ["ma tapenapenaga,", "and provisions,"], ["ma faleie,", "and tents,"], ["ma o ese atu i le vao.", "and departed into the wilderness."]]},
  {num:5,words:[["Ma sa alu ifo o ia i lalo i tafatafa o tuaoi e latalata i le matafaga o le Sami Ulaula;", "And he came down by the borders near the shore of the Red Sea;"], ["ma sa malaga o ia i le vao i tuaoi e latalata lava i le Sami Ulaula;", "and he traveled in the wilderness in the borders which are nearer the Red Sea;"], ["ma sa malaga o ia i le vao faatasi ma lona aiga,", "and he did travel in the wilderness with his family,"], ["sa i ai lo'u tinā,", "which consisted of my mother,"], ["o Sarai,", "Sariah,"], ["ma o'u uso matutua,", "and my elder brothers,"], ["o Lamana ,", "who were Laman,"], ["Lemuelu,", "Lemuel,"], ["ma Sama.", "and Sam."]]},
  {num:6,words:[["Ma sa oo ina ua mavae aso e tolu talu ona malaga o ia i le vao,", "And it came to pass that when he had traveled three days in the wilderness,"], ["sa faatu e ia lona faleie i se vanu i tafatafa o se vaitafe.", "he pitched his tent in a valley by the side of a river of water."]]},
  {num:7,words:[["Ma sa oo ina faia e ia se fatafaitaulaga i maa ,", "And it came to pass that he built an altar of stones,"], ["ma osi ai se taulaga i le Alii,", "and made an offering unto the Lord,"], ["ma avatu le faafetai i le Alii lo matou Atua.", "and gave thanks unto the Lord our God."]]},
  {num:8,words:[["Ma sa oo ina faaigoa e ia le vaitafe,", "And it came to pass that he called the name of the river,"], ["o Lamana,", "Laman,"], ["ma sa tafe atu i le Sami Ulaula;", "and it emptied into the Red  Sea;"], ["ma o le vanu sa i tuaoi latalata i lona mulivai.", "and the valley was in the borders near the mouth thereof."]]},
  {num:9,words:[["Ma ina ua vaai atu lo'u tamā ua tafe atu vai o le vaitafe i le punavai o le Sami Ulaula,", "And when my father saw that the waters of the river emptied into the fountain of the Red Sea,"], ["sa tautala atu o ia ia Lamana,", "he spake unto Laman,"], ["ua fai atu: E,", "saying:"], ["ma'umau e pe a na mafai ona pei oe o lenei vaitafe,", "O that thou mightest be like unto this river,"], ["e tafe atu pea i le punavai o le amiotonu uma!", "continually running into the fountain of all righteousness!"]]},
  {num:10,words:[["Ma sa tautala atu foi o ia ia Lemuelu:", "And he also spake unto Lemuel:"], ["E,", "O that thou mightest be like unto this valley,"], ["ma'umau e pe a na mafai ona pei oe o lenei vanu, e tumau ma mausali,", "firm and steadfast,"], ["ma lē maluelue i le tausiga o poloaiga a le Alii!", "and immovable  in keeping the commandments of the Lord!"]]},
  {num:11,words:[["O lenei sa tautala atu o ia i nei mea ona o le ua maaa o Lamana ma Lemuelu;", "Now this he spake because of the stiffneckedness of Laman and Lemuel;"], ["aua faauta sa muimui i laua i lo laua tamā i mea e tele,", "for behold they did murmur in many things against their father,"], ["ona o ia o se tagata mau faaaliga,", "because he was a visionary man,"], ["ma ua taitai ese e ia i latou i fafo mai le laueleele o Ierusalema,", "and had led them out of the land of Jerusalem,"], ["ae tuu le fanua o lo latou tofi,", "to leave the land of their inheritance,"], ["ma a latou auro,", "and their gold,"], ["ma a latou ario,", "and their silver,"], ["ma a latou mea taua,", "and their precious things,"], ["ia fano i le vao. Ma sa fai mai i laua ua faia e ia lenei mea ona o mafaufauga valea o lona loto.", "to perish in the wilderness. And this they said he had done because of the foolish imaginations of his heart."]]},
  {num:12,words:[["Ma sa faapea ona muimui o Lamana ma Lemuelu,", "And thus Laman and Lemuel,"], ["o e ua matutua,", "being the eldest,"], ["i lo laua tamā. Ma sa muimui i laua ona sa laua lē iloa faiga a lena Atua o lē na foafoaina i laua.", "did murmur against their father. And they did murmur because they knew not the dealings of that God who had created them."]]},
  {num:13,words:[["E lei talitonu foi i laua e mafai ona faaumatia lena aai tele,", "Neither did they believe that Jerusalem,"], ["o Ierusalema,", "that great city,"], ["e tusa ma upu a perofeta. Ma sa pei i laua o tagata Iutaia o e sa i Ierusalema,", "could be destroyed according to the words of the prophets. And they were like unto the Jews who were at Jerusalem,"], ["o e na saili e aveese le ola o lo'u tamā.", "who sought to take away the life of my father."]]},
  {num:14,words:[["Ma sa oo ina tautala atu lo'u tamā ia te i laua i le vanu o Lemuelu,", "And it came to pass that my father did speak unto them in the valley of Lemuel,"], ["ma le mana ,", "with power,"], ["ona sa tumu o ia i le Agaga,", "being filled with the Spirit,"], ["seia oo ina tetete o laua tino i ona luma. Ma sa ia faafememeaiina i laua,", "until their frames did shake before him. And he did confound them,"], ["sa matatau ai i laua e tautatala mai ia te ia;", "that they durst not utter against him;"], ["o le mea lea,", "wherefore,"], ["sa laua faia ai e pei ona sa poloaiina ai i laua e ia.", "they did as he commanded them."]]},
  {num:15,words:[["Ma sa nofo lo'u tamā i se faleie.", "And my father dwelt in a tent."]]},
  {num:16,words:[["Ma sa oo,", "And it came to pass that I,"], ["o a'u,", "Nephi,"], ["o Nifae,", "being exceedingly young,"], ["ona sa ou talavou lava,", "nevertheless being large in stature,"], ["e ui i lea sa ou tino ese,", "and also having great desires to know of the mysteries of God,"], ["ma sa ia te a'u foi le naunau tele e fia iloa mealilo a le Atua, o le mea lea,", "wherefore,"], ["na ou tagi atu ai i le Alii;", "I did cry unto the Lord;"], ["ma faauta sa asiasi mai o ia ia te a'u,", "and behold he did visit me,"], ["ma faamalūlūina lo'u loto,", "and did soften my heart that I did believe all the words which had been spoken by my father;"], ["o le mea lea na ou talitonu ai i upu uma na tautalaina e lo'u tamā ;", "wherefore,"], ["o le mea lea na ou lē fouvale ai e faasaga ia te ia e pei o o'u uso.", "I did not rebel against him like unto my brothers."]]},
  {num:17,words:[["Ma sa ou tautala atu ia Sama,", "And I spake unto Sam,"], ["ma faailoa atu ia te ia mea na faaali mai e le Alii ia te a'u e ala mai i lona Agaga Paia. Ma sa oo ina talitonu o ia i a'u upu.", "making known unto him the things which the Lord had manifested unto me by his Holy Spirit. And it came to pass that he believed in my words."]]},
  {num:18,words:[["Ae,", "But,"], ["faauta,", "behold,"], ["sa le fia faalogologo mai Lamana ma Lemuelu i a'u upu; ma ona o lo'u faanoanoa ona o le maaa o o laua loto,", "Laman and Lemuel would not hearken unto my words;"], ["sa ou tagi atu i le Alii mo i laua.", "and being grieved because of the hardness of their hearts I cried unto the Lord for them."]]},
  {num:19,words:[["Ma sa oo ina fofoga mai le Alii ia te a'u,", "And it came to pass that the Lord spake unto me,"], ["ua fetalai mai:", "saying:"], ["Amuia lava oe,", "Blessed art thou,"], ["Nifae,", "Nephi,"], ["ona o lou faatuatua ,", "because of thy faith,"], ["ona ua e saili mai ia te a'u ma le filiga,", "for thou hast sought me diligently,"], ["ma le maualalo o le loto.", "with lowliness of heart."]]},
  {num:20,words:[["Ma o le tulaga e te tausia a'u poloaiga,", "And inasmuch as ye shall keep my commandments,"], ["o le a e manuia ,", "ye shall prosper,"], ["ma o le a taitai atu oe i se laueleele o le folafolaga;", "and shall be led to a land of promise;"], ["ioe,", "yea,"], ["o se laueleele lava ua Ou saunia mo oe;", "even a land which I have prepared for you;"], ["ioe,", "yea,"], ["o se laueleele ua silisili atu i isi laueleele uma.", "a land which is choice above all other lands."]]},
  {num:21,words:[["Ma o le tulaga e oo i ai le fouvale o ou uso ia te oe,", "And inasmuch as thy brethren shall rebel against thee,"], ["o le a vavae ese i laua mai luma o le Alii.", "they shall be cut off from the presence of the Lord."]]},
  {num:22,words:[["Ma o le tulaga e oo i ai lau tausiga o a'u poloaiga,", "And inasmuch as thou shalt keep my command– ments,"], ["o le a fai oe o se pule ma se aoao i ou uso.", "thou shalt be made a ruler and a teacher over thy brethren."]]},
  {num:23,words:[["Aua faauta,", "For behold,"], ["i lena aso la te fouvale faasaga mai ai ia te a'u,", "in that day that they shall rebel against me,"], ["Ou te fetuu ai i laua i se fetuu tiga,", "I will curse them even with a sore curse,"], ["ma o le a leai sa laua pule i au fanau vagana ai ua latou fouvale mai foi ia te a'u.", "and they shall have no power over thy seed except they shall rebel against me also."]]},
  {num:24,words:[["Ma afai e oo ina faapea ona latou fouvale mai ia te a'u,", "And if it so be that they rebel against me,"], ["o le a fai i laua ma sasa i au fanau,", "they shall be a scourge unto thy seed,"], ["e faaoso ai i latou i ala e manatua ai.", "to stir them up in the ways of remembrance."]]},
];
renderVerseSet(ch_2_Verses, 'ch2-verses');

var ch_3_Verses = [
  {num:1,words:[["Ma sa oo ina foi mai a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi, returned from speaking with the Lord,"], ["i le faleie o lo'u tamā mai le talanoaga ma le Alii.", "to the tent of my father."]]},
  {num:2,words:[["Ma sa oo ina tautala mai o ia ia te a'u, fai mai:", "And it came to pass that he spake unto me,"], ["Faauta,", "saying:"], ["sa ou miti se miti ,", "Behold I have dreamed a dream,"], ["na poloaiina ai a'u e le Alii, ia e foi atu ma ou uso i Ierusalema.", "in the which the Lord hath commanded me that thou and thy brethren shall return to Jerusalem."]]},
  {num:3,words:[["Aua faauta,", "For behold,"], ["o loo i ai ia Lapana talafaamaumau o tagata Iutaia ma le gafa foi o o'u muātua'a,", "Laban hath the record of the Jews and also a genealogy of my forefathers,"], ["ma ua togitogia i luga o papatusi apamemea.", "and they are engraven upon plates of brass."]]},
  {num:4,words:[["O le mea lea,", "Wherefore,"], ["ua poloaia a'u e le Alii,", "the Lord hath commanded me that thou and thy brothers should go unto the house of Laban,"], ["e tatau ia te oe ma ou uso ona o atu i le fale o Lapana, ma saili talafaamaumau,", "and seek the records,"], ["ma aumai i latou i lalo iinei i le vao.", "and bring them down hither into the wilderness."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["faauta ua muimui ou uso,", "behold thy brothers murmur,"], ["fai mai o se mea faigata ua ou faatonuina ai i laua,", "saying it is a hard thing which I have required of them;"], ["ae faauta ou te lei faatonuina ai i laua,", "but behold I have not required it of them,"], ["ae o se poloaiga mai le Alii.", "but it is a commandment of the Lord."]]},
  {num:6,words:[["O lea ia e alu ai,", "Therefore go,"], ["lo'u atalii e,", "my son,"], ["ma o le a alofagia oe e le Alii,", "and thou shalt be favored of the Lord,"], ["ona ua e lē muimui.", "because thou hast not murmured."]]},
  {num:7,words:[["Ma sa oo ina fai atu a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["i lo'u tamā:", "said unto my father:"], ["O le a ou alu ma fai mea ua poloaiina e le Alii,", "I will go and do the things which the Lord hath commanded,"], ["aua ua ou iloa e lē tuuina mai e le Alii ni poloaiga i le fanauga a tagata,", "for I know that the Lord giveth no commandments unto the children of men,"], ["vagana o le a saunia e ia se ala mo i latou ina ia mafai ai ona latou faataunuuina o le mea ua ia poloaiina ai i latou.", "save he shall prepare a way for them that they may accomplish the thing which he commandeth them."]]},
  {num:8,words:[["Ma sa oo ina ua faalogo mai lo'u tamā i nei upu sa fiafia tele o ia,", "And it came to pass that when my father had heard these words he was exceedingly glad,"], ["ona sa iloa e ia ua faamanuiaina a'u e le Alii.", "for he knew that I had been blessed of the Lord."]]},
  {num:9,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["ma o'u uso,", "and my brethren took our journey in the wilderness,"], ["sa alu la matou malaga i le vao ma o matou faleie,", "with our tents,"], ["matou te o a'e i le laueleele o Ierusalema.", "to go up to the land of Jerusalem."]]},
  {num:10,words:[["Ma sa oo ina ua matou o a'e i le laueleele o Ierusalema, o a'u ma o'u uso,", "And it came to pass that when we had gone up to the land of Jerusalem,"], ["sa matou talatalanoa o le tasi i le isi.", "I and my brethren did consult one with another."]]},
  {num:11,words:[["Ma sa matou faia se vili—po o ai o i matou e tatau ona alu atu i totonu o le fale o Lapana. Ma sa oo ina pa'ū le vili ia Lamana;", "And we cast lots—who of us should go in unto the house of Laban. And it came to pass that the lot fell upon Laman;"], ["ma sa alu atu Lamana i totonu o le fale o Lapana,", "and Laman went in unto the house of Laban,"], ["ma talanoa o ia ma ia a'o nofo o ia i lona fale.", "and he talked with him as he sat in his house."]]},
  {num:12,words:[["Ma sa manaomia e ia mai ia Lapana talafaamaumau sa togitogia i luga o papatusi apamemea,", "And he desired of Laban the records which were engraven upon the plates of brass,"], ["sa i ai le gafa o lo'u tamā.", "which contained the genealogy of my father."]]},
  {num:13,words:[["Ma faauta,", "And behold,"], ["sa oo ina ita Lapana,", "it came to pass that Laban was angry,"], ["ma tuli ese o ia i fafo mai ona luma;", "and thrust him out from his presence;"], ["ma sa lē manao o ia e tuu ai ia te ia talafaamaumau. O le mea lea,", "and he would not that he should have the records. Wherefore,"], ["sa fai mai o ia ia te ia:", "he said unto him:"], ["Faauta o oe o se faomea,", "Behold thou art a robber,"], ["ma o le a ou fasioti ia te oe.", "and I will slay thee."]]},
  {num:14,words:[["Peitai sa sola ese Lamana i fafo mai ona luma,", "But Laman fled out of his presence, and told the things which Laban had done,"], ["ma ta'u mai ia te i matou mea na faia e Lapana.", "unto us."], ["Ma sa amata ona matou faanoanoa tele,", "And we began to be exceedingly sorrowful,"], ["ma o o'u uso sa fai o le a toe foi atu i lo'u tamā i le vao.", "and my brethren were about to return unto my father in the wilderness."]]},
  {num:15,words:[["Ae faauta sa ou fai atu ia te i latou:", "But behold I said unto them that:"], ["E pei ona soifua le Alii,", "As the Lord liveth,"], ["ma e pei foi ona tatou ola,", "and as we live,"], ["tatou te lē o ifo lava i lalo i lo tatou tamā i le vao seiloga ua uma ona tatou faataunuuina o le mea na poloaiina ai i tatou e le Alii.", "we will not go down unto our father in the wilderness until we have accomplished the thing which the Lord hath commanded us."]]},
  {num:16,words:[["O le mea lea,", "Wherefore,"], ["ia tatou faamaoni i le tausiga o poloaiga a le Alii;", "let us be faithful in keeping the commandments of the Lord;"], ["o lea ia tatou o i lalō i le fanua o le tofi o lo tatou tamā,", "therefore let us go down to the land of our father's inheritance,"], ["aua faauta ua tuua e ia o auro ma ario,", "for behold he left gold and silver,"], ["ma ituaiga uma o oloa eseese. Ma o lenei mea atoa sa faia e ia ona o poloaiga a le Alii.", "and all manner of riches. And all this he hath done because of the commandments of the Lord."]]},
  {num:17,words:[["Ona sa iloa e ia o le a faaumatia Ierusalema,", "For he knew that Jerusalem must be destroyed,"], ["ona o le amioleaga o tagata.", "because of the wickedness of the people."]]},
  {num:18,words:[["Aua faauta,", "For behold,"], ["ua latou teena upu a perofeta. O le mea lea,", "they have rejected the words of the prophets. Wherefore,"], ["afai e nofo lo'u tamā i le laueleele ina ua uma ona poloaiina o ia 'ia sola ese i fafo mai le laueleele,", "if my father should dwell in the land after he hath been commanded to flee out of the land,"], ["faauta,", "behold,"], ["e fano foi o ia. O le mea lea,", "he would also perish. Wherefore,"], ["ua tatau ai ona sola ese o ia i fafo mai le laueleele.", "it must needs be that he flee out of the land."]]},
  {num:19,words:[["Ma faauta,", "And behold,"], ["o le poto o i le Atua ua tatau ai ona tatou maua o ia talafaamaumau ,", "it is wisdom in God that we should obtain these records,"], ["ia mafai ai ona tatou faasaoina mo a tatou fanau le gagana a o tatou tamā;", "that we may preserve unto our children the language of our fathers;"]]},
  {num:20,words:[["Ma ia mafai ai foi ona tatou faasaoina mo i latou upu na tulei mai fofoga o perofeta paia uma,", "And also that we may preserve unto them the words which have been spoken by the mouth of all the holy prophets,"], ["na tuu mai ia te i latou e le Agaga ma le mana o le Atua,", "which have been delivered unto them by the Spirit and power of God,"], ["talu mai le amataga o le lalolagi,", "since the world began,"], ["e oo mai lava i le taimi lenei.", "even down unto this present time."]]},
  {num:21,words:[["Ma sa oo ina faapea le ituaiga o gagana sa ou faatauanauina ai o'u uso,", "And it came to pass that after this manner of language did I persuade my brethren,"], ["ina ia laua faamaoni i le tausiga o poloaiga a le Atua.", "that they might be faithful in keeping the command– ments of God."]]},
  {num:22,words:[["Ma sa oo ina matou o ifo i lalo i le fanua o lo matou tofi,", "And it came to pass that we went down to the land of our inheritance,"], ["ma matou faaputuputu faatasi a matou auro ,", "and we did gather together our gold,"], ["ma a matou ario,", "and our silver,"], ["ma a matou mea taua.", "and our precious things."]]},
  {num:23,words:[["Ma ina ua uma ona matou faaputuputu faatasi o ia mea,", "And after we had gathered these things together,"], ["sa matou toe o a'e i luga i le fale o Lapana.", "we went up again unto the house of Laban."]]},
  {num:24,words:[["Ma sa oo ina matou o atu i totonu ia Lapana,", "And it came to pass that we went in unto Laban,"], ["ma mananao ia te ia ia tuu mai e ia ia te i matou talafaamaumau ua togitogia i luga o papatusi apamemea,", "and desired him that he would give unto us the records which were engraven upon the plates of brass,"], ["ae matou avatu ia te ia a matou auro,", "for which we would give unto him our gold,"], ["ma a matou ario,", "and our silver,"], ["ma a matou mea taua uma.", "and all our precious things."]]},
  {num:25,words:[["Ma sa oo ina ua vaai mai Lapana ia matou meatotino,", "And it came to pass that when Laban saw our property,"], ["ma sa tele lava,", "and that it was exceedingly great,"], ["sa tuinanau i ai o ia,", "he did lust after it,"], ["sa oo ina ia tutuli ese i matou i fafo,", "insomuch that he thrust us out,"], ["ma auina mai ana auauna e fasioti i matou,", "and sent his servants to slay us,"], ["ina ia mafai ona ia maua o a matou meatotino.", "that he might obtain our property."]]},
  {num:26,words:[["Ma sa oo ina matou sosola ese mai luma o auauna a Lapana,", "And it came to pass that we did flee before the servants of Laban,"], ["ma sa faamalosia i matou e tuu a matou meatotino,", "and we were obliged to leave behind our property,"], ["ma pauu atu ai i lima o Lapana.", "and it fell into the hands of Laban."]]},
  {num:27,words:[["Ma sa oo ina matou sosola i le vao,", "And it came to pass that we fled into the wilderness,"], ["ma lē maua mai i matou e auauna a Lapana,", "and the servants of Laban did not overtake us,"], ["ma matou lalafi i le ana o se papa.", "and we hid ourselves in the cavity of a rock."]]},
  {num:28,words:[["Ma sa oo ina ita Lamana ia te a'u,", "And it came to pass that Laman was angry with me,"], ["ma i lo'u tamā foi;", "and also with my father;"], ["ma sa faapea foi Lemuelu,", "and also was Lemuel,"], ["ona sa faalogo o ia i upu a Lamana. O le mea lea na fai mai ai e Lamana ma Lemuelu 'upu faigata e tele ia te i ma'ua,", "for he hearkened unto the words of Laman. Wherefore Laman and Lemuel did speak many hard words unto us,"], ["o laua uso laiti,", "their younger brothers,"], ["ma sa laua sasa i ma'ua i se tootoo lava.", "and they did smite us even with a rod."]]},
  {num:29,words:[["Ma sa oo ina laua sasaina i ma'ua i se tootoo,", "And it came to pass as they smote us with a rod,"], ["faauta,", "behold,"], ["sa afio mai se agelu a le Alii ma tu i o laua luma,", "an angel of the Lord came and stood before them,"], ["ma sa fetalai mai o ia ia te i laua,", "and he spake unto them,"], ["fai mai:", "saying:"], ["Se a ua oulua sasa ai lo oulua uso laitiiti i le tootoo? Lua te lē iloa ea ua filifilia o ia e le Alii e avea ma pule i luga o oulua,", "Why do ye smite your younger brother with a rod? Know ye not that the Lord hath chosen him to be a ruler over you,"], ["ma o lenei ona o a oulua amioletonu? Faauta ia outou toe o atu i luga i Ierusalema,", "and this because of your iniquities? Behold ye shall go up to Jerusalem again,"], ["ma o le a tuu atu e le Alii Lapana i o outou lima.", "and the Lord will deliver Laban into your hands."]]},
  {num:30,words:[["Ma ina ua uma ona fetalai mai o le agelu ia te i matou,", "And after the angel had spoken unto us,"], ["sa afio ese atu o ia.", "he departed."]]},
  {num:31,words:[["Ma ina ua mavae ona afio ese atu o le agelu,", "And after the angel had departed,"], ["sa toe amata ona muimui o Lamana ma Lemuelu,", "Laman and Lemuel again began to murmur,"], ["fai mai:", "saying:"], ["E mafai faapefea e le Alii ona tuu mai Lapana i o tatou lima? Faauta,", "How is it possible that the Lord will deliver Laban into our hands? Behold,"], ["o ia o se tagata malosi,", "he is a mighty man,"], ["ma e mafai e ia ona faatonu le toalimagafulu,", "and he can command fifty,"], ["ioe,", "yea,"], ["e mafai e ia ona fasioti le toalimagafulu;", "even he can slay fifty;"], ["se a la e lē mafai ai i tatou?", "then why not us?"]]},
];
renderVerseSet(ch_3_Verses, 'ch3-verses');

var ch_4_Verses = [
  {num:1,words:[["Ma sa oo ina ou tautala atu i o'u uso,", "And it came to pass that I spake unto my brethren,"], ["ua ou fai atu:", "saying:"], ["Inā tatou toe o a'e ia i Ierusalema,", "Let us go up again unto Jerusalem,"], ["ma ia tatou faamaoni i le tausiga o poloaiga a le Alii;", "and let us be faithful in keeping the commandments of the Lord;"], ["aua faauta ua silisili atu lona malosi i le lalolagi atoa,", "for behold he is mightier than all the earth,"], ["ona lē sili ai lea i se a ona malosi atu nai lo o Lapana ma lana toalimagafulu,", "then why not mightier than Laban and his fifty,"], ["ioe,", "yea,"], ["po o ana sefulu o afe?", "or even than his tens of thousands?"]]},
  {num:2,words:[["O lea ia tatou o a'e;", "Therefore let us go up;"], ["ia tatou faamalolosi e pei o Mose ;", "let us be strong like unto Moses;"], ["ona e moni sa fetalai atu o ia i vai o le Sami Ulaula ona vaeluaina ai lea i le tasi itu ma le isi itu,", "for he truly spake unto the waters of the Red Sea and they divided hither and thither,"], ["ma o mai ai o tatou tamā i fafo, mai le faatagataotauaina,", "and our fathers came through,"], ["i le ilititai matutu,", "out of captivity,"], ["ma mulimuli atu ai 'au a Farao,", "on dry ground,"], ["ma malelemo ai i vai o le Sami Ulaula.", "and the armies of Pharaoh did follow and were drowned in the waters of the Red Sea."]]},
  {num:3,words:[["O lenei faauta ua oulua iloa ua moni lenei mea;", "Now behold ye know that this is true;"], ["ma ua oulua iloa foi na fetalai mai se agelu ia te oulua;", "and ye also know that an angel hath spoken unto you;"], ["o le mea lea e mafai ea faapefea ona oulua masalosalo? Inā tatou o a'e ia;", "wherefore can ye doubt? Let us go up;"], ["e mafai e le Alii ona laveai i tatou,", "the Lord is able to deliver us,"], ["e pei lava o o tatou tamā,", "even as our fathers,"], ["ma faaumatia Lapana,", "and to destroy Laban,"], ["e pei lava o tagata Aikupito.", "even as the Egyptians."]]},
  {num:4,words:[["O lenei ina ua uma ona ou tautala atu o nei upu,", "Now when I had spoken these words,"], ["sa laua feitai pea,", "they were yet wroth,"], ["ma sa muimui pea;", "and did still continue to murmur;"], ["e ui i lea sa laua mulimuli mai ia te a'u sei oo ina matou taunuu i tuapa o Ierusalema.", "never– theless they did follow me up until we came without the walls of Jerusalem."]]},
  {num:5,words:[["Ma o le po na faia ai;", "And it was by night;"], ["ma sa ou faatonu atu ia latou lalafi i tuapa. Ma ina ua uma ona latou lalafi,", "and I caused that they should hide themselves without the walls. And after they had hid themselves,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["sa ou tolotolo atu i le aai ma ou alu atu agai i le fale o Lapana.", "crept into the city and went forth towards the house of Laban."]]},
  {num:6,words:[["Ma sa taitai a'u e le Agaga,", "And I was led by the Spirit,"], ["ona sa ou lē mua'i iloa muamua mea e tatau ona ou faia.", "not knowing beforehand the things which I should do."]]},
  {num:7,words:[["E ui i lea sa ou alu atu,", "Nevertheless I went forth,"], ["ma ina ua ou latalata atu i le fale o Lapana sa ou vaaia se tagata,", "and as I came near unto the house of Laban I beheld a man,"], ["ma ua pa'ū o ia i le eleele i o'u luma,", "and he had fallen to the earth before me,"], ["ona ua 'onā o ia i le uaina.", "for he was drunken with wine."]]},
  {num:8,words:[["Ma ina ua ou oo atu ia te ia sa ou iloaina o ia o Lapana.", "And when I came to him I found that it was Laban."]]},
  {num:9,words:[["Ma sa ou vaai atu i lana pelu ,", "And I beheld his sword,"], ["ma sa ou se'ia i fafo mai lona faamoega;", "and I drew it forth from the sheath thereof;"], ["ma o lona 'au sa faia i le auro mao'i,", "and the hilt thereof was of pure gold,"], ["ma o lona gaosiga sa matua lelei lava;", "and the workmanship thereof was exceedingly fine,"], ["ma sa ou vaai o lona lau o le sila ua sili ona lelei.", "and I saw that the blade thereof was of the most precious steel."]]},
  {num:10,words:[["Ma sa oo ina uunai a'u e le Agaga ia ou fasioti ia Lapana;", "And it came to pass that I was constrained by the Spirit that I should kill Laban;"], ["ae sa ou fai ifo i lo'u loto:", "but I said in my heart:"], ["E lei i ai lava se taimi na ou faamasaaina ai le toto o se tagata. Ma sa ou me'ime'i ma manao ia ou lē fasioti ia te ia.", "Never at any time have I shed the blood of man. And I shrunk and would that I might not slay him."]]},
  {num:11,words:[["Ma sa toe fetalai mai le Agaga ia te a'u:", "And the Spirit said unto me again:"], ["Faauta ua tuu mai o ia e le Alii i ou lima. Ioe,", "Behold the Lord hath delivered him into thy hands. Yea,"], ["ma sa ou iloa foi sa taumafai o ia e aveese lo'u lava ola;", "and I also knew that he had sought to take away mine own life;"], ["ioe,", "yea,"], ["ma sa lē fia faalogo o ia i poloaiga a le Alii;", "and he would not hearken unto the command– ments of the Lord;"], ["ma sa ave foi e ia a matou meatotino.", "and he also had taken away our property."]]},
  {num:12,words:[["Ma sa oo ina toe fetalai mai le Agaga ia te a'u:", "And it came to pass that the Spirit said unto me again:"], ["Fasioti ia te ia,", "Slay him,"], ["ona ua tuu mai o ia e le Alii i ou lima;", "for the Lord hath delivered him into thy hands;"]]},
  {num:13,words:[["Faauta e fasioti e le Alii e amioleaga e faataunuu ai ona faamoemoega amiotonu. E sili le fano o le tagata e toatasi nai lo le faaitiitia ma le fano o se atunuu i le lē talitonu.", "Behold the Lord slayeth the wicked to bring forth his righteous purposes. It is better that one man should perish than that a nation should dwindle and perish in unbelief."]]},
  {num:14,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona faalogo atu o a'u,", "when I,"], ["o Nifae,", "Nephi,"], ["i nei upu,", "had heard these words,"], ["sa ou manatua fetalaiga a le Alii na fetalai mai ai o ia ia te a'u i le vao,", "I remembered the words of the Lord which he spake unto me in the wilderness,"], ["na fetalai mai e faapea:", "saying that:"], ["O le tulaga e oo i ai le tausiga a au fanau o a'u poloaiga ,", "Inasmuch as thy seed shall keep my commandments,"], ["o le a latou manuia i le laueleele o le folafolaga.", "they shall prosper in the land of promise."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["ma sa ou manatu foi e le mafai ona latou tausia poloaiga a le Alii e tusa ma le tulafono a Mose,", "and I also thought that they could not keep the commandments of the Lord according to the law of Moses,"], ["vagana ua ia te i latou le tulafono.", "save they should have the law."]]},
  {num:16,words:[["Ma sa ou iloa foi ua togitogia le tulafono i luga o papatusi apamemea.", "And I also knew that the law was engraven upon the plates of brass."]]},
  {num:17,words:[["Ma o lenei foi,", "And again,"], ["sa ou iloa ua tuu mai e le Alii Lapana i o'u lima mo le pogai lenei—ina ia ou maua talafaamaumau e tusa ma ana poloaiga.", "I knew that the Lord had delivered Laban into my hands for this cause—that I might obtain the records according to his commandments."]]},
  {num:18,words:[["O lea na ou usiusitai ai i le siufofoga o le Agaga,", "Therefore I did obey the voice of the Spirit,"], ["ma tago atu ia Lapana i lauulu o le ulu,", "and took Laban by the hair of the head,"], ["ma ou vavae ese lona ulu i lana lava pelu .", "and I smote off his head with his own sword."]]},
  {num:19,words:[["Ma ina ua uma ona ou vavae ese o lona ulu i lana lava pelu,", "And after I had smitten off his head with his own sword,"], ["sa ou ave ofu o Lapana ma ou ofuina i lo'u lava tino;", "I took the garments of Laban and put them upon mine own body;"], ["ioe,", "yea,"], ["i ofu uma lava;", "even every whit;"], ["ma sa ou fusi lona ofutau i o'u sulugatiti.", "and I did gird on his armor about my loins."]]},
  {num:20,words:[["Ma ina ua uma ona ou faia o lenei mea,", "And after I had done this,"], ["sa ou alu atu i luma i le mea sa teu ai 'oa a Lapana. Ma a'o ou alu atu i luma agai i le mea sa teu ai 'oa a Lapana,", "I went forth unto the treasury of Laban. And as I went forth towards the treasury of Laban,"], ["faauta,", "behold,"], ["sa ou vaai atu i le auauna a Lapana o lē sa i ai ki o le mea sa teu ai 'oa. Ma sa ou faatonuina o ia i le leo o Lapana,", "I saw the servant of Laban who had the keys of the treasury. And I commanded him in the voice of Laban,"], ["e tatau ona alu o ia faatasi ma a'u i le mea ua teu ai 'oa.", "that he should go with me into the treasury."]]},
  {num:21,words:[["Ma sa manatu o ia o a'u o lona matai,", "And he supposed me to be his master,"], ["o Lapana,", "Laban,"], ["ona sa vaai mai o ia i ofu ma le pelu foi sa fusi i o'u sulugatiti.", "for he beheld the garments and also the sword girded about my loins."]]},
  {num:22,words:[["Ma sa talanoa mai o ia ia te a'u e uiga i toeaina o Iutaia,", "And he spake unto me concerning the elders of the Jews,"], ["i lona iloa o lona matai,", "he knowing that his master,"], ["o Lapana,", "Laban,"], ["sa i ai i fafo faatasi ma i latou i le po.", "had been out by night among them."]]},
  {num:23,words:[["Ma sa ou tautala atu ia te ia e peiseai o Lapana.", "And I spake unto him as if it had been Laban."]]},
  {num:24,words:[["Ma sa ou fai atu foi ia te ia e tatau ona ou ave togitogiga sa i luga o papatusi apamemea,", "And I also spake unto him that I should carry the engravings,"], ["i o'u uso matutua,", "which were upon the plates of brass, to my elder brethren,"], ["o e sa i tuāpā.", "who were without the walls."]]},
  {num:25,words:[["Ma sa ou faatonuina foi o ia ia mulimuli mai ia te a'u.", "And I also bade him that he should follow me."]]},
  {num:26,words:[["Ma o ia,", "And he,"], ["i le manatu ua ou tautala atu e uiga i uso o le ekalesia,", "supposing that I spake of the brethren of the church,"], ["ma o a'u moni o Lapana lena o lē ua ou fasiotia,", "and that I was truly that Laban whom I had slain,"], ["o le mea lea na mulimuli mai ai o ia ia te a'u.", "wherefore he did follow me."]]},
  {num:27,words:[["Ma sa talanoa mai o ia ia te a'u i taimi e tele e uiga i toeaina o Iutaia,", "And he spake unto me many times concerning the elders of the Jews,"], ["a'o ou alu atu i o'u uso,", "as I went forth unto my brethren,"], ["o e sa i tuapa.", "who were without the walls."]]},
  {num:28,words:[["Ma sa oo ina ua vaai mai Lamana ia te a'u sa fefe tele o ia,", "And it came to pass that when Laman saw me he was exceedingly frightened,"], ["ma Lemuelu foi ma Sama. Ma sa latou sosola mai o'u luma;", "and also Lemuel and Sam. And they fled from before my presence;"], ["ona sa latou manatu o Lapana,", "for they supposed it was Laban,"], ["ma ua ia fasiotia a'u ma ua saili foi e aveese o latou ola.", "and that he had slain me and had sought to take away their lives also."]]},
  {num:29,words:[["Ma sa oo ina ou valaau atu ia te i latou,", "And it came to pass that I called after them,"], ["ma sa latou lagona mai a'u;", "and they did hear me;"], ["o le mea lea na latou lē toe sosola ai mai o'u luma.", "wherefore they did cease to flee from my presence."]]},
  {num:30,words:[["Ma sa oo ina ua vaai atu le auauna a Lapana i o'u uso sa amata ona gatete o ia,", "And it came to pass that when the servant of Laban beheld my brethren he began to tremble,"], ["ma sa fai o le a sola ese mai o'u luma ma foi atu i le aai o Ierusalema.", "and was about to flee from before me and return to the city of Jerusalem."]]},
  {num:31,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae,", "being a man large in stature,"], ["ona o a'u o se tagata tino ese, ma sa ou maua foi le malosi tele mai le Alii,", "and also having received much strength of the Lord,"], ["o lea na ou tago atu ai i le auauna a Lapana,", "therefore I did seize upon the servant of Laban,"], ["ma taofi o ia,", "and held him,"], ["ina ia le sola o ia.", "that he should not flee."]]},
  {num:32,words:[["Ma sa oo ina ou fai atu ia te ia,", "And it came to pass that I spake with him,"], ["afai e faalogo mai o ia i a'u upu,", "that if he would hearken unto my words,"], ["e pei ona soifua le Alii,", "as the Lord liveth,"], ["ma e pei foi ona ou ola,", "and as I live,"], ["e faapea lava pe afai e faalogo mai o ia ia matou upu,", "even so that if he would hearken unto our words,"], ["matou te faasaoina lona ola.", "we would spare his life."]]},
  {num:33,words:[["Ma sa ou fai atu ia te ia,", "And I spake unto him,"], ["i se tautoga lava,", "even with an oath,"], ["e le tatau ona fefe o ia;", "that he need not fear;"], ["e avea o ia ma tagata saoloto e pei o i matou pe afai e alu ifo o ia i le vao faatasi ma i matou.", "that he should be a free man like unto us if he would go down in the wilderness with us."]]},
  {num:34,words:[["Ma sa ou fai atu foi ia te ia,", "And I also spake unto him,"], ["ua faapea atu:", "saying:"], ["E moni lava na poloaiina i matou e le Alii e fai lenei mea;", "Surely the Lord hath commanded us to do this thing;"], ["ma pe le tatau ea ona matou filiga i le tausiga o poloaiga a le Alii? O lea,", "and shall we not be diligent in keeping the commandments of the Lord? Therefore,"], ["afai e te alu ifo i le vao i lo'u tamā o le a maua sou nofoaga faatasi ma i matou.", "if thou wilt go down into the wilderness to my father thou shalt have place with us."]]},
  {num:35,words:[["Ma sa oo ina lototele Sorama i upu na ou fai atu. O lenei o Sorama o le igoa lea o le auauna;", "And it came to pass that Zoram did take courage at the words which I spake. Now Zoram was the name of the servant;"], ["ma sa folafola mai o ia o le a alu ifo o ia i lalo i le vao i lo matou tamā. Ioe,", "and he promised that he would go down into the wilderness unto our father. Yea,"], ["sa fai mai foi e ia se tautoga ia te i matou o le a nofo o ia faatasi ma i matou mai le taimi lena i luma.", "and he also made an oath unto us that he would tarry with us from that time forth."]]},
  {num:36,words:[["O lenei sa matou mananao ia nofo o ia faatasi ma i matou mo le pogai lenei,", "Now we were desirous that he should tarry with us for this cause,"], ["ina ia lē iloa e tagata Iutaia e uiga i la matou solaaga i le vao,", "that the Jews might not know concerning our flight into the wilderness,"], ["ne'i latou tuliloa mai i matou ma faaumatia i matou.", "lest they should pursue us and destroy us."]]},
  {num:37,words:[["Ma sa oo ina ua uma ona fai mai e Sorama se tautoga ia te i matou,", "And it came to pass that when Zoram had made an oath unto us,"], ["sa uma lo matou popole e uiga ia te ia.", "our fears did cease concerning him."]]},
  {num:38,words:[["Ma sa ao ina matou ave papatusi apamemea ma le auauna a Lapana,", "And it came to pass that we took the plates of brass and the servant of Laban,"], ["ma matou o atu i le vao,", "and departed into the wilderness,"], ["ma malaga atu i le faleie o lo matou tamā.", "and journeyed unto the tent of our father."]]},
];
renderVerseSet(ch_4_Verses, 'ch4-verses');

var ch_5_Verses = [
  {num:1,words:[["Ma sa oo ina ua matou o ifo i lalo i le vao i lo matou tamā,", "And it came to pass that after we had come down into the wilderness unto our father,"], ["faauta,", "behold,"], ["sa tumu o ia i le olioli,", "he was filled with joy,"], ["ma o lo'u tinā foi,", "and also my mother,"], ["o Saraia ,", "Sariah,"], ["sa fiafia tele,", "was exceedingly glad,"], ["ona sa faanoanoa moni lava o ia ona o i matou.", "for she truly had mourned because of us."]]},
  {num:2,words:[["Ona fa te ia ua fano i matou i le vao;", "For she had supposed that we had perished in the wilderness;"], ["ma sa muimui foi o ia e faasaga i lo'u tamā,", "and she also had complained against my father,"], ["ua fai atu ia te ia o ia o se tagata mau faaaliga;", "telling him that he was a visionary man;"], ["fai mai:", "saying:"], ["Faauta ua e taitaieseina i matou mai le fanua o lo tatou tofi,", "Behold thou hast led us forth from the land of our inheritance,"], ["ma ua lē toe i ai a'u tama tane,", "and my sons are no more,"], ["ma o le a tatou fano i le vao.", "and we perish in the wilderness."]]},
  {num:3,words:[["Ma sa faapea le ituaiga o gagana na muimui ai lo'u tinā i lo'u tamā.", "And after this manner of language had my mother complained against my father."]]},
  {num:4,words:[["Ma sa oo ina fai atu lo'u tamā ia te ia,", "And it had come to pass that my father spake unto her,"], ["ua fai atu:", "saying:"], ["Ua ou iloa o a'u o se tagata mau faaaliga;", "I know that I am a visionary man;"], ["aua a na ou lē vaai i mea a le Atua i se faaaliga vaaia po ua ou lē iloa le agalelei o le Atua,", "for if I had not seen the things of God in a vision I should not have known the goodness of God,"], ["ae ua ou nofo pea i Ierusalema,", "but had tarried at Jerusalem,"], ["ma fano ai faatasi ma o'u uso.", "and had perished with my brethren."]]},
  {num:5,words:[["Ae faauta,", "But behold,"], ["ua ou maua se laueleele o le folafolaga,", "I have obtained a land of promise,"], ["o mea ia ua ou olioli ai;", "in the which things I do rejoice;"], ["ioe,", "yea,"], ["ma ua ou iloa o le a laveaiina e le Alii o'u atalii i fafo mai lima o Lapana,", "and I know that the Lord will deliver my sons out of the hands of Laban,"], ["ma toe aumai i latou i lalo ia te i ta'ua i le vao.", "and bring them down again unto us in the wilderness."]]},
  {num:6,words:[["Ma sa faapea le ituaiga o gagana sa faamafanafana atu ai lo'u tamā,", "And after this manner of language did my father,"], ["o Liae,", "Lehi,"], ["i lo'u tinā,", "comfort my mother,"], ["o Sarai,", "Sariah,"], ["e uiga ia i matou,", "concerning us,"], ["a'o matou malaga i le vao e o a'e i le laueleele o Ierusalema,", "while we journeyed in the  wilderness up to the land of Jerusalem,"], ["ia maua mai le talafaamaumau o tagata Iutaia.", "to obtain the record of the Jews."]]},
  {num:7,words:[["Ma ina ua matou foi mai i le faleie o lo'u tamā,", "And when we had returned to the tent of my father,"], ["faauta, sa atoatoa lo laua olioli,", "behold their joy was full,"], ["ma sa faamafanaina lo'u tinā.", "and my mother was comforted."]]},
  {num:8,words:[["Ma sa fai mai o ia,", "And she spake,"], ["e faapea:", "saying:"], ["Ua ou iloa nei ma le mautinoa sa poloaiina e le Alii la'u tane ia sola i le vao;", "Now I know of a surety that the Lord hath commanded my husband to flee into the wilderness;"], ["ioe,", "yea,"], ["ma ua 'ou iloa foi ma le mautinoa sa puipuia e le Alii a'u tama tane,", "and I also know of a surety that the Lord hath protected my sons,"], ["ma laveai i latou i fafo mai lima o Lapana,", "and delivered them out of the hands of Laban,"], ["ma tuu mai ia te i latou le mana e mafai ai ona latou faia o le mea na poloaiina ai i latou e le Alii. Ma sa faapea le ituaiga o gagana sa tautala ai o ia.", "and given them power whereby they could accomplish the thing which the Lord hath commanded them. And after this manner of language did she speak."]]},
  {num:9,words:[["Ma sa oo ina matua'i olioli lava i laua,", "And it came to pass that they did rejoice exceedingly,"], ["ma osi atu taulaga ma taulaga mu i le Alii;", "and did offer sacrifice and burnt offerings unto the Lord;"], ["ma sa laua avatu le faafetai i le Atua o Isaraelu.", "and they gave thanks unto the God of Israel."]]},
  {num:10,words:[["Ma ina ua uma ona laua tuuina atu o le faafetai i le Atua o Isaraelu,", "And after they had given thanks unto the God of Israel,"], ["sa ave e lo'u tamā,", "my father,"], ["o Liae,", "Lehi,"], ["talafaamaumau sa togitogia i luga o papatusi apamemea,", "took the records which were engraven upon the plates of brass,"], ["ma suesue i ai o ia mai i le amataga.", "and he did search them from the beginning."]]},
  {num:11,words:[["Ma sa vaai o ia,", "And he beheld that they did contain the five books of Moses,"], ["ua i ai tusi e lima a Mose,", "which gave an account of the creation of the world,"], ["sa tuu mai ai se tala o le foafoaga o le lalolagi, faapea foi ma Atamu ma Eva,", "and also of Adam and Eve,"], ["o e o o tatou uluai matua;", "who were our first parents;"]]},
  {num:12,words:[["Ma se talafaamaumau foi o tagata Iutaia mai le amataga,", "And also a record of the Jews from the beginning,"], ["e oo ifo lava i lalo i le amataga o le nofoaiga a Setekaia,", "even down to the commence– ment of the reign of Zedekiah,"], ["le tupu o Iuta;", "king of Judah;"]]},
  {num:13,words:[["Ma valoaga foi a perofeta paia,", "And also the prophecies of the holy prophets,"], ["mai le amataga,", "from the beginning,"], ["seia oo ifo i lalo i le amataga o le nofoaiga a Setekaia ;", "even down to the commencement of the reign of Zedekiah;"], ["ma le tele foi o valoaga na fetalaia e le fofoga o Ieremia .", "and also many prophecies which have been spoken by the mouth of Jeremiah."]]},
  {num:14,words:[["Ma sa oo ina maua foi e lo'u tamā,", "And it came to pass that my father,"], ["o Liae,", "Lehi,"], ["i luga o papatusi apamemea se gafa o ona tamā;", "also found upon the plates of brass a genealogy of his fathers;"], ["o le mea lea na iloa ai e ia o ia o se e tupuga mai ia Iosefa ;", "wherefore he knew that he was a descendant of Joseph;"], ["ioe,", "yea,"], ["o Iosefa lava lea le atalii o Iakopo ,", "even that Joseph who was the son of Jacob,"], ["o lē na faatau atu i Aikupito,", "who was sold into Egypt,"], ["ma o lē na faasaoina e le aao o le Alii,", "and who was preserved by the hand of the Lord,"], ["ina ia mafai ona faasaoina e ia lona tamā,", "that he might preserve his father,"], ["o Iakopo,", "Jacob,"], ["ma lona aiga uma mai le fano i le oge.", "and all his household from perishing with famine."]]},
  {num:15,words:[["Ma sa taitaieseina foi i latou i fafo mai le faatagataotauaina ma i fafo mai le laueleele o Aikupito,", "And they were also led out of captivity and out of the land of Egypt,"], ["e lena lava Atua e tasi o lē na faasaoina i latou.", "by that same God who had preserved them."]]},
  {num:16,words:[["Ma sa faapea ona iloa ai e lo'u tamā,", "And thus my father,"], ["o Liae,", "Lehi,"], ["le gafa o ona tamā. Ma o Lapana foi o se e tupuga mai ia Iosefa ,", "did discover the genealogy of his fathers. And Laban also was a descendant of Joseph,"], ["o le mea lea na tausi ai e ia ma ona tamā talafaamaumau.", "wherefore he and his fathers had kept the records."]]},
  {num:17,words:[["Ma o lenei ina ua vaai lo'u tamā i nei mea uma,", "And now when my father saw all these things,"], ["sa tumu o ia i le Agaga,", "he was filled with the Spirit,"], ["ma amata ona vavalo e uiga i ana fanau—", "and began to prophesy concerning his seed—"]]},
  {num:18,words:[["E faapea o nei papatusi apamemea o le a oo atu i atunuu uma,", "That these plates of brass should go forth unto all nations,"], ["ituaiga,", "kindreds,"], ["gagana, ma nuu,", "tongues,"], ["o e e tupuga mai i ana fanau.", "and people who were of his seed."]]},
  {num:19,words:[["O le mea lea,", "Wherefore,"], ["na fai mai ai o ia o nei papatusi apamemea o le a lē faaumatiaina lava;", "he said that these plates of brass should never perish;"], ["pe toe faanenefuina e le taimi. Ma e tele mea sa valoia e ia e uiga i ana fanau.", "neither should they be dimmed any more by time. And he prophesied many things concerning his seed."]]},
  {num:20,words:[["Ma sa oo ina e oo mai i lea lava taimi o tausia pea e a'u ma lo'u tamā poloaiga sa poloaiina ai i ma'ua e le Alii.", "And it came to pass that thus far I and my father had kept the commandments where with the Lord had commanded us."]]},
  {num:21,words:[["Ma ua matou maua talafaamaumau sa poloaiina ai i matou e le Alii,", "And we had obtained the records which the Lord had commanded us,"], ["ma matou suesueina i latou ma matou iloa ai ua manaomia i latou;", "and searched them and found that they were desirable;"], ["ioe,", "yea,"], ["ua aoga tele lava ia te i matou,", "even of great worth unto us,"], ["ina ia mafai ai ona matou faasaoina o poloaiga a le Alii mo a matou fanau.", "insomuch that we could preserve the commandments of the Lord unto our children."]]},
  {num:22,words:[["O le mea lea,", "Wherefore,"], ["o le poto sa i le Alii sa tatau ai ona matou ave o nei papatusi faatasi ma i matou,", "it was wisdom in the Lord that we should carry them with us,"], ["a'o matou malaga i le vao agai i le laueleele o le folafolaga.", "as we journeyed in the wilderness towards the land of promise."]]},
];
renderVerseSet(ch_5_Verses, 'ch5-verses');

var ch_6_Verses = [
  {num:1,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae,", "do not give the genealogy of my fathers in this part of my record;"], ["ou te lē tuuina atu le gafa o o'u tamā i le vaega lenei o la'u talafaamaumau; pe ou te tuuina atu i soo se taimi o mulimuli mai i luga o nei papatusi o loo ou tusia;", "neither at any time shall I give it after upon these plates which I am writing;"], ["ona ua tuuina atu i le talafaamaumau sa tausia e lo'u tamā ;", "for it is given in the record which has been kept by my father;"], ["o le mea lea,", "wherefore,"], ["ou te lē tusia ai i lenei tusi.", "I do not write it in this work."]]},
  {num:2,words:[["Ona ua lava ia te a'u ona fai atu o i matou o ni isi e tupuga mai ia Iosefa .", "For it sufficeth me to say that we are descendants of Joseph."]]},
  {num:3,words:[["Ma e le afaina ia te a'u pe faapitoa ona ou tuu atu o se tala atoa o mea uma a lo'u tamā,", "And it mattereth not to me that I am particular to give a full account of all the things of my father,"], ["ona e le mafai ona tusia ia mea i luga o papatusi nei,", "for they cannot be written upon these plates,"], ["ona ou te manaomia le avanoa e mafai ona ou tusia ai mea a le Atua.", "for I desire the room that I may write of the things of God."]]},
  {num:4,words:[["Ona o le atoatoa o lo'u faamoemoe ia mafai ona ou faatauanauina tagata ia o mai i le Atua o Aperaamo,", "For the fulness of mine intent is that I may persuade men to come unto the God of Abraham,"], ["ma le Atua o Isaako,", "and the God of Isaac,"], ["ma le Atua o Iakopo,", "and the God of Jacob,"], ["ma faaolaina.", "and be saved."]]},
  {num:5,words:[["O le mea lea,", "Wherefore,"], ["o mea e fiafia i ai le lalolagi ou te lē tusia,", "the things which are pleasing unto the world I do not write,"], ["ae o mea e fiafia i ai le Atua ma i latou o e e lē o ni isi o le lalolagi.", "but the things which are pleasing unto God and unto those who are not of the world."]]},
  {num:6,words:[["O le mea lea,", "Wherefore,"], ["ou te tuu atu ai se poloaiga i a'u fanau,", "I shall give command– ment unto my seed,"], ["ia latou lē faatumuina nei papatusi i mea e lē aoga i le fanauga a tagata.", "that they shall not occupy these plates with things which are not of worth unto the children of men."]]},
];
renderVerseSet(ch_6_Verses, 'ch6-verses');

var ch_7_Verses = [
  {num:1,words:[["Ma o lenei ou te manao ia outou iloa,", "And now I would that ye might know,"], ["ina ua uma ona faai'u e lo'u tamā,", "that after my father,"], ["o Liae,", "Lehi,"], ["le vavalo mai e uiga i ana fanau,", "had made an end of prophesying concerning his seed,"], ["sa oo ina toe fetalai mai le Alii ia te ia, ua faapea mai,", "it came to pass that the Lord spake unto him again,"], ["ua lē tatau ia te ia,", "saying that it was not meet for him,"], ["o Liae,", "Lehi,"], ["ona ia ave nao lona auaiga i le vao;", "that he should take his family into the wilderness alone;"], ["ae e tatau i ona atalii ona ave ni afafine e faiavā i ai,", "but that his sons should take daughters to wife,"], ["ina ia mafai ona latou fanauina ni fanau mo le Alii i le laueleele o le folafolaga.", "that they might raise up seed unto the Lord in the land of promise."]]},
  {num:2,words:[["Ma sa oo ina poloaiina o ia e le Alii e tatau ia te a'u,", "And it came to pass that the Lord commanded him that I,"], ["o Nifae,", "Nephi,"], ["ma o'u uso,", "and my brethren, should again return unto the land of Jerusalem,"], ["ona toe foi atu i le laueleele o Ierusalema ma aumai i le vao Isamaeli ma lona aiga.", "and bring down Ishmael and his family into the wilderness."]]},
  {num:3,words:[["Ma sa oo ina toe o atu a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["faatasi ma o'u uso,", "did again, with my brethren,"], ["i le vao matou te o a'e i Ierusalema.", "go forth into the wilderness to go up to Jerusalem."]]},
  {num:4,words:[["Ma sa oo ina matou o a'e i luga i le fale o Isamaeli,", "And it came to pass that we went up unto the house of Ishmael,"], ["ma sa talileleia i matou i le silafaga a Isamaeli,", "and we did gain favor in the sight of Ishmael,"], ["sa oo ina matou fai atu ia te ia fetalaiga a le Alii.", "insomuch that we did speak unto him the words of the Lord."]]},
  {num:5,words:[["Ma sa oo ina faamaluluina e le Alii le loto o Isamaeli,", "And it came to pass that the Lord did soften the heart of Ishmael,"], ["ma lona auaiga foi,", "and also his household,"], ["sa oo ina latou malaga ifo faatasi mai i matou i le vao i le faleie o lo matou tamā.", "insomuch that they took their journey with us down into the wilderness to the tent of our father."]]},
  {num:6,words:[["Ma sa oo ina matou malaga i le vao,", "And it came to pass that as we journeyed in the wilderness,"], ["faauta o Lamana ma Lemuelu,", "behold Laman and Lemuel,"], ["ma le toalua o afafine o Isamaeli,", "and two of the daughters of Ishmael,"], ["ma atalii e toalua o Isamaeli ma o laua aiga,", "and the two sons of Ishmael and their families,"], ["ua fouvale ia te i matou;", "did rebel against us;"], ["ioe,", "yea,"], ["ia te a'u,", "against me,"], ["o Nifae,", "Nephi,"], ["ma Sama,", "and Sam,"], ["ma lo latou tamā,", "and their father,"], ["o Isamaeli,", "Ishmael,"], ["ma lana avā,", "and his wife,"], ["ma isi ona afafine e toatolu.", "and his three other daughters."]]},
  {num:7,words:[["Ma sa oo i lea fouvalega,", "And it came to pass in the which rebellion,"], ["sa latou mananao ai e toe foi atu i le laueleele o Ierusalema.", "they were desirous to return unto the land of Jerusalem."]]},
  {num:8,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae,", "being grieved for the hardness of their hearts,"], ["ona o lo'u faanoanoa ona o le maaa o o latou loto, o lea na ou tautala atu ai ia te i latou,", "therefore I spake unto them,"], ["ua ou fai atu,", "saying,"], ["ioe,", "yea,"], ["ia Lamana lava ma ia Lemuelu:", "even unto Laman and unto Lemuel:"], ["Faauta,", "Behold ye are mine elder brethren,"], ["o oulua o o'u uso matutua,", "and how is it that ye are so hard in your hearts,"], ["ma ua faapefea ona oulua maaa tele i o oulua loto,", "and so blind in your minds,"], ["ma tauaso tele i o oulua mafaufau,", "that ye have need that I,"], ["ua oulua manaomia ai a'u, lo oulua uso laitiiti,", "your younger brother,"], ["ona tatau ona tautala atu ia te oulua,", "should speak unto you,"], ["ioe,", "yea,"], ["ma fai se faataitaiga mo oulua?", "and set an example for you?"]]},
  {num:9,words:[["Pe ua faapefea ea ona oulua lē faalogo i fetalaiga a le Alii?", "How is it that ye have not hearkened unto the word of the Lord?"]]},
  {num:10,words:[["Pe ua faapefea ea ona galo ia te oulua sa oulua vaai i se agelu a le Alii?", "How is it that ye have forgotten that ye have seen an angel of the Lord?"]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma ua faapefea ea ona galo ia te oulua mea tetele na faia e le Alii mo i tatou,", "and how is it that ye have forgotten what great things the Lord hath done for us,"], ["i le laveaiina o i tatou mai lima o Lapana,", "in delivering us out of the hands of  Laban,"], ["ma ina ia tatou maua ai foi talafaamaumau?", "and also that we should obtain the record?"]]},
  {num:12,words:[["Ioe,", "Yea,"], ["ma ua faapefea ona galo ia te oulua e mafai e le Alii ona fai mea uma e tusa ai ma lona finagalo,", "and how is it that ye have forgotten that the Lord is able to do all things according to his will,"], ["mo le fanauga a tagata,", "for the children of  men,"], ["pe afai latou te faaaoga le faatuatua ia te ia? O le mea lea,", "if it so be that they exercise faith in him? Wherefore,"], ["ia tatou faamaoni ia te ia.", "let us be faithful to him."]]},
  {num:13,words:[["Ma afai tatou te faamaoni ia te ia,", "And if it so be that we are faithful to him,"], ["tatou te maua le laueleele o le folafolaga;", "we shall obtain the land of promise;"], ["ma o le a outou iloa i se taimi o i lumanai o le a faataunuuina lava le fetalaiga a le Alii e uiga i le faaumatiaga o Ierusalema;", "and ye shall know at some future period that the word of the Lord shall be fulfilled concerning the destruction of Jerusalem;"], ["ona e ao ina faataunuuina mea uma na fetalai mai ai le Alii e uiga i le faaumatiaga o Ierusalema.", "for all things which the Lord hath spoken concerning the destruction of Jerusalem must be fulfilled."]]},
  {num:14,words:[["Aua faauta,", "For behold,"], ["ua lata ona lē toe taumafai o le Agaga o le Alii ia te i latou;", "the Spirit of the Lord ceaseth soon to strive with them;"], ["aua faauta,", "for behold,"], ["ua latou teena perofeta,", "they have rejected the prophets,"], ["ma ua latou lafoina Ieremia i le falepuipui. Ma sa latou saili e aveese le ola o lo'u tamā,", "and Jeremiah have they cast into prison. And they have sought to take away the life of my father,"], ["ua oo ai ina latou tuli ese o ia mai le laueleele.", "insomuch that they have driven him out of the land."]]},
  {num:15,words:[["O lenei faauta,", "Now behold,"], ["ou te fai atu ia te outou afai tou te foi atu i Ierusalema o le a outou fano foi faatasi ma i latou. Ma o lenei,", "I say unto you that if ye will return unto Jerusalem ye shall also perish with them. And now,"], ["afai tou te filifili i ai,", "if ye have choice,"], ["o atu i luga i le laueleele,", "go up to the  land,"], ["ma ia manatua upu ua ou tautala atu ai ia te outou,", "and remember the words which I speak unto you,"], ["afai tou te o atu o le a outou fano foi;", "that if ye go ye will also perish;"], ["ona ua faapea ona uunaia o a'u e le Agaga o le Alii e tatau ona ou tautala atu ai.", "for thus the Spirit of the Lord constraineth me that I should speak."]]},
  {num:16,words:[["Ma sa oo ina ua uma ona tautala atu o a'u,", "And it came to pass that when I,"], ["o Nifae,", "Nephi,"], ["i nei upu, i o'u uso,", "had spoken these words unto my brethren,"], ["sa laua feitai ia te a'u.", "they were angry with me."], ["Ma sa oo ina fetagofi mai o laua lima ia te a'u,", "And it came to pass that they did lay their hands upon me,"], ["aua faauta,", "for behold,"], ["sa laua feitai tele,", "they were exceedingly wroth,"], ["ma laua noatia a'u i maea,", "and they did bind me with cords,"], ["aua sa laua saili e aveese lo'u ola,", "for they sought to take away my life,"], ["ina ia latou tuu a'u i le vao ia 'aia e manu feai.", "that they might leave me in the wilderness to be devoured by wild beasts."]]},
  {num:17,words:[["Peitai sa oo ina ou tatalo atu i le Alii,", "But it came to pass that I prayed unto the Lord,"], ["ua ou fai atu:", "saying:"], ["Le Alii e,", "O Lord,"], ["e tusa ma lo'u faatuatua ia te oe,", "according to my faith which is in thee,"], ["sei e laveaia a'u mai lima o o'u uso;", "wilt thou deliver me from the hands of my brethren;"], ["ioe,", "yea,"], ["foai mai ia te a'u le malosi ia mafai ai ona ou motusia o nei maea ua noatia ai a'u.", "even give me strength that I may burst these bands with which I am bound."]]},
  {num:18,words:[["Ma sa oo ina ua ou fai atu ia upu,", "And it came to pass that when I had said these words,"], ["faauta,", "behold,"], ["sa matala ese maea mai o'u lima ma o'u vae,", "the bands were loosed from off my hands and feet,"], ["ma ou tu i luma o o'u uso,", "and I stood before my brethren,"], ["ma ou toe tautala atu ia i laua.", "and I spake unto them again."]]},
  {num:19,words:[["Ma sa oo ina laua toe feitai mai ia te a'u,", "And it came to pass that they were angry with me again,"], ["ma taumafai e fetagofi mai o laua lima ia te a'u,", "and sought to lay hands upon me;"], ["ae faauta o se tasi o afafine o Isamaeli,", "but behold, one of the daughters of Ishmael,"], ["ioe,", "yea,"], ["ma lona tinā foi,", "and also her mother,"], ["ma se tasi o atalii o Isamaeli,", "and one of the sons of Ishmael, did plead with my brethren,"], ["sa aioi atu i o'u uso sa oo ina latou faamalūlūina o laua loto;", "insomuch that they did soften their hearts;"], ["ma sa laua tuu ai lo laua taumafai e aveese lo'u ola.", "and they did cease striving to take away my life."]]},
  {num:20,words:[["Ma sa oo ina laua faanoanoa ona o lo laua amioleaga,", "And it came to pass that they were sorrowful,"], ["sa oo ina laua ifo mai i o'u luma,", "because of their wickedness, insomuch that they did bow down before me,"], ["ma aioi mai ia te a'u ia ou faamagalo atu ia te i laua mo mea na laua faia e faasaga mai ia te a'u.", "and did plead with me that I would forgive them of the thing that they had done against me."]]},
  {num:21,words:[["Ma sa oo ina ou faamagalo moni atu ia te i laua i mea uma sa laua faia,", "And it came to pass that I did frankly forgive them all that they had done,"], ["ma sa ou apoapoai atu ia te i laua ia laua tatalo atu i le Alii lo laua Atua mo se faamagaloga. Ma sa oo ina faapea ona laua faia. Ma ina ua uma ona laua tatalo atu i le Alii sa toe alu la matou malaga agai i le faleie o lo matou tamā.", "and I did exhort them that they would pray unto the Lord their God for forgiveness. And it came to pass that they did so. And after they had done praying unto the Lord we did again travel on our journey towards the tent of our father."]]},
  {num:22,words:[["Ma sa oo ina matou o ifo i lalo i le faleie o lo matou tamā. Ma ina ua mavae ona o ifo o a'u ma o'u uso ma le 'au'aiga uma o Isamaeli i lalo i le faleie o lou tamā,", "And it came to pass that we did come down unto the tent of our father. And after I and my brethren and all the house of Ishmael had come down unto the tent of my father,"], ["sa latou ava'e le faafetai i le Alii lo latou Atua;", "they did give thanks unto the Lord their God;"], ["ma sa latou osi atu taulaga ma taulaga mu ia te ia.", "and they did offer sacrifice and burnt offerings unto him."]]},
];
renderVerseSet(ch_7_Verses, 'ch7-verses');

var ch_8_Verses = [
  {num:1,words:[["Ma sa oo ina matou faaputuputu faatasi ituaiga uma o fatu eseese,", "And it came to pass that we had gathered together all manner of seeds of every kind,"], ["o kuranuma o ituaiga eseese,", "both of grain of every kind,"], ["ma fatu foi o laau 'aina o ituaiga uma.", "and also of  the seeds of fruit of every kind."]]},
  {num:2,words:[["Ma sa oo a'o nofo lo'u tamā i le vao,", "And it came to pass that while my father tarried in the wilderness he spake unto us,"], ["sa tautala mai o ia ia te i matou,", "saying:"], ["fai mai:", "Behold,"], ["Faauta, sa ou miti se miti;", "I have dreamed a dream;"], ["pe,", "or,"], ["i ni isi upu,", "in other words,"], ["sa ou vaai i se faaaliga vaaia.", "I have seen a vision."]]},
  {num:3,words:[["Ma faauta,", "And behold,"], ["ona o le mea sa ou vaai i ai,", "because of the thing which I have seen,"], ["ua ia te a'u se pogai ou te olioli ai i le Alii ona o Nifae ma Sama foi;", "I have reason to rejoice in the Lord because of Nephi and also of Sam;"], ["ona ua ia te a'u se pogai ua ou manatu ai o i laua,", "for I have reason to suppose that they,"], ["ma le toatele o a laua fanau,", "and also many of their seed,"], ["o le a faaolaina.", "will be saved."]]},
  {num:4,words:[["Ae faauta,", "But behold,"], ["Lamana ma Lemuelu,", "Laman and Lemuel,"], ["ua ou fefe tele ona o oulua;", "I fear exceedingly because of you;"], ["aua faauta,", "for behold,"], ["ua ou manatu sa ou vaaia i la'u miti,", "methought I saw in my dream,"], ["se vao pouliuli ma le pagatia.", "a dark and dreary wilderness."]]},
  {num:5,words:[["Ma sa oo ina ou vaai i se tagata,", "And it came to pass that I saw a man,"], ["ma sa ofu o ia i se ofu talaloa pa'epa'e;", "and he was dressed in a white robe;"], ["ma sa afio mai o ia ma tu i o'u luma.", "and he came and stood before me."]]},
  {num:6,words:[["Ma sa oo ina fetalai mai o ia ia te a'u,", "And it came to pass that he spake unto me,"], ["ma fetalai mai ia te a'u e mulimuli atu ia te ia.", "and bade me follow him."]]},
  {num:7,words:[["Ma a'o ou mulimuli atu ia te ia sa ou vaai ua ou i ai i totonu o se gaogao pogisa ma pagatia.", "And it came to pass that as I followed him I beheld myself that I was in a dark and dreary waste."]]},
  {num:8,words:[["Ma ina ua uma ona ou malaga i le va o ni itula e tele i le pogisa,", "And after I had traveled for the space of many hours in darkness,"], ["sa amata ona ou tatalo atu i le Alii ia alofa mutimutivale mai ia te a'u,", "I began to pray unto the Lord that he would have mercy on me,"], ["e tusa ma le tele o lona alofa mutimutivale agamalu.", "according to the multitude of his tender mercies."]]},
  {num:9,words:[["Ma sa oo ina ua uma ona ou tatalo atu i le Alii, sa ou vaaia se fanua tele ma le ateatea.", "And it came to pass after I had prayed unto the Lord I beheld a large and spacious field."]]},
  {num:10,words:[["Ma sa oo ina ou vaaia se laau ,", "And it came to pass that I beheld a tree,"], ["o ona fua sa manaomia lava e faafiafia ai le tagata.", "whose fruit was desirable to make one happy."]]},
  {num:11,words:[["Ma sa oo ina ou alu atu ma 'ai i lona fua ;", "And it came to pass that I did go forth and partake of the fruit thereof;"], ["ma sa ou iloa ua sili ona suamalie,", "and I beheld that it was most sweet,"], ["nai lo o mea uma sa ou tofo muamua i ai. Ioe,", "above all that I ever before tasted. Yea,"], ["ma sa ou vaai o le fua o le laau ua pa'epa'e,", "and I beheld that the fruit thereof was white,"], ["ua sili atu nai lo mea papa'e uma ua ou vaai i ai.", "to exceed all the whiteness that I had ever seen."]]},
  {num:12,words:[["Ma a'o ou 'ai le fua o le laau,", "And as I partook of the fruit thereof it filled my soul with exceedingly great joy;"], ["sa faatumulia lo'u agaga i le olioli tele;", "wherefore,"], ["o le mea lea, sa amata ai ona ou manao ia aai ai foi lo'u aiga;", "I began to be desirous that my family should partake of it also;"], ["ona ua ou iloa ua sili atu ona manaomia nai lo isi fua uma.", "for I knew that it was desirable above all other fruit."]]},
  {num:13,words:[["Ma a'o vaavaai solo atu o'u mata,", "And as I cast my eyes round about,"], ["pe atonu e mafai ona ou iloa atu foi lo'u aiga,", "that perhaps I might discover my family also,"], ["sa ou vaaia se vaitafe ;", "I beheld a river of water;"], ["ma sa tafe ane,", "and it ran along,"], ["ma sa latalata i le laau lea sa ou 'aia lona fua.", "and it was near the tree of which I was partaking the fruit."]]},
  {num:14,words:[["Ma sa ou tilotilo e vaai atu po o fea e tafe mai ai;", "And I looked to behold from whence it came;"], ["ma sa ou vaai i lona mata sa mamao ese atu laitiiti;", "and I saw the head thereof a little way off;"], ["ma i lona mata sa ou vaaia ai lo outou tinā, o Sarai,", "and at the head thereof I beheld your mother Sariah,"], ["ma Sama,", "and Sam,"], ["ma Nifae;", "and Nephi;"], ["ma sa latou tutu mai e peiseai sa latou lē iloa le mea e tatau ona latou o i ai.", "and they stood as if they knew not whither they should go."]]},
  {num:15,words:[["Ma sa oo ina ou talo atu ia te i latou;", "And it came to pass that I beckoned unto them;"], ["ma sa ou fai atu foi ia te i latou ma se leo tele ia latou o mai ia te a'u,", "and I also did say unto them with a loud voice that they should come unto me, and partake of the fruit,"], ["ma aai i le fua ua sili ona manaomia nai lo isi fua uma lava.", "which was desirable above all other fruit."]]},
  {num:16,words:[["Ma sa oo ina latou o mai ia te a'u ma aai foi i le fua.", "And it came to pass that they did come unto me and partake of the fruit also."]]},
  {num:17,words:[["Ma sa oo ina ou manao ia Lamana ma Lemuelu ia o mai ma aai foi i le fua;", "And it came to pass that I was desirous that Laman and Lemuel should come and partake of the fruit also;"], ["o le mea lea,", "wherefore,"], ["na ou vaavaai atu ai i le mata o le vai,", "I cast mine eyes towards the head of the river,"], ["atonu pe mafai ona ou iloa atu i laua.", "that perhaps I might see them."]]},
  {num:18,words:[["Ma sa oo ina ou vaai atu ia te i laua,", "And it came to pass that I saw them,"], ["peitai sa laua lē fia o mai ia te a'u ma aai i le fua.", "but they would not come unto me and partake of the fruit."]]},
  {num:19,words:[["Ma sa ou vaai i se āi u'amea,", "And I beheld a rod of iron,"], ["ma sa alu faasolo ane i le auvai o le vaitafe,", "and it extended along the bank of the river,"], ["ma sa tau mai i le laau lea sa ou tu ai i ona tafatafa.", "and led to the tree by which I stood."]]},
  {num:20,words:[["Ma sa ou vaai foi i se ala lauitiiti ma le vaapiapi,", "And I also beheld a strait and narrow path,"], ["sa sau mai autafa o le āi u'amea,", "which came along by the rod of iron,"], ["e oo mai lava i le laau lea sa ou tu ai i ona tafatafa;", "even to the tree by which I stood;"], ["ma sa alu atu foi i tafatafa o le mata o le vaipuna,", "and it also led by the head of the fountain,"], ["i se fanua tele ma le ateatea,", "unto a large and spacious field,"], ["e peiseai o se lalolagi.", "as if it had been a world."]]},
  {num:21,words:[["Ma sa ou vaai i motu o tagata e lē masino,", "And I saw numberless concourses of people,"], ["o le toatele o i latou sa fetaomi mai i luma,", "many of whom were pressing forward,"], ["ina ia latou maua le ala e tau mai i le laau lea sa ou tu ai i ona tafatafa.", "that they might obtain the path which led unto the tree by which I stood."]]},
  {num:22,words:[["Ma sa oo ina latou o mai i luma ma amata ona savavali i le ala e tau mai i le laau.", "And it came to pass that they did come forth, and commence in the path which led to the tree."]]},
  {num:23,words:[["Ma sa oo ina alu a'e se puao o le pogisa;", "And it came to pass that there arose a mist of darkness;"], ["ioe, o se puao tele lava o le pogisa,", "yea,"], ["sa oo ina lē iloa ai e i latou o e na amata ona savavali i le ala,", "even an exceedingly great mist of darkness,"], ["lo latou ala, ma latou fesesea'i ai,", "insomuch that they who had commenced in the path did lose their way,"], ["ma leiloloa.", "that they wandered off and were lost."]]},
  {num:24,words:[["Ma sa oo ina ou vaai i isi o fetaomi mai i luma,", "And it came to pass that I beheld others pressing forward,"], ["ma sa latou o mai ma fepiiti i le pito o le āi u'amea;", "and they came forth and caught hold of the end of the rod of iron;"], ["ma sa latou fetaomi mai i luma e ala mai i le puao o le pogisa,", "and they did press forward through the mist of darkness,"], ["ma fepiiti i le āi u'amea,", "clinging to the rod of iron,"], ["seia oo lava ina latou oo mai ma aai i le fua o le laau.", "even until they did come forth and partake of the fruit of the tree."]]},
  {num:25,words:[["Ma ina ua uma ona latou aai i le fua o le laau sa fetepaa'i solo o latou mata e peiseai ua latou mamā .", "And after they had partaken of the fruit of the tree they did cast their eyes about as if they were ashamed."]]},
  {num:26,words:[["Ma sa fetepaa'i solo foi o'u mata,", "And I also cast my eyes round about,"], ["ma ou vaaia ai,", "and beheld,"], ["i le isi itu o le vaitafe,", "on the other side of the river of water,"], ["se fale tele ma le ateatea;", "a great and spacious building;"], ["ma sa tu mai e peiseai ua tu i le ea,", "and it stood as it were in the air,"], ["maualuga lava i luga o le eleele.", "high above the earth."]]},
  {num:27,words:[["Ma sa tumu i tagata,", "And it was filled with people,"], ["o e matutua ma e iti,", "both old and young,"], ["o tane atoa ma fafine;", "both male and female;"], ["ma o o latou ituaiga ofu sa matua lelei lava;", "and their manner of dress was exceedingly fine;"], ["ma sa latou peiseai o faatauemu ma tusitusi mai o latou tamatamailima i e na o mai ma aai i le fua.", "and they were in the attitude of mocking and pointing their fingers towards those who had come at and were partaking of the fruit."]]},
  {num:28,words:[["Ma ina ua uma ona latou totofo i le fua sa latou mamā ,", "And after they had tasted of the fruit they were ashamed,"], ["ona o i latou o e sa faatauemu mai ia te i latou;", "because of those that were scoffing at them;"], ["ma sa latou pauu ese atu ai i ala faasaina ma ua leiloloa.", "and they fell away into forbidden paths and were lost."]]},
  {num:29,words:[["Ma o lenei,", "And now I,"], ["o a'u o Nifae,", "Nephi,"], ["ou te le tautala atu upu uma a lo'u tamā.", "do not speak all the words of my father."]]},
  {num:30,words:[["Ae,", "But,"], ["ina ia tusia faapuupuu,", "to be short in writing,"], ["faauta,", "behold,"], ["sa vaai o ia i isi motu o tagata o fetaomi mai i luma;", "he saw other multitudes pressing forward;"], ["ma sa latou o mai ma fepi'iti i le pito o le āi u'amea;", "and they came and caught hold of the end of the rod of iron;"], ["ma sa latou fetaomi mai i luma i lo latou ala,", "and they did press their way forward,"], ["ma piimau pea i le āi u'amea,", "continually holding fast to the rod of iron,"], ["seia oo ina latou o mai i luma ma faapauu i lalo ma aai i le fua o le laau.", "until they came forth and fell down and partook of the fruit of the tree."]]},
  {num:31,words:[["Ma sa vaai foi o ia i isi motu o tagata o tautagotago atu lo latou ala agai i le fale tele ma le ateatea.", "And he also saw other multitudes feeling their way towards that great and spacious building."]]},
  {num:32,words:[["Ma sa oo ina malelemo le toatele i mea loloto o le punavai ;", "And it came to pass that many were drowned in the depths of the fountain;"], ["ma e toatele sa lē iloa atu i lana vaai,", "and many were lost from his view,"], ["ua fesesea'i i ala ese.", "wandering in strange roads."]]},
  {num:33,words:[["Ma sa toatele le motu o tagata sa ulufale atu i totonu o lena fale uiga ese. Ma ina ua uma ona latou ulufale atu i totonu o lena fale sa latou tusitusi mai le tamatamailima o le faatauemu ia te a'u ma i latou foi o e na aai i le fua o le laau;", "And great was the multitude that did enter into that strange building. And after they did enter into that building they did point the finger of scorn at me and those that were partaking of the fruit also;"], ["peitai sa matou lē amanaiaina i latou.", "but we heeded them not."]]},
  {num:34,words:[["O upu nei a lo'u tamā:", "These are the words of my father:"], ["O le toatele na amanaiaina i latou,", "For as many as heeded them,"], ["na pauu ese.", "had fallen away."]]},
  {num:35,words:[["Ma o Lamana ma Lemuelu, sa fai mai lo'u tamā,", "And Laman and Lemuel partook not of the fruit,"], ["sa lei aai i le fua.", "said my father."]]},
  {num:36,words:[["Ma sa oo ina ua uma ona tautalaina mai e lo'u tamā upu uma o lana miti po o le faaaliga vaaia,", "And it came to pass after my father had spoken all the words of his dream or vision,"], ["sa tele,", "which were many,"], ["sa fai mai o ia ia te i matou,", "he said unto us,"], ["ona o nei mea sa vaai i ai o ia i se faaaliga vaaia,", "because of these things which he saw in a vision,"], ["sa popole tele ai o ia e uiga ia Lamana ma Lemuelu;", "he exceedingly feared for Laman and Lemuel;"], ["ioe,", "yea,"], ["sa popole o ia ne'i lafoai ese i laua mai luma o le Alii.", "he feared lest they should be cast off from the presence of the Lord."]]},
  {num:37,words:[["Ma sa apoapoai atu o ia ia te i laua i le taimi lena ma lagona uma o se matua alofa,", "And he did exhort them then with all the feeling of a tender parent,"], ["ia laua faalogologo mai i ana upu,", "that they would hearken to his words,"], ["atonu e alofa mutimutivale ai le Alii ia te i laua,", "that perhaps the Lord would be merciful to them,"], ["ma lē lafoai ese ai i laua;", "and not cast them off;"], ["ioe,", "yea,"], ["sa lauga atu lo'u tamā ia te i laua.", "my father did preach unto them."]]},
  {num:38,words:[["Ma ina ua uma ona lauga atu o ia ia te i laua,", "And after he had preached unto them,"], ["ma vavalo atu foi ia te i laua i mea e tele,", "and also prophesied unto them of many things,"], ["sa ia poloaiina i laua ia tausi i poloaiga a le Alii;", "he bade them to keep the commandments of the Lord;"], ["ma sa faai'u e ia le tautala atu ia te i laua.", "and he did cease speaking unto them."]]},
];
renderVerseSet(ch_8_Verses, 'ch8-verses');

var ch_9_Verses = [
  {num:1,words:[["Ma o mea uma nei sa vaai,", "And all these things did my father see,"], ["ma faalogo,", "and hear,"], ["ma tautala i ai lo'u tamā,", "and speak,"], ["a'o nofo o ia i se faleie,", "as he dwelt in a tent,"], ["i le vanu o Lemuelu,", "in the valley of Lemuel,"], ["ma le tele atu foi o isi mea,", "and also a great many more things,"], ["e le mafai ona tusia i luga o papatusi nei.", "which cannot be written upon these plates."]]},
  {num:2,words:[["Ma o lenei,", "And now,"], ["e pei ona ou tautala atu e uiga i papatusi nei,", "as I have spoken concerning these plates,"], ["faauta e le o papatusi nei ua ou faia ai se tala atoa o le talafaasolopito o lo'u nuu;", "behold they are not the plates upon which I make a full account of the history of my people;"], ["ona o papatusi ua ou faia ai se tala atoa o lo'u nuu ua ou faaigoaina o Nifae;", "for the plates upon which I make a full account of my people I have given the name of Nephi;"], ["o le mea lea,", "wherefore,"], ["ua ta'ua ai o papatusi a Nifae,", "they are called the plates of Nephi,"], ["ua faaigoaina i lo'u lava igoa;", "after mine own name;"], ["ma o papatusi nei ua ta'ua foi o papatusi a Nifae.", "and these plates also are called the plates of Nephi."]]},
  {num:3,words:[["E ui i lea,", "Nevertheless,"], ["ua ou maua se poloaiga mai le Alii e tatau ona ou faia papatusi nei,", "I have received a commandment of the Lord that I should make these plates,"], ["mo le faamoemoega faapitoa ia i ai se tala e togitogia o auaunaga a lo'u nuu.", "for the special purpose that there should be an account engraven of the ministry of my people."]]},
  {num:4,words:[["I luga o isi papatusi e tatau ona togitogia ai se tala o nofoaiga a tupu,", "Upon the other plates should be engraven an account of the reign of the kings,"], ["ma taua ma finauga a lo'u nuu;", "and the wars and contentions of my people;"], ["o le mea lea o papatusi nei o le vaega tele ua faatatau i auaunaga a lo'u nuu;", "wherefore these plates are for the more part of the ministry;"], ["ma o isi papatusi o le vaega tele ua faatatau i nofoaiga a tupu ma taua ma finauga a lo'u nuu.", "and the other plates are for the more part of the reign of the kings and the wars and contentions of my people."]]},
  {num:5,words:[["O le mea lea,", "Wherefore,"], ["na poloaiina ai a'u e le Alii ia ou faia nei papatusi mo se faamoemoega poto o ia te ia,", "the Lord hath commanded me to make these plates for a wise purpose in him,"], ["o se faamoemoega ou te lē iloa.", "which purpose I know not."]]},
  {num:6,words:[["Ae ua silafia e le Alii mea uma mai le amataga;", "But the Lord knoweth all things from the beginning;"], ["o le mea lea,", "wherefore,"], ["ua saunia ai e ia se ala e faataunuu ai ana galuega uma i totonu o le fanauga a tagata;", "he prepareth a way to accomplish all his works among the children of  men;"], ["aua faauta,", "for behold,"], ["ua ia te ia le mana uma e faataunuu ai ana fetalaiga uma. Ma ua faapea lava. Amene.", "he hath all power unto the fulfilling of all his words. And thus it is. Amen."]]},
];
renderVerseSet(ch_9_Verses, 'ch9-verses');

var ch_10_Verses = [
  {num:1,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae,", "proceed to give an account upon these plates of my proceedings,"], ["ou te faaauau ona faia i papatusi nei se tala o a'u taualumaga,", "and my reign and ministry;"], ["ma la'u nofoaiga ma la'u auaunaga; o le mea lea,", "wherefore,"], ["ina ia faaauau la'u tala,", "to proceed with mine account,"], ["e ao ina ou tautala teisi e uiga i mea a lo'u tamā,", "I must speak somewhat of the things of my father,"], ["ma a o'u uso foi.", "and also of my brethren."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["sa oo ina ua uma ona faaiu e lo'u tamā le tautala mai o upu o lana miti ,", "it came to pass after my father had made an end of speaking the words of his dream,"], ["ma le apoapoaiina foi o i la'ua ia filiga atoatoa,", "and also of exhorting them to all diligence,"], ["sa tautala atu o ia ia te i laua e uiga i tagata Iutaia—", "he spake unto them concerning the Jews—"]]},
  {num:3,words:[["E faapea a uma ona faaumatia o i latou,", "That after they should be destroyed,"], ["lena lava aai tele o Ierusalema ,", "even that great city Jerusalem,"], ["ma ave faatagataotauaina le toatele i Papelonia ,", "and many be carried away captive into Babylon,"], ["e tusa ma le taimi tatau ai a le Alii,", "according to the own due time of the Lord,"], ["o le a toe foi mai i latou,", "they should return again,"], ["ioe,", "yea,"], ["e toe aumai lava i latou i fafo mai le faatagataotauaina;", "even be brought back out of captivity;"], ["ma a uma ona toe aumai o i latou i fafo mai le faatagataotauaina o le a toe maua e i latou le laueleele o lo latou tofi.", "and after they should be brought back out of captivity they should possess again the land of their inheritance."]]},
  {num:4,words:[["Ioe,", "Yea,"], ["i le ono selau tausaga mai le taimi na tuua ai e lo'u tamā Ierusalema,", "even six hundred years from the time that my father left Jerusalem,"], ["o le a faatu mai ai e le Alii le Atua se perofeta i totonu o tagata Iutaia—o se Mesia lava,", "a prophet would the Lord God raise up among the Jews—even a Messiah,"], ["po o,", "or,"], ["i ni isi upu,", "in other words,"], ["o le Faaola o le lalolagi.", "a Savior of the world."]]},
  {num:5,words:[["Ma sa tautala foi o ia e uiga i perofeta,", "And he also spake concerning the prophets,"], ["le toatele na'uā o se aofai o i latou na molimau mai e uiga i nei mea,", "how great a number had testified of these things,"], ["e uiga i lenei Mesia,", "concerning this Messiah,"], ["o lē na tautala i ai o ia,", "of whom he had spoken,"], ["po o lenei Togiola o le lalolagi.", "or this Redeemer of the world."]]},
  {num:6,words:[["O le mea lea,", "Wherefore,"], ["sa leiloloa tagata uma ma i ai i se tulaga pa'ū,", "all mankind were in a lost and in a fallen state,"], ["ma o le a tumau ai pea vagana ai ua latou faalagolago i lenei Togiola.", "and ever would be save they should rely on this Redeemer."]]},
  {num:7,words:[["Ma sa tautala foi o ia e uiga i se perofeta o lē o le a sau muamua mai i le Mesia,", "And he spake also concerning a prophet who should come before the Messiah,"], ["e teuteu le ala o le Alii—", "to prepare the way of the Lord–"]]},
  {num:8,words:[["Ioe,", "Yea,"], ["o le a alu atu lava o ia ma alaga i le vao:", "even he should go forth and cry in the wilderness:"], ["Inā teuteu ia e outou le ala o le Alii,", "Prepare ye the way of the Lord,"], ["ma ia faasa'osa'o ona ala;", "and make his paths straight;"], ["ona ua i ai se tasi ua tu mai ia te outou o lē ua outou lē iloaina;", "for there standeth one among you whom ye know not;"], ["ma o ia ua malosi silisili atu ia te a'u,", "and he is mightier than I,"], ["o lē ou te lē agavaa e tatala le nonoa o lona seevae. Ma e tele mea sa tautala mai ai lo'u tamā e uiga i lenei mea.", "whose shoe's latchet I am not worthy to unloose. And much spake my father concerning this thing."]]},
  {num:9,words:[["Ma sa fai mai lo'u tamā o le a ia papatiso i Petapara ,", "And my father said he should baptize in Bethabara,"], ["i tala atu o Ioritana;", "beyond Jordan;"], ["ma sa fai mai foi o ia o le a ia papatiso i le vai;", "and he also said he should baptize with water;"], ["o le a papatisoina lava e ia le Mesia i le vai.", "even that he should baptize the Messiah with water."]]},
  {num:10,words:[["Ma a uma ona papatiso e ia le Mesia i le vai,", "And after he had baptized the Messiah with water,"], ["o le a iloa e ia ma molimau atu ua ia papatisoina le Tamai Mamoe a le Atua,", "he should behold and bear record that he had baptized the Lamb of God,"], ["o lē o le a aveesea agasala a le lalolagi.", "who should take away the sins of the world."]]},
  {num:11,words:[["Ma sa oo ina ua uma ona tautala mai e lo'u tamā ia upu, sa tautala atu o ia i o'u uso e uiga i le talalelei o le a talai atu i totonu o tagata Iutaia,", "And it came to pass after my father had spoken these words he spake unto my brethren concerning the gospel which should be preached among the Jews,"], ["ma e uiga foi i le faaitiitia o tagata Iutaia i le lē talitonu.", "and also concerning the dwindling of the Jews in unbelief."], ["Ma a uma ona latou fasioti o le Mesia,", "And after they had slain the Messiah,"], ["o lē o le a afio mai,", "who should come,"], ["ma a uma ona fasiotia o ia,", "and after he had been slain he should rise from  the dead,"], ["o le a toetu mai o ia mai le oti,", "and should make himself manifest,"], ["ma o le a ia faaali atu o ia lava i Nuuese,", "by the Holy Ghost,"], ["e ala i le Agaga Paia.", "unto the Gentiles."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["sa tele mea sa tautala mai ai lo'u tamā e uiga i Nuuese,", "even my father spake much concerning the Gentiles,"], ["ma e uiga foi i le aiga o Isaraelu,", "and also concerning the house of Israel,"], ["e faatusaina i latou i se laau olive,", "that they should be compared like unto an olive tree,"], ["o le a fa'i ese ona lala ma o le a faataapeapeina i luga o le lalolagi atoa.", "whose branches should be broken off and should be scattered upon all the face of the earth."]]},
  {num:13,words:[["O le mea lea,", "Wherefore,"], ["sa fai mai ai o ia ua tatau ai ona taitai atu o i matou ma le lotogatasi i le laueleele o le folafolaga,", "he said it must needs be that we should be led with one accord into the land of promise,"], ["e faataunuu ai le fetalaiga a le Alii,", "unto the fulfilling of the word of the Lord,"], ["ia faataapeapeina i matou i luga o le lalolagi atoa.", "that we should be scattered upon all the face of the earth."]]},
  {num:14,words:[["Ma a mavae ona faataapeape o le aiga o Isaraelu o le a toe faapotopoto faatasi i latou;", "And after the house of Israel should be scattered they should be gathered together again;"], ["po o lona uiga,", "or,"], ["a mavae ona maua e Nuuese le atoatoaga o le Talalelei,", "in fine,"], ["o lala moni o le laau olive,", "after the Gentiles had received the fulness of the Gospel,"], ["po o le toe vaega o le aiga o Isaraelu,", "the natural branches of the olive– tree, or the remnants of the house of Israel,"], ["o le a sulu i totonu,", "should be grafted in,"], ["pe o le a o mai i le malamalama o le Mesia moni,", "or come to the knowledge of the true Messiah,"], ["lo latou Alii ma lo latou Togiola.", "their Lord and their Redeemer."]]},
  {num:15,words:[["Ma sa faapea le ituaiga o gagana sa vavalo ma tautala atu ai lo'u tamā i o'u uso,", "And after this manner of language did my father prophesy and speak unto my brethren,"], ["ma le tele foi o isi mea ou te lē tusia i lenei tusi;", "and also many more things which I do not write in this book;"], ["ona ua ou tusia le tele o i latou ua tatau ai ia te a'u i le isi a'u tusi.", "for I have written as many of them as were expedient for me in mine other book."]]},
  {num:16,words:[["Ma o nei mea uma,", "And all these things,"], ["ua ou tautala atu ai,", "of which I have spoken,"], ["sa faia a'o nofo lo'u tamā i se faleie,", "were done as my father dwelt in a tent,"], ["i le vanu o Lemuelu.", "in the valley of Lemuel."]]},
  {num:17,words:[["Ma sa oo ina ua uma ona faalogo atu o a'u,", "And it came to pass after I,"], ["o Nifae,", "Nephi,"], ["i upu uma a lo'u tamā,", "having heard all the words of my father,"], ["e uiga i mea sa vaai i ai o ia i se faaaliga vaaia,", "concerning the things which he saw in a vision,"], ["ma mea foi sa tautala mai ai o ia i le mana o le Agaga Paia,", "and also the things which he spake by the power of the Holy Ghost,"], ["o le mana lea sa maua e ia i le faatuatua i le Alo o le Atua—ma o le Alo o le Atua o le Mesia lava lea o lē o le a afio mai—o a'u,", "which power he received by faith on the Son of God—and the Son of God was the Messiah who should come—I,"], ["o Nifae,", "Nephi,"], ["sa ou manao foi ia mafai ona ou vaai,", "was desirous also that I might see,"], ["ma faalogo,", "and hear,"], ["ma iloa e uiga i ia mea,", "and know of these things,"], ["i le mana o le Agaga Paia,", "by the power of the Holy Ghost,"], ["le meaalofa lea a le Atua ia i latou uma o e e saili ia te ia ma le filiga ,", "which is the gift of God unto all those who diligently seek him,"], ["e pei o taimi anamua faapea foi i le taimi o le a faaali mai ai o ia lava i le fanauga a tagata.", "as well in times of old as in the time that he should manifest himself unto the children of men."]]},
  {num:18,words:[["Ona ua tutusa lava o ia ananafi,", "For he is the same yesterday,"], ["i le asō,", "today,"], ["ma le faavavau;", "and forever;"], ["ma ua saunia le ala mo tagata uma mai le faavaega o le lalolagi,", "and the way is prepared for all men from the foundation of the world,"], ["pe afai latou te salamo ma o mai ia te ia.", "if it so be that they repent and come unto him."]]},
  {num:19,words:[["Ona o ia o lē e saili ma le filiga o le a maua e ia;", "For he that diligently seeketh shall find;"], ["ma o le a faaali ia te i latou mealilo a le Atua,", "and the mysteries of God shall be unfolded unto them,"], ["e ala i le mana o le Agaga Paia,", "by the power of the Holy Ghost,"], ["e pei o taimi nei e faapei o taimi anamua,", "as well in these times as in times of old,"], ["ma e pei foi o taimi anamua e pei o taimi o le a oo mai;", "and as well in times of old as in times to come;"], ["o le mea lea,", "wherefore,"], ["o le ala o le Alii o se taamilosaga faavavau e tasi.", "the course of the Lord is one eternal round."]]},
  {num:20,words:[["O le mea lea ia manatua ai,", "Therefore remember,"], ["le tagata e,", "O man,"], ["o le a aumai oe i le faamasinoga mo au mea uma na fai.", "for all thy doings thou shalt be brought into judgment."]]},
  {num:21,words:[["O le mea lea,", "Wherefore,"], ["afai na e saili e fai le amioleaga i aso o lou vaavaaiga ,", "if ye have sought to do wickedly in the days of your probation,"], ["o le a maua oe i le lē mamā i luma o le nofoa-faamasino o le Atua;", "then ye are found unclean before the judgment– seat of God;"], ["ma e leai se mea e lē mamā e mafai ona nofo faatasi ma le Atua;", "and no unclean thing can dwell with God;"], ["o le mea lea,", "wherefore,"], ["o le a lafo ese ai oe e faavavau.", "ye must be cast off forever."]]},
  {num:22,words:[["Ma ua tuu mai e le Agaga Paia le pule ou te tautala atu ai nei mea,", "And the Holy Ghost giveth authority that I should speak these things,"], ["ma lē faafitia i latou.", "and deny them not."]]},
];
renderVerseSet(ch_10_Verses, 'ch10-verses');

var ch_11_Verses = [
  {num:1,words:[["Ona sa oo ina ua uma ona ou fia iloa o mea sa vaai i ai lo'u tamā,", "For it came to pass after I had desired to know the things that my father had seen,"], ["ma lo'u talitonu e mafai e le Alii ona faailoa mai ia te a'u,", "and believing that the Lord was able to make them known unto me,"], ["a'o ou nofo ma mafaufau loloto i lo'u loto,", "as I sat pondering in mine heart I was caught away in the Spirit of the Lord,"], ["sa segia ese a'u i le Agaga o le Alii, ioe,", "yea,"], ["i se mauga maualuga lava,", "into an exceedingly high mountain,"], ["ou te lei vaai muamua i ai,", "which I never had before seen,"], ["ma e lei tu muamua ai foi i luga lo'u vae.", "and upon which I never had before set my foot."]]},
  {num:2,words:[["Ma sa fetalai mai le Agaga ia te a'u:", "And the Spirit said unto me:"], ["Faauta,", "Behold,"], ["o le a le mea ua e manao i ai?", "what desirest thou?"]]},
  {num:3,words:[["Ma sa ou fai atu:", "And I said:"], ["ou te fia vaai i mea sa vaai i ai lo'u tamā.", "I desire to behold the things which my father saw."]]},
  {num:4,words:[["Ma sa fetalai mai le Agaga ia te a'u:", "And the Spirit said unto me:"], ["E te talitonu ea sa vaai lou tamā i le laau lea sa tautala atu ai o ia?", "Believest thou that thy father saw the tree of which he hath spoken?"]]},
  {num:5,words:[["Ma sa ou fai atu:", "And I said:"], ["Ioe,", "Yea,"], ["ua e silafia ua ou talitonu i upu uma a lo'u tamā.", "thou knowest that I believe all the words of my father."]]},
  {num:6,words:[["Ma ina ua uma ona ou fai atu o ia upu,", "And when I had spoken these words,"], ["sa alaga le Agaga ma le leo tele,", "the Spirit cried with a loud voice,"], ["fai mai:", "saying:"], ["Osana ia i le Alii,", "Hosanna to the Lord,"], ["le Atua silisili ese;", "the most high God;"], ["ona o ia o le Atua i luga o le lalolagi atoa,", "for he is God over all the earth,"], ["ioe,", "yea,"], ["i luga o mea uma lava. Ma amuia lava oe,", "even above all. And blessed art thou,"], ["Nifae,", "Nephi,"], ["ona ua e talitonu i le Alo o le Atua silisili ese;", "because thou believest in the Son of the most high God;"], ["o le mea lea,", "wherefore,"], ["o le a e vaai ai i mea ua e manao i ai.", "thou shalt behold the things which thou hast desired."]]},
  {num:7,words:[["Ma faauta o le a tuu atu ia te oe lenei mea mo se faailoga ,", "And behold this thing shall be given unto thee for a sign,"], ["e faapea a uma ona e vaai i le laau sa fua mai ai le fua sa tofo i ai lou tamā,", "that after thou hast beheld the tree which bore the fruit which thy father tasted,"], ["o le a e vaai foi i se tagata ua afio ifo mai le lagi,", "thou shalt also behold a man descending out of heaven,"], ["ma o ia o le a e vaai i ai;", "and him shall ye witness;"], ["ma a uma ona e vaai ia te ia o le a e molimauina o ia o le Alo o le Atua.", "and after ye have witnessed him ye shall bear record that it is the Son of God."]]},
  {num:8,words:[["Ma sa oo ina fetalai mai le Agaga ia te a'u:", "And it came to pass that the Spirit said unto me:"], ["Vaai ia! Ma sa ou vaai ma iloa atu se laau;", "Look! And I looked and beheld a tree;"], ["ma sa pei o le laau sa vaai i ai lo'u tamā;", "and it was like unto the tree which my father had seen;"], ["ma o lona matagofie sa sili mamao atu,", "and the beauty thereof was far beyond,"], ["ioe,", "yea,"], ["silisili atu i matagofie uma;", "exceeding of all beauty;"], ["ma o lona pa'epa'e sa sili atu i le pa'epa'e o le kiona lelea.", "and the whiteness thereof did exceed the whiteness of the driven snow."]]},
  {num:9,words:[["Ma sa oo ina ua uma ona ou vaai i le laau,", "And it came to pass after I had seen the tree,"], ["sa ou fai atu i le Agaga:", "I said unto the Spirit:"], ["Ua ou vaai ua e faaali mai ia te a'u le laau ua pele i mea uma.", "I behold thou hast shown unto me the tree which is precious above all."]]},
  {num:10,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["O le a le mea ua e manao i ai?", "What desirest thou?"]]},
  {num:11,words:[["Ma sa ou fai atu ia te ia:", "And I said unto him:"], ["Ia ou iloa lona uiga —ona sa ou tautala atu ia te ia e pei ona tautala se tagata;", "To know the interpretation thereof—for I spake unto him as a man speaketh;"], ["ona sa ou vaai atu sa fuaitino mai o ia i se tagata;", "for I beheld that he was in the form of a man;"], ["ae e ui i lea,", "yet nevertheless,"], ["sa ou iloa o ia o le Agaga o le Alii;", "I knew that it was the Spirit of the Lord;"], ["ma sa fetalai mai o ia ia te a'u e pei ona tautala se tagata i se tasi tagata.", "and he spake unto me as a man speaketh with another."]]},
  {num:12,words:[["Ma sa oo ina fetalai mai o ia ia te a'u:", "And it came to pass that he said unto me:"], ["Vaai ia! Ma sa ou tepa atu e peiseai ou te vaai atu ia te ia,", "Look! And I looked as if to look upon him,"], ["ae sa ou lē iloa atu o ia;", "and I saw him not;"], ["ona ua maliu ese atu o ia mai o'u luma.", "for he had gone from before my presence."]]},
  {num:13,words:[["Ma sa oo ina ou vaai ma iloa atu le aai tele o Ierusalema,", "And it came to pass that I looked and beheld the great city of Jerusalem,"], ["ma isi foi aai. Ma sa ou vaai i le aai o Nasareta;", "and also other cities. And I beheld the city of Nazareth;"], ["ma i totonu o le aai o Nasareta sa ou vaaia ai se taupou ,", "and in the city of Nazareth I beheld a virgin,"], ["ma sa matua silisili ona lalelei ma pa'epa'e o ia.", "and she was exceedingly fair and white."]]},
  {num:14,words:[["Ma sa oo ina ou vaai atu ua avanoa le lagi ;", "And it came to pass that I saw the heavens open;"], ["ma sa afio mai i lalo se agelu ma ua tu i o'u luma;", "and an angel came down and stood before me;"], ["ma sa fetalai mai o ia ia te a'u:", "and he said unto me:"], ["Nifae,", "Nephi,"], ["o le a le mea ua e vaai atu i ai?", "what beholdest thou?"]]},
  {num:15,words:[["Ma sa ou fai atu ia te ia:", "And I said unto him:"], ["O se taupou,", "A virgin,"], ["ua silisili ona aulelei ma lalelei i isi taupou uma.", "most beautiful and fair above all other virgins."]]},
  {num:16,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["Pe ua e iloa ea le faamaualalo o le Atua?", "Knowest thou the condescension of God?"]]},
  {num:17,words:[["Ma sa ou fai atu ia te ia:", "And I said unto him:"], ["Ua ou iloa e alofa o ia i ana fanau;", "I know that he loveth his children;"], ["e ui i lea,", "nevertheless,"], ["ou te le iloa le uiga o mea uma.", "I do not know the meaning of all things."]]},
  {num:18,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["Faauta,", "Behold,"], ["o le taupou ua e vaai atu i ai o le tinā lea o le Alo o le Atua,", "the virgin whom thou seest is the mother of the Son of God,"], ["e tusa ma la le tino.", "after the manner of the flesh."]]},
  {num:19,words:[["Ma sa oo ina ou vaai atu ua segia ese atu o ia i le Agaga;", "And it came to pass that I beheld that she was carried away in the Spirit;"], ["ma ina ua mavae ona segia atu o ia i le Agaga mo le va o se taimi,", "and after she had been carried away in the Spirit for the space of a time the angel spake unto me,"], ["sa fetalai mai le agelu ia te a'u, ua fetalai mai:", "saying:"], ["Vaai ia!", "Look!"]]},
  {num:20,words:[["Ma sa ou vaai ma toe iloa atu le taupou,", "And I looked and beheld the virgin again,"], ["ua sapasapaia e ia se tamameamea i ona lima.", "bearing a child in her arms."]]},
  {num:21,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Faauta i le Tamai Mamoe a le Atua,", "Behold the Lamb of God,"], ["ioe,", "yea,"], ["o le Alo lava o le Tama Faavavau! Ua e iloa ea le uiga o le laau sa vaai i ai lou tamā?", "even the Son of the Eternal Father! Knowest thou the meaning of the tree which thy father saw?"]]},
  {num:22,words:[["Ma sa ou tali atu ia te ia,", "And I answered him,"], ["ua ou fai atu:", "saying:"], ["Ioe,", "Yea,"], ["o le alofa lea o le Atua,", "it is the love of God,"], ["ua faamaligi ifo lautele o ia lava i loto o le fanauga a tagata;", "which sheddeth itself abroad in the hearts of the children of men;"], ["o lea,", "wherefore,"], ["o le mea lea ua silisili atu ona manaomia i mea uma.", "it is the most desirable above all things."]]},
  {num:23,words:[["Ma sa fetalai mai o ia ia te a'u,", "And he spake unto me,"], ["fai mai:", "saying:"], ["Ioe,", "Yea,"], ["ma le silisili ona olioli i le agaga.", "and the most joyous to the soul."]]},
  {num:24,words:[["Ma ina ua uma ona fetalai mai e ia o nei upu,", "And after he had said these words,"], ["sa fetalai mai o ia ia te a'u:", "he said unto me:"], ["Vaai ia! Ma sa ou vaai,", "Look! And I looked,"], ["ma sa ou iloa atu le Alo o le Atua ua femaliuai i totonu o le fanauga a tagata;", "and I beheld the Son of God going forth among the children of men;"], ["ma sa ou vaai i le toatele ua faapauu i lalo i ona vae ma tapuai atu ia te ia.", "and I saw many fall down at his feet and worship him."]]},
  {num:25,words:[["Ma sa oo ina ou vaai o le āi uamea,", "And it came to pass that I beheld that the rod of iron,"], ["lea sa vaai i ai lo'u tamā,", "which my father had seen,"], ["o le afioga lea a le Atua,", "was the word of God,"], ["lea sa tau atu i le punavai o vai ola,", "which led to the fountain of living waters,"], ["po o i le laau o le ola;", "or to the tree of life;"], ["o vai ia o se faatusa o le alofa o le Atua;", "which waters are a representation of the love of God;"], ["ma sa ou vaai foi o le laau o le ola o se faatusa o le alofa o le Atua.", "and I also beheld that the tree of life was a representation of the love of God."]]},
  {num:26,words:[["Ma sa toe fetalai mai le agelu ia te a'u:", "And the angel said unto me again:"], ["Vaai ia ma faauta i le faamaualalo o le Atua!", "Look and behold the condescension of God!"]]},
  {num:27,words:[["Ma sa ou vaai ma iloa atu le Togiola o le lalolagi,", "And I looked and beheld the Redeemer of the world,"], ["o lē sa tautala i ai lo'u tamā;", "of whom my father had spoken;"], ["ma sa ou vaai foi i le perofeta o lē o le a teuteuina le ala i ona luma. Ma sa afio atu le Tamai Mamoe a le Atua ma ua papatisoina e ia;", "and I also beheld the prophet who should prepare the way before him. And the Lamb of God went forth and was baptized of him;"], ["ma ina ua uma ona papatisoina o ia,", "and after he was baptized,"], ["sa ou vaai ua avanoa le lagi,", "I beheld the heavens open,"], ["ma ua afio ifo i lalo le Agaga Paia mai le lagi ma ua afio i luga o ia e peiseai o se lupe .", "and the Holy Ghost come down out of heaven and abide upon him in the form of a dove."]]},
  {num:28,words:[["Ma sa ou vaai ua afio atu o ia ma auauna atu i tagata,", "And I beheld that he went forth ministering unto the people,"], ["i le mana ma le mamalu tele;", "in power and great glory;"], ["ma sa faapotopoto motu o tagata e faalogologo ia te ia;", "and the multitudes were gathered together to hear him;"], ["ma sa ou vaai ua latou tuli ese o ia i fafo mai totonu o i latou.", "and I beheld that they cast him out from among them."]]},
  {num:29,words:[["Ma sa ou vaaia foi isi e toasefululua o mulimuli atu ia te ia. Ma sa oo ina segia ese atu i latou i le Agaga mai luma o o'u mata,", "And I also beheld twelve others following him. And it came to pass that they were carried away in the Spirit from before my face,"], ["ma sa ou lē vaai atu ia te i latou.", "and I saw them not."]]},
  {num:30,words:[["Ma sa oo ina toe fetalai mai le agelu ia te a'u,", "And it came to pass that the angel spake unto me again,"], ["fai mai:", "saying:"], ["Vaai ia! Ma sa ou vaai,", "Look! And I looked,"], ["ma ou vaai atu ua toe avanoa le lagi,", "and I beheld the heavens open again,"], ["ma sa ou vaai atu ua afifio ifo agelu i luga o le fanauga a tagata;", "and I saw angels descending upon the children of men;"], ["ma ua latou auauna atu ia te i latou.", "and they did minister unto them."]]},
  {num:31,words:[["Ma sa toe fetalai mai o ia ia te a'u,", "And he spake unto me again,"], ["fai mai:", "saying:"], ["Vaai ia! Ma sa ou vaai,", "Look! And I looked,"], ["ma ou iloa atu le Tamai Mamoe a le Atua ua afio atu i totonu o le fanauga a tagata. Ma sa ou vaai i motu o tagata o e sa mama'i,", "and I beheld the Lamb of God going forth among the children of men. And I beheld multitudes of people who were sick,"], ["ma e sa puapuagatia i ituaiga uma o faama'i eseese,", "and who were afflicted with all manner of diseases,"], ["ma i tiapolo ma agaga lē mamā;", "and with devils and unclean spirits;"], ["ma sa fetalai ma faaali mai e le agelu nei mea uma ia te a'u. Ma sa faamaloloina i latou i le mana o le Tamai Mamoe a le Atua;", "and the angel spake and showed all these things unto me. And they were healed by the power of the Lamb of God;"], ["ma sa tutuli ese tiapolo ma agaga lē mamā.", "and the devils and the unclean spirits were cast out."]]},
  {num:32,words:[["Ma sa oo ina toe fetalai mai le agelu ia te a'u,", "And it came to pass that the angel spake unto me again,"], ["fai mai:", "saying:"], ["Vaai ia! Ma sa ou vaai ma iloa atu le Tamai Mamoe a le Atua,", "Look! And I looked and beheld the Lamb of God,"], ["ua ave o ia e le nuu;", "that he was taken by the people;"], ["ioe,", "yea,"], ["o le Alo o le Atua tumau-faavavau ua faamasinoina e le lalolagi;", "the Son of the everlasting God was judged of the world;"], ["ma sa ou vaaia ma molimauina.", "and I saw and bear record."]]},
  {num:33,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa ou vaai ua sii a'e o ia i luga o le satauro ma fasiotia mo agasala a le lalolagi.", "saw that he was lifted up upon the cross and slain for the sins of the world."]]},
  {num:34,words:[["Ma ina ua uma ona fasiotia o ia sa ou vaaia motu o tagata o le lalolagi,", "And after he was slain I saw the multitudes of the earth,"], ["ua latou faapotopoto faatasi e faasagatau i aposetolo a le Tamai Mamoe;", "that they were gathered together to fight against the apostles of the Lamb;"], ["ona sa faapea ona ta'ua o le toasefululua e le agelu a le Alii.", "for thus were the twelve called by the angel of the Lord."]]},
  {num:35,words:[["Ma sa faapotopoto faatasi le motu o tagata o le lalolagi;", "And the multitude of the earth was gathered together;"], ["ma sa ou vaai ua latou i ai i totonu o se fale tele ma le ateatea,", "and I beheld that they were in a large and spacious building,"], ["e pei o le fale sa vaai i ai lo'u tamā. Ma sa toe fetalai mai le agelu a le Alii ia te a'u,", "like unto the building which my father saw. And the angel of the Lord spake unto me again,"], ["fai mai:", "saying:"], ["Faauta i le lalolagi ma lona poto;", "Behold the world and the wisdom thereof;"], ["ioe,", "yea,"], ["faauta ua faapotopoto faatasi le aiga o Isaraelu e faasagatau i aposetolo e toasefululua a le Tamai Mamoe.", "behold the house of Israel hath gathered together to fight against the twelve apostles of the Lamb."]]},
  {num:36,words:[["Ma sa oo ina ou vaaia ma molimauina,", "And it came to pass that I saw and bear record,"], ["o le fale tele ma le ateatea o le faamaualuga lea o le lalolagi;", "that the great and spacious building was the pride of the world;"], ["ma sa pa'ū,", "and it fell,"], ["ma o lona pa'ū sa matua tele lava. Ma sa toe fetalai mai le agelu a le Alii ia te a'u,", "and the fall thereof was exceedingly great. And the angel of the Lord spake unto me again,"], ["fai mai:", "saying:"], ["O le a faapea lava le faaumatiaga o atunuu uma,", "Thus shall be the destruction of all nations,"], ["ituaiga,", "kindreds,"], ["gagana eseese,", "tongues,"], ["ma tagata,", "and people,"], ["o e e faasagatau i aposetolo e toasefululua a le Tamai Mamoe.", "that shall fight against the twelve apostles of the Lamb."]]},
];
renderVerseSet(ch_11_Verses, 'ch11-verses');

var ch_12_Verses = [
  {num:1,words:[["Ma sa oo ina fetalai mai le agelu ia te a'u:", "And it came to pass that the angel said unto me:"], ["Vaai ia,", "Look,"], ["ma tagai i au fanau,", "and behold thy seed,"], ["ma fanau foi a ou uso. Ma sa ou vaai ma iloa atu le laueleele o le folafolaga;", "and also the seed of thy brethren. And I looked and beheld the land of promise;"], ["ma sa ou vaaia motu o tagata,", "and I beheld multitudes of  people,"], ["ioe,", "yea,"], ["e peiseai ua tusa lo latou toatele ma oneone o le sami.", "even as it were in number as many as the sand of the sea."]]},
  {num:2,words:[["Ma sa oo ina ou vaai ua faapotopoto faatasi motu o tagata e tau,", "And it came to pass that I beheld multitudes gathered together to battle,"], ["o le tasi e faasaga i le tasi;", "one against the other;"], ["ma sa ou vaai i taua ,", "and I beheld wars,"], ["ma tala o taua,", "and rumors of wars,"], ["ma fasiga tetele i le pelu i totonu o o'u tagata.", "and great slaughters with the sword among my people."]]},
  {num:3,words:[["Ma sa oo ina ou vaai ua mavae atu tupulaga e tele,", "And it came to pass that I beheld many generations pass away,"], ["e tusa ai ma taua ma finauga i le laueleele;", "after the manner of wars and contentions in the land;"], ["ma sa ou vaai i aai e tele,", "and I beheld many cities,"], ["ioe,", "yea,"], ["sa matuai tele lava sa ou lē faitaulia i latou.", "even that I did not number them."]]},
  {num:4,words:[["Ma sa oo ina ou vaai i se puao o le pogisa i luga o le laueleele o le folafolaga;", "And it came to pass that I saw a mist of darkness on the face of the land of promise;"], ["ma sa ou vaai i uila,", "and I saw lightnings,"], ["ma sa ou faalogo i faititili,", "and I heard thunderings,"], ["ma mafuie,", "and earthquakes,"], ["ma ituaiga uma o gogolo eseese;", "and all manner of tumultuous noises;"], ["ma sa ou vaai i le eleele ma papa,", "and I saw the earth and the rocks,"], ["ua mavaevae i latou;", "that they rent;"], ["ma sa ou vaai i mauga ua solo nutililii;", "and I saw mountains tumbling into pieces;"], ["ma sa ou vaai i fanua laugatasi o le eleele,", "and I saw the plains of the earth,"], ["ua mavaevae i latou;", "that they were broken up;"], ["ma sa ou vaai i aai e tele ua gogoto ;", "and I saw many cities that they were sunk;"], ["ma sa ou vaai i le tele ua mu i le afi;", "and I saw many that they were burned with fire;"], ["ma sa ou vaai i le tele ua solo i le eleele,", "and I saw many that did tumble to the earth,"], ["ona o lona galulu tele.", "because of the quaking thereof."]]},
  {num:5,words:[["Ma sa oo ina ua uma ona ou vaai i nei mea,", "And it came to pass after I saw these things,"], ["sa ou vaaia le puao o le pogisa,", "I saw the vapor of darkness,"], ["ua alu ese atu mai luga o le lalolagi;", "that it passed from off the face of the earth;"], ["ma faauta,", "and behold,"], ["sa ou vaaia motu o tagata o e sa lei pauu i le tetele ma le mata'utia o faamasinoga a le Alii.", "I saw multitudes who had not fallen because of the great and terrible judgments of the Lord."]]},
  {num:6,words:[["Ma sa ou vaai ua avanoa le lagi,", "And I saw the heavens open,"], ["ma le Tamai Mamoe a le Atua ua afio ifo mai le lagi;", "and the Lamb of God descending out of heaven;"], ["ma sa afio ifo o ia i lalo ma faaali mai o ia lava ia te i latou.", "and he came down and showed himself unto them."]]},
  {num:7,words:[["Ma sa ou vaai foi ma molimauina sa afio ifo le Agaga Paia i luga o isi e toasefululua ;", "And I also saw and bear record that the Holy Ghost fell upon twelve others;"], ["ma sa faauuina i latou e le Atua,", "and they were ordained of God,"], ["ma filifilia.", "and chosen."]]},
  {num:8,words:[["Ma sa fetalai mai le agelu ia te a'u,", "And the angel spake unto me,"], ["fai mai:", "saying:"], ["Faauta i soo e toasefululua a le Tamai Mamoe,", "Behold the twelve disciples of the Lamb,"], ["o e ua filifilia e auauna atu i au fanau.", "who are chosen to minister unto thy seed."]]},
  {num:9,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["E te manatua aposetolo e toasefululua a le Tamai Mamoe? Faauta o i latou ia o e o le a latou faamasinoina ituaiga e sefululua o Isaraelu;", "Thou rememberest the twelve apostles of the Lamb? Behold they are they who shall judge the twelve tribes of Israel;"], ["o le mea lea,", "wherefore,"], ["o auauna e toasefululua o au fanau o le a faamasinoina e i latou;", "the twelve ministers of thy seed shall be judged of them;"], ["ona o outou o le aiga o Isaraelu.", "for ye are of the house of Israel."]]},
  {num:10,words:[["Ma o auauna nei e toasefululua o e o loo e vaai atu i ai o le a faamasinoina au fanau. Ma,", "And these twelve ministers whom thou beholdest shall judge thy seed. And,"], ["faauta,", "behold,"], ["ua amiotonu i latou e faavavau;", "they are righteous forever;"], ["po o ona o lo latou faatuatua i le Tamai Mamoe a le Atua ua faasinasina ai o latou ofu i lona toto.", "for because of their faith in the Lamb of God their garments are made white in his blood."]]},
  {num:11,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Vaai ia! Ma sa ou vaai,", "Look! And I looked,"], ["ma iloa atu tupulaga e tolu ua mavae atu i le amiotonu;", "and beheld three generations pass away in righteous– ness;"], ["ma sa papa'e o latou ofu e pei lava o le Tamai Mamoe a le Atua. Ma sa fetalai mai le agelu ia te a'u:", "and their garments were white even like unto the Lamb of God. And the angel said unto me:"], ["Ua faasinasinaina i latou nei i le toto o le Tamai Mamoe,", "These are made white in the blood of the Lamb,"], ["ona o lo latou faatuatua ia te ia.", "because of their faith in him."]]},
  {num:12,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa ou vaai foi i le toatele o le tupulaga lona fa o e na mavae atu i le amiotonu.", "also saw many of the fourth generation who passed away in righteousness."]]},
  {num:13,words:[["Ma sa oo ina ou vaai i motu o tagata o le lalolagi ua faapotopoto faatasi.", "And it came to pass that I saw the multitudes of the earth gathered together."]]},
  {num:14,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Faauta i au fanau,", "Behold thy seed,"], ["ma fanau foi a ou uso.", "and also the seed of thy brethren."]]},
  {num:15,words:[["Ma sa oo ina ou vaai ma iloa atu tagata o a'u fanau ua faapotopoto faatasi i motu o tagata e faasaga i fanau a o'u uso;", "And it came to pass that I looked and beheld the people of my seed gathered together in multitudes against the seed of my brethren;"], ["ma sa latou faapotopoto faatasi e tau.", "and they were gathered together to battle."]]},
  {num:16,words:[["Ma sa fetalai mai le agelu ia te a'u,", "And the angel spake unto me,"], ["fai mai:", "saying:"], ["Faauta i le punavai o vai eleelea sa vaai i ai lou tamā; ioe,", "Behold the fountain of filthy water which thy father saw;"], ["le vaitafe lava lea sa tautala o ia e uiga i ai;", "yea,"], ["ma o ona loloto,", "even the river of which he spake;"], ["o loloto ia o seoli .", "and the depths thereof are the depths of hell."]]},
  {num:17,words:[["Ma o puao o le pogisa o faaosoosoga ia a le tiapolo,", "And the mists of darkness are the temptations of the devil,"], ["ia e faatauaso ai mata,", "which blindeth the eyes,"], ["ma faamaaa ai loto o le fanauga a tagata,", "and hardeneth the hearts of the children of men,"], ["ma taitai ese atu ai i latou i ala lautetele,", "and leadeth them away into broad roads,"], ["latou te fano ma se ai.", "that they perish and are lost."]]},
  {num:18,words:[["Ma o le fale tele ma le ateatea,", "And the large and spacious building,"], ["lea sa vaai i ai lou tamā,", "which thy father saw,"], ["o mafaufauga lē aoga ma le faamaualuga lea o le fanauga a tagata. Ma ua vavae ese i latou i se vanu tele ma le mata'utia;", "is vain imaginations and the pride of the children of men. And a great and a terrible gulf divideth them;"], ["ioe,", "yea,"], ["o le afioga lava lea o le faamasinotonu o le Atua Faavavau,", "even the word of the justice of the Eternal God,"], ["ma le Mesia o Lē o le Tamai Mamoe a le Atua,", "and the Messiah who is the Lamb of God,"], ["o Lē ua molimau i ai le Agaga Paia,", "of whom the Holy Ghost beareth record,"], ["mai le amataga o le lalolagi seia oo mai i le taimi nei,", "from the beginning of the world until this time,"], ["ma mai i le taimi nei e oo i le faavavau.", "and from this time henceforth and forever."]]},
  {num:19,words:[["Ma a'o fetalai mai e le agelu nei upu,", "And while the angel spake these words,"], ["sa ou vaai ma iloa atu fanau a o'u uso ua tau faasaga mai i a'u fanau,", "I beheld and saw that the seed of my brethren did contend against my seed,"], ["e tusa ma le fetalaiga a le agelu;", "according to the word of the angel;"], ["ma ona o le faamaualuluga o a'u fanau,", "and because of the pride of my seed,"], ["ma faaosoosoga a le tiapolo,", "and the temptations of the devil,"], ["na ou vaai ua manumalo ai le fanau a o'u uso i tagata o a'u fanau.", "I beheld that the seed of my brethren did overpower the people of my seed."]]},
  {num:20,words:[["Ma sa oo ina ou vaai,", "And it came to pass that I beheld,"], ["ma iloa atu tagata o le fanau a o'u uso ua latou manumalo i a'u fanau;", "and saw the people of the seed of my brethren that they had overcome my seed;"], ["ma ua latou o atu o ni motu o tagata i luga o le laueleele.", "and they went forth in multitudes upon the face of the land."]]},
  {num:21,words:[["Ma sa ou vaai atu ia te i latou ua faapotopoto faatasi i motu o tagata;", "And I saw them gathered together in multitudes;"], ["ma sa ou vaai i taua ma tala o taua i totonu o i latou;", "and I saw wars and rumors of wars among them;"], ["ma sa ou vaai i le tele o tupulaga ua mavae atu i taua ma tala o taua.", "and in wars and rumors of wars I saw many generations pass away."]]},
  {num:22,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Faauta o i latou nei o le a faaitiitia i le lē talitonu.", "Behold these shall dwindle in unbelief."]]},
  {num:23,words:[["Ma sa oo ina 'ou vaai atu,", "And it came to pass that I beheld,"], ["ina ua mavae ona faaitiitia o i latou i le lē talitonu,", "after they had dwindled in unbelief they became a dark,"], ["ua avea i latou ma tagata uli , ma inosia,", "and loathsome,"], ["ma eleelea ,", "and a filthy people,"], ["ua tutumu i le paie ma ituaiga uma o mea inosia.", "full of idleness and all manner of abominations."]]},
];
renderVerseSet(ch_12_Verses, 'ch12-verses');

var ch_13_Verses = [
  {num:1,words:[["Ma sa oo ina fetalai mai le agelu ia te a'u,", "And it came to pass that the angel spake unto me,"], ["fai mai:", "saying:"], ["Vaai ia! Ma sa ou vaai ma iloa atu atunuu ma malo e tele.", "Look! And I looked and beheld many nations and kingdoms."]]},
  {num:2,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["O le a le mea ua e vaai atu i ai? Ma sa ou fai atu:", "What beholdest thou? And I said:"], ["Ua ou vaai atu i atunuu ma malo e tele.", "I behold many nations and kingdoms."]]},
  {num:3,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["O atunuu ma malo ia o Nuuese.", "These are the nations and kingdoms of the Gentiles."]]},
  {num:4,words:[["Ma sa oo ina ou vaaia i totonu o atunuu o Nuuese le faavaega o se ekalesia tele.", "And it came to pass that I saw among the nations of the Gentiles the formation of a great church."]]},
  {num:5,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Faauta i le faavaega o se ekalesia ua sili ona inosia i isi ekalesia uma,", "Behold the formation of a church which is most abominable above all other churches,"], ["lea ua fasiotia le au paia a le Atua,", "which slayeth the saints of God,"], ["ioe,", "yea,"], ["ma faasaunoa ia te i latou ma noatia i latou i lalo,", "and tortureth them and bindeth them down,"], ["ma faaamo i latou i se amo u'amea,", "and yoketh them with a yoke of iron,"], ["ma aumai i latou i lalo i le faatagataotauaina.", "and bringeth them down into captivity."]]},
  {num:6,words:[["Ma sa oo ina ou vaai i lenei ekalesia tele ma le inosia;", "And it came to pass that I beheld this great and abominable church;"], ["ma sa ou vaai o le tiapolo o ia lea na faavaeina.", "and I saw the devil that he was the founder of it."]]},
  {num:7,words:[["Ma sa ou vaai foi i auro ,", "And I also saw gold,"], ["ma ario,", "and silver,"], ["ma silika,", "and silks,"], ["ma 'ie mūmū,", "and scarlets,"], ["ma 'ie lino miloa lelei,", "and finetwined linen,"], ["ma ituaiga uma o ofu taugata;", "and all manner of precious clothing;"], ["ma sa ou vaai i fafine talitane e toatele.", "and I saw many harlots."]]},
  {num:8,words:[["Ma sa fetalai mai le agelu ia te a'u,", "And the angel spake unto me,"], ["fai mai:", "saying:"], ["Faauta i le auro,", "Behold the gold,"], ["ma le ario,", "and the silver,"], ["ma silika,", "and the silks,"], ["ma 'ie mūmū,", "and the scarlets,"], ["ma 'ie lino miloa lelei,", "and the finetwined linen,"], ["ma ofu taugata,", "and the precious clothing,"], ["ma fafine talitane,", "and the harlots,"], ["o manaoga ia o lenei ekalesia tele ma le inosia.", "are the desires of this great and abominable church."]]},
  {num:9,words:[["Ma o viiga foi o le lalolagi ua latou faaumatia ai le au paia a le Atua,", "And also for the praise of the world do they destroy the saints of God,"], ["ma aumai i latou i lalo i le faatagataotauaina.", "and bring them down into captivity."]]},
  {num:10,words:[["Ma sa oo ina ou vaai ma iloa atu vai e tele;", "And it came to pass that I looked and beheld many waters;"], ["ma sa vavaeese ai Nuuese mai fanau a o'u uso.", "and they divided the Gentiles from the seed of my brethren."]]},
  {num:11,words:[["Ma sa oo ina fetalai mai le agelu ia te a'u:", "And it came to pass that the angel said unto me:"], ["Faauta ua i luga o le fanau a ou uso le toasa o le Atua.", "Behold the wrath of God is upon the seed of thy brethren."]]},
  {num:12,words:[["Ma sa ou vaai ma iloa atu se tagata i totonu o Nuuese,", "And I looked and beheld a man among the Gentiles,"], ["o lē sa vavaeese mai le fanau a o'u uso i vai e tele;", "who was separated from the seed of my brethren by the many waters;"], ["ma sa ou vaai i le Agaga o le Atua,", "and I beheld the Spirit of God,"], ["ua afio ifo ma ua galue i luga o lea tagata;", "that it came down and wrought upon the man;"], ["ma sa alu atu o ia i luga o vai e tele,", "and he went forth upon the many waters,"], ["seia oo atu lava i le fanau a o'u uso,", "even unto the seed of my brethren,"], ["o e sa i le laueleele na folafolaina.", "who were in the promised land."]]},
  {num:13,words:[["Ma sa oo ina ou vaai i le Agaga o le Atua,", "And it came to pass that I beheld the Spirit of God,"], ["ua galue o ia i luga o isi tagata o Nuuese;", "that it wrought upon other Gentiles;"], ["ma sa latou o ese atu i fafo mai le faatagataotauaina,", "and they went forth out of captivity,"], ["i luga o vai e tele.", "upon the many waters."]]},
  {num:14,words:[["Ma sa oo ina ou vaaia motu e tele o Nuuese i luga o le laueleele o le folafolaga;", "And it came to pass that I beheld many multitudes of the Gentiles upon the land of promise;"], ["ma sa ou vaaia le toasa o le Atua,", "and I beheld the wrath of God,"], ["ua i luga o le fanau a o'u uso;", "that it was upon the seed of my brethren;"], ["ma sa faataapeapeina i latou i luma o Nuuese ma fasia.", "and they were scattered before the Gentiles and were smitten."]]},
  {num:15,words:[["Ma sa ou vaai i le Agaga o le Alii,", "And I beheld the Spirit of the Lord,"], ["ua i luga o Nuuese;", "that it was upon the Gentiles,"], ["ma ua latou manuia ma mauaina le laueleele mo o latou tofi;", "and they did prosper and obtain the land for their inheritance;"], ["ma sa ou vaai ua papa'e i latou,", "and I beheld that they were white,"], ["ma ua sili ona lalelei ma aulelei ,", "and exceedingly fair and beautiful,"], ["e pei lava o o'u tagata ae lei fasiotia i latou.", "like unto my people before they were slain."]]},
  {num:16,words:[["Ma sa oo ina vaaia e a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["Nuuese o e na o ese atu i fafo mai le faatagataotauaina, sa latou faamaualaloina i latou lava i luma o le Alii;", "beheld that the Gentiles who had gone forth out of captivity did humble themselves before the Lord;"], ["ma sa faatasi le mana o le Alii ma i latou .", "and the power of the Lord was with them."]]},
  {num:17,words:[["Ma sa ou vaai ua faapotopoto faatasi o latou tinā Nuuese i luga o vai,", "And I beheld that their mother Gentiles were gathered together upon the waters,"], ["ma luga foi o le laueleele,", "and upon the land also,"], ["e tau faasaga ia te i latou.", "to battle against them."]]},
  {num:18,words:[["Ma sa ou vaai ua faatasi le mana o le Atua ma i latou, ma ua i luga foi o i latou uma o e sa faapotopoto faatasi e faasagatau mai ia te i latou,", "And I beheld that the power of God was with them,"], ["le toasa o le Atua.", "and also that the wrath of God was upon  all those that were gathered together against them to battle."]]},
  {num:19,words:[["Ma o a'u,", "And I,"], ["o Nifae, sa ou vaai atu i Nuuese ia sa o ese mai i fafo mai le faatagataotauaina,", "Nephi,"], ["ua laveaiina e le mana o le Atua mai lima o isi atunuu uma.", "beheld that the Gentiles that had gone out of captivity were delivered by the power of God out of the hands of all other nations."]]},
  {num:20,words:[["Ma sa oo ina vaai atu a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["ua latou manuia i le laueleele;", "beheld that they did prosper in the land;"], ["ma sa ou vaaia se tusi ,", "and I beheld a book,"], ["ma sa ave atu i totonu o i latou.", "and it was carried forth among them."]]},
  {num:21,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["E te iloa le uiga o le tusi?", "Knowest thou the meaning of the book?"]]},
  {num:22,words:[["Ma sa ou fai atu ia te ia:", "And I said unto him:"], ["Ou te lē iloa.", "I know not."]]},
  {num:23,words:[["Ma sa fetalai mai o ia:", "And he said:"], ["Faauta ua sau le tusi mai le fofoga o se Iutaia. Ma o a'u,", "Behold it proceedeth out of the mouth of a Jew. And I,"], ["o Nifae,", "Nephi,"], ["sa ou vaai i ai;", "beheld it;"], ["ma sa fetalai mai o ia ia te a'u:", "and he said unto me:"], ["O le tusi ua e vaai atu i ai o se talafaamaumau lea o tagata Iutaia,", "The book that thou beholdest is a record of the Jews,"], ["ua i ai i totonu feagaiga a le Alii,", "which contains the covenants of the Lord,"], ["na ia faia i le aiga o Isaraelu;", "which he hath made unto the house of Israel;"], ["ma ua i ai foi i totonu le tele o valoaga a perofeta paia;", "and it also containeth many of the prophecies of the holy prophets;"], ["ma o se talafaamaumau e pei o togitogiga ua i ai i luga o papatusi apamemea,", "and it is a record like unto the engravings which are upon the plates of brass,"], ["ae ua lē tele naua;", "save there are not so many;"], ["e ui i lea,", "nevertheless,"], ["ua i ai i totonu o i latou feagaiga a le Alii,", "they contain the covenants of the Lord,"], ["ia na ia faia i le aiga o Isaraelu;", "which he hath made unto the house of Israel;"], ["o le mea lea,", "wherefore,"], ["ua aoga tele ai i latou i Nuuese.", "they are of great worth unto the Gentiles."]]},
  {num:24,words:[["Ma sa fetalai mai le agelu a le Alii ia te a'u:", "And the angel of the Lord said unto me:"], ["Sa e vaai o le tusi sa sau mai le fofoga o se Iutaia;", "Thou hast beheld that the book proceeded forth from the mouth of a Jew;"], ["ma ina ua sau mai le fofoga o se Iutaia, sa i ai le atoatoa o le talalelei a le Alii,", "and when it proceeded forth from the mouth of a Jew it contained the fulness of the gospel of the Lord,"], ["o lē ua molimau i ai le au aposetolo e toasefululua;", "of whom the twelve apostles bear record;"], ["ma ua latou molimau e tusa ma le upumoni o loo i ai i le Tamai Mamoe a le Atua.", "and they bear record according to the truth which is in the Lamb of God."]]},
  {num:25,words:[["O le mea lea,", "Wherefore,"], ["ua o atu ia mea ma le mamā mai tagata Iutaia i Nuuese ,", "these things go forth from the Jews in purity unto the Gentiles,"], ["e tusa ma le upumoni o loo i le Atua.", "according to the truth which is in God."]]},
  {num:26,words:[["Ma ina ua uma ona o atu o ia mea e ala atu i le lima o le au aposetolo e toasefululua a le Tamai Mamoe,", "And after they go forth by the hand of the twelve apostles of the Lamb,"], ["mai tagata Iutaia i Nuuese,", "from the Jews unto the Gentiles,"], ["sa e vaai i le faavaega o lena ekalesia tele ma le inosia,", "thou seest the formation of a great and abominable church,"], ["lea ua silisili ona inosia i luga o isi ekalesia uma;", "which is most abominable above all other churches;"], ["aua faauta,", "for behold,"], ["ua latou aveese mai le talalelei a le Tamai Mamoe le tele o vaega ia ua manino ma sili ona pele;", "they have taken away from the gospel of the Lamb many parts which are plain and most precious;"], ["ma e tele foi feagaiga a le Alii ua latou aveese.", "and also many covenants of the Lord have they taken away."]]},
  {num:27,words:[["Ma ua latou faia lenei mea uma ina ia latou faasese ai ala sa'o o le Alii,", "And all this have they done that they might pervert the right ways of the Lord,"], ["ina ia latou faatauaso ai mata ma faamaaa ai loto o le fanauga a tagata.", "that they might blind the eyes and harden the hearts of the children of men."]]},
  {num:28,words:[["O le mea lea,", "Wherefore,"], ["ua e vaai ina ua uma ona alu atu o le tusi e ala atu i lima o le ekalesia tele ma le inosia,", "thou seest that after the book hath gone forth through the hands of the great and abominable church,"], ["e tele mea manino ma pele ua aveesea mai le tusi,", "that there are many plain and precious things taken away from the book,"], ["o le tusi lea e uiga i le Tamai Mamoe a le Atua.", "which is the book of the Lamb of God."]]},
  {num:29,words:[["Ma ina ua uma ona aveesea o ia mea manino ma pele ua alu atu le tusi i atunuu uma o Nuuese;", "And after these plain and precious things were taken away it goeth forth unto all the nations of the Gentiles;"], ["ma ina ua uma ona alu atu o le tusi i atunuu uma o Nuuese,", "and after it goeth forth unto all the nations of the Gentiles,"], ["ioe,", "yea,"], ["e oo lava i tala atu o vai e tele sa e vaai i ai faatasi ma Nuuese o e sa o ese atu i fafo mai le faatagataotauaina,", "even across the many waters which thou hast seen  with the Gentiles which have gone forth out of captivity,"], ["sa e vaai—ona o le tele o mea manino ma pele ua aveesea i fafo mai le tusi,", "thou seest—because of the many plain and precious things which have been taken out of the book,"], ["ia sa manino i le malamalamaaga o le fanauga a tagata,", "which were plain unto the understanding of the children of men,"], ["e tusa ma le manino lea o loo i le Tamai Mamoe a le Atua—ona o ia mea ua aveesea i fafo mai le talalelei a le Tamai Mamoe,", "according to the plainness which is in the Lamb of God—because of these things which are taken away out of the gospel of the Lamb,"], ["ua matua toatele lava ua tautevateva,", "an exceedingly great many do stumble,"], ["ioe,", "yea,"], ["ua oo ina maua ai e Satani le mana tele i luga o i latou.", "insomuch that Satan hath great power over them."]]},
  {num:30,words:[["E ui i lea,", "Nevertheless,"], ["sa e vaai o Nuuese o e na o ese atu i fafo mai le faatagataotauaina,", "thou beholdest that the Gentiles who have gone forth out of captivity,"], ["ma ua sii a'e e le mana o le Atua i luga o isi atunuu uma,", "and have been lifted up by the power of God above all other nations,"], ["i luga o le laueleele lea ua silisili ona lelei i isi laueleele uma,", "upon the face of the land which is choice above all other lands,"], ["o le laueleele lea sa osifeagaiga ai le Alii le Atua ma lou tamā o le a maua e ana fanau mo laueleele o lo latou tofi;", "which is the land that the Lord God hath covenanted with thy father that his seed should have for the land of their inheritance;"], ["o le mea lea,", "wherefore,"], ["ua e vaai e lē tuuina lava e le Alii le Atua ia faaumatia atoa e Nuuese au fanau toto-filogia ,", "thou seest that the Lord God will not suffer that the Gentiles will utterly destroy the mixture of thy seed,"], ["ua i ai i totonu o ou uso.", "which are among thy brethren."]]},
  {num:31,words:[["Pe tuua foi e ia 'ia faaumatia e Nuuese le fanau a ou uso.", "Neither will he suffer that the Gentiles shall destroy the seed of thy brethren."]]},
  {num:32,words:[["Pe tuua foi e le Alii le Atua ia tumau pea e faavavau Nuuese i lena tulaga leaga tele o le tauaso,", "Neither will the Lord God suffer that the Gentiles shall forever remain in that awful state of blindness,"], ["lea ua e vaai ua latou i ai,", "which thou beholdest they are in,"], ["ona o vaega manino ma sili ona pele o le talalelei a le Tamai Mamoe ua taofia i tua e lena ekalesia inosia,", "because of the plain and most precious parts of the gospel of the Lamb which have been kept back by that abominable church,"], ["o lona faavaega sa e vaai i ai.", "whose formation thou hast seen."]]},
  {num:33,words:[["O le mea lea ua fetalai mai ai le Tamai Mamoe a le Atua:", "Wherefore saith the Lamb of God:"], ["O le a 'Ou alofa mutimutivale i Nuuese,", "I will be merciful unto the Gentiles,"], ["i le asia o le toe vaega o le aiga o Isaraelu i le faamasinoga tele.", "unto the visiting of the remnant of the house of Israel in great judgment."]]},
  {num:34,words:[["Ma sa oo ina fetalai mai le agelu a le Alii ia te a'u,", "And it came to pass that the angel of the Lord spake unto me,"], ["fai mai:", "saying:"], ["Faauta,", "Behold,"], ["ua fetalai mai le Tamai Mamoe a le Atua,", "saith the Lamb of God,"], ["a uma ona Ou asiasi atu i le toe vaega o le aiga o Isaraelu—ma o lenei toe vaega o e ua Ou tautala i ai o le fanau lea a lou tamā—o le mea lea,", "after I have visited the remnant of the house of Israel—and this remnant of whom I speak is the seed of thy father—wherefore,"], ["a uma ona Ou asiasi atu ia te i latou i le faamasinoga,", "after I have visited them in judgment,"], ["ma taia i latou i le lima o Nuuese,", "and smitten them by the hand of the Gentiles,"], ["ma a mavae ona tautevateva tele o Nuuese,", "and after the Gentiles do stumble exceedingly,"], ["ona o vaega sili ona manino ma pele o le talalelei a le Tamai Mamoe sa taofia i tua e lena ekalesia inosia,", "because of the most plain and precious parts of the gospel of the Lamb which have been kept back by that abominable church,"], ["le tinā lea o fafine talitane,", "which is the mother of harlots,"], ["ua fetalai mai ai le Tamai Mamoe—o le a Ou alofa mutimutivale i Nuuese i lena aso,", "saith the Lamb—I will be merciful unto the Gentiles in that day,"], ["e oo lava ina o le a Ou 'aumai ia te i latou,", "insomuch that I will bring forth unto them,"], ["i lo'u lava mana,", "in mine own power,"], ["le tele o la'u talalelei,", "much of my gospel,"], ["lea o le a manino ma pele,", "which shall be plain and precious,"], ["ua fetalai mai ai le Tamai Mamoe.", "saith the Lamb."]]},
  {num:35,words:[["Aua,", "For,"], ["faauta,", "behold,"], ["ua fetalai mai le Tamai Mamoe:", "saith the Lamb:"], ["O le a 'Ou faaali atu a'u lava i au fanau,", "I will manifest myself unto thy seed,"], ["ma o le a latou tusia le tele o mea o le a Ou aoao atu ia te i latou,", "that they shall write many things which I shall minister unto them,"], ["ia o le a manino ma pele;", "which shall be plain and precious;"], ["ma a uma ona faaumatia o au fanau,", "and after thy seed shall be destroyed,"], ["ma faaitiitia i le lē talitonu,", "and dwindle in unbelief,"], ["ma fanau foi a ou uso,", "and also the seed of thy brethren,"], ["faauta,", "behold,"], ["o le a natia nei mea,", "these things shall be hid up,"], ["ia oo mai i Nuuese,", "to come forth unto the Gentiles,"], ["e ala mai i le meaalofa ma le mana o le Tamai Mamoe.", "by the gift and power of the Lamb."]]},
  {num:36,words:[["Ma o le a tusia i totonu o i latou la'u talalelei ,", "And in them shall be written my gospel,"], ["ua fetalai mai ai le Tamai Mamoe,", "saith the Lamb,"], ["ma la'u papa ma la'u olataga.", "and my rock and my salvation."]]},
  {num:37,words:[["Ma 'amuia lava i latou o e e saili e aumai la'u Siona i lena aso,", "And blessed are they who shall seek to bring forth my Zion at that day,"], ["ona o le a latou maua le meaalofa ma le mana o le Agaga Paia;", "for they shall have the gift and the power of the Holy Ghost;"], ["ma afai latou te tumau e oo i le iuga o le a sii a'e i latou i luga i le aso gataaga,", "and if they endure unto the end they shall be lifted up at the last day,"], ["ma o le a faaolaina i le malo tumau-faavavau o le Tamai Mamoe;", "and shall be saved in the everlasting kingdom of the Lamb;"], ["ma 'ai se tasi na te talai atu le filemu,", "and whoso shall publish peace,"], ["ioe,", "yea,"], ["o tala o le olioli tele,", "tidings of great joy,"], ["o le a matagofie naua i latou i luga o mauga.", "how beautiful upon the mountains shall they be."]]},
  {num:38,words:[["Ma sa oo ina ou vaai i le toe vaega o le fanau a o'u uso,", "And it came to pass that I beheld the remnant of the seed of my brethren,"], ["ma le tusi foi e uiga i le Tamai Mamoe a le Atua,", "and also the book of the Lamb of God,"], ["lea na sau mai le fofoga o le Iutaia,", "which had proceeded forth from the mouth of the Jew,"], ["ua sau mai Nuuese i le toe vaega o le fanau a o'u uso.", "that it came forth from the Gentiles unto the remnant of the seed of my brethren."]]},
  {num:39,words:[["Ma ina ua uma ona oo mai o le tusi ia te i latou sa ou vaaia isi tusi ,", "And after it had come forth unto them I beheld other books,"], ["na o mai e ala mai i le mana o le Tamai Mamoe,", "which came forth by the power of the Lamb,"], ["mai Nuuese ia te i latou,", "from the Gentiles unto them,"], ["mo le faatalitonuina o Nuuese ma le toe vaega o le fanau a o'u uso,", "unto the convincing of the Gentiles and the remnant of the seed of my brethren,"], ["ma tagata Iutaia foi o e ua faataapeapeina i luga o le lalolagi,", "and also the Jews who were scattered upon all the face of the earth,"], ["e faapea ua moni talafaamaumau a perofeta ma aposetolo e toasefululua a le Tamai Mamoe.", "that the records of the prophets and of the twelve apostles of the Lamb are true."]]},
  {num:40,words:[["Ma sa fetalai mai le agelu ia te a'u,", "And the angel spake unto me,"], ["fai mai:", "saying:"], ["O talafaamaumau mulimuli nei,", "These last records,"], ["na e vaai atu i ai i totonu o Nuuese,", "which thou hast seen among the Gentiles,"], ["o le a faamaonia ai le moni o talafaamaumau muamua,", "shall establish the truth of the first,"], ["ia e mai aposetolo e toasefululua a le Tamai Mamoe,", "which are of the twelve apostles of the Lamb,"], ["ma o le a faailoa mai ai mea manino ma pele na aveesea mai ia i latou;", "and shall make known the plain and precious things which have been taken away from them;"], ["ma o le a faailoa atu ai i ituaiga,", "and shall make known to all kindreds,"], ["gagana,", "tongues,"], ["ma tagata uma,", "and people,"], ["o le Tamai Mamoe a le Atua o le Alo lea o le Tamā Faavavau,", "that the Lamb of God is the Son of the Eternal Father,"], ["ma o le Faaola o le lalolagi;", "and the Savior of the world;"], ["ma e ao i tagata uma ona o mai ia te ia,", "and that all men must come unto him,"], ["pe e lē mafai ona faaolaina i latou.", "or they cannot be saved."]]},
  {num:41,words:[["Ma e ao ina latou o mai e tusa ma afioga o le a faatutuina e le fofoga o le Tamai Mamoe;", "And they must come according to the words which shall be established by the mouth of the Lamb;"], ["ma o afioga a le Tamai Mamoe o le a faaali mai i talafaamaumau a au fanau,", "and the words of the Lamb shall be made known in the records of thy seed,"], ["faapea foi i talafaamaumau a aposetolo e toasefululua a le Tamai Mamoe;", "as well as in the records of the twelve apostles of the Lamb;"], ["o le mea lea o le a faatutuina i laua uma i le tasi ;", "wherefore they both shall be established in one;"], ["ona ua tasi le Atua ma tasi le Leoleo Mamoe i luga o le lalolagi atoa.", "for there is one God and one Shepherd over all the earth."]]},
  {num:42,words:[["Ma e oo mai le taimi o le a faaali atu ai e ia o ia lava i atunuu uma,", "And the time cometh that he shall manifest himself unto all nations,"], ["i Iutaia ma i Nuuese foi;", "both unto the Jews and also unto the Gentiles;"], ["ma a uma ona faaali atu e ia o ia lava i Iutaia ma i Nuuese foi,", "and after he has manifested himself unto the Jews and also unto the Gentiles,"], ["ona ia faaali atu lea o ia lava i Nuuese ma i Iutaia foi,", "then he shall manifest himself unto the Gentiles and also unto the Jews,"], ["ma o lē e mulimuli o le a muamua,", "and the last shall be first,"], ["ma o lē e muamua o le a mulimuli.", "and the first shall be last."]]},
];
renderVerseSet(ch_13_Verses, 'ch13-verses');

var ch_14_Verses = [
  {num:1,words:[["Ma o le a oo mai,", "And it shall come to pass,"], ["pe afai e faalogologo Nuuese i le Tamai Mamoe a le Atua i lena aso o le a ia faaali mai ai o ia lava ia te i latou i le upu,", "that if the Gentiles shall hearken unto the Lamb of God in that day that he shall manifest himself unto them in word,"], ["ma i le mana foi,", "and also in power,"], ["ma i galuega lava,", "in very deed,"], ["i le aveesea o latou maa tū'ia—", "unto the taking away of their stumbling blocks—"]]},
  {num:2,words:[["Ma lē faamaaaina o latou loto e faasaga i le Tamai Mamoe a le Atua,", "And harden not their hearts against the Lamb of God,"], ["o le a faitauina i latou i totonu o fanau a lou tamā;", "they shall be numbered among the seed of thy father;"], ["ioe,", "yea,"], ["o le a faitauina i latou i totonu o le aiga o Isaraelu;", "they shall be numbered among the house of Israel;"], ["ma o le a avea i latou ma tagata faamanuiaina e faavavau i luga o le laueleele na folafolaina;", "and they shall be a blessed people upon the promised land forever;"], ["o le a lē toe aumaia i latou i lalo i le faatagataotauaina;", "they shall be no more brought down into captivity;"], ["ma o le a lē toe feleiloana'i le aiga o Isaraelu.", "and the house of Israel shall no more be confounded."]]},
  {num:3,words:[["Ma o lena lua tele,", "And that great pit,"], ["lea sa eli mo i latou e lena ekalesia tele ma le inosia,", "which hath been digged for them by that great and abominable church,"], ["lea sa faavae e le tiapolo ma ana fanau,", "which was founded by the devil and his children,"], ["ina ia mafai ona taitai ese e ia agaga o tagata i lalo i seoli—ioe,", "that he might lead away the souls of men down to hell—yea,"], ["lena lua tele lea na eli mo le faaumatiaina o tagata, o le a faatumuina ia te i latou lava o e na elia,", "that great pit which hath been digged for the destruction of men shall be filled by those who digged it,"], ["mo lo latou faaumatiaga atoa,", "unto their utter destruction,"], ["ua fetalai mai ai le Tamai Mamoe a le Atua;", "saith the Lamb of God;"], ["e lē o le faaumatiaga o le agaga,", "not the destruction of the soul,"], ["ae o lona lafoina lea i totonu o lena seoli lea ua leai se iuga.", "save it be the casting of it into that hell which hath no end."]]},
  {num:4,words:[["Aua faauta,", "For behold,"], ["ua tusa lenei ma le faatagataotauaina a le tiapolo,", "this is according to the captivity of the devil,"], ["ma tusa foi ma le faamasinotonu o le Atua,", "and also according to the justice of God,"], ["i luga o i latou uma o e e faia amioleaga ma mea inosia i ona luma.", "upon all those who will work wickedness and abomination before him."]]},
  {num:5,words:[["Ma sa oo ina fetalai mai le agelu ia te a'u,", "And it came to pass that the angel spake unto me,"], ["o Nifae,", "Nephi,"], ["fai mai:", "saying:"], ["Ua e vaai afai e salamo Nuuese o le a lelei ia te i latou;", "Thou hast beheld that if the Gentiles repent it shall be well with them;"], ["ma ua e iloa foi e uiga i feagaiga a le Alii i le aiga o Isaraelu;", "and thou also knowest concerning the covenants of the Lord unto the house of Israel;"], ["ma sa e faalogo foi 'ai se e lē salamo o le a fano o ia.", "and thou also hast heard that whoso repenteth not must perish."]]},
  {num:6,words:[["O lea,", "Therefore,"], ["oi talofa i Nuuese pe afai latou te faamaaa o latou loto e faasaga i le Tamai Mamoe a le Atua.", "wo be unto the Gentiles if it so be that they harden their hearts against the Lamb of God."]]},
  {num:7,words:[["Aua e oo mai le taimi,", "For the time cometh,"], ["ua fetalai mai ai le Tamai Mamoe a le Atua,", "saith the Lamb of God,"], ["o le a Ou faia ai se galuega tele ma le ofoofogia i totonu o le fanauga a tagata;", "that I will work a great and a marvelous work among the children of men;"], ["o se galuega o le a tumau-faavavau,", "a work which shall be everlasting,"], ["a lē i le tasi itu o le isi itu—a lē mo le faatalitonuina o i latou i le filemu ma le ola e faavavau,", "either on the one hand or on the other—either to the convincing of them unto peace and life eternal,"], ["o le tuuina atu lea o i latou i le maaa o o latou loto ma le tauaso o o latou mafaufau e aumai ai i latou i lalo i le faatagataotauaina,", "or unto the deliverance of them to the hardness of their hearts and the blindness of their minds unto their being brought down into captivity,"], ["ma le faafanoga foi,", "and also into destruction,"], ["faaletino ma faaleagaga,", "both temporally and spiritually,"], ["e tusa ma le faatagataotauaina a le tiapolo,", "according to the captivity of the devil,"], ["lea sa Ou tautalaina.", "of which I have spoken."]]},
  {num:8,words:[["Ma sa oo ina ua uma ona fofogaina e le agelu nei upu,", "And it came to pass that when the angel had spoken these words,"], ["sa fetalai mai o ia ia te a'u:", "he said unto me:"], ["E te manatua feagaiga a le Tamā i le aiga o Isaraelu? Sa ou fai atu ia te ia,", "Rememberest thou the covenants of the Father unto the house of Israel? I said unto him,"], ["Ioe.", "Yea."]]},
  {num:9,words:[["Ma sa oo ina fetalai mai o ia ia te a'u:", "And it came to pass that he said unto me:"], ["Vaai ia,", "Look,"], ["ma tagai i lena ekalesia tele ma le inosia,", "and behold that great and abominable church,"], ["le tinā lea o mea inosia,", "which is the mother of abominations,"], ["o lē na faavaeina o le tiapolo .", "whose founder is the devil."]]},
  {num:10,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["Faauta,", "Behold there are save two churches only;"], ["ua nao le lua lava ekalesia; o le tasi o le ekalesia a le Tamai Mamoe a le Atua,", "the one is the church of the Lamb of God,"], ["ma le tasi o le ekalesia a le tiapolo;", "and the other is the church of the devil;"], ["o le mea lea,", "wherefore,"], ["'ai se ua lē i ai i le ekalesia a le Tamai Mamoe a le Atua, ua i ai o ia i lena ekalesia tele,", "whoso belongeth not to the church of the Lamb of God belongeth to that great church,"], ["le tinā lea o mea inosia;", "which is the mother of abominations;"], ["ma o ia lea o le fafine talitane o le lalolagi atoa.", "and she is the whore of all the earth."]]},
  {num:11,words:[["Ma sa oo ina ou vaai ma iloa atu le fafine talitane o le lalolagi atoa,", "And it came to pass that I looked and beheld the whore of all the earth,"], ["ma sa nofo o ia i luga o vai e tele;", "and she sat upon many waters;"], ["ma sa ia te ia le pule i luga o le lalolagi atoa,", "and she had dominion over all the earth,"], ["i totonu o atunuu uma,", "among all nations,"], ["ituaiga,", "kindreds,"], ["gagana,", "tongues,"], ["ma nuu.", "and people."]]},
  {num:12,words:[["Ma sa oo ina ou vaai atu i le ekalesia a le Tamai Mamoe a le Atua,", "And it came to pass that I beheld the church of the Lamb of God,"], ["ma sa toaitiiti ona aofai,", "and its numbers were few,"], ["ona o le amioleaga ma mea inosia a le fafine talitane o lē sa nofo i luga o vai e tele;", "because of the wickedness and abominations of the whore who sat upon many waters;"], ["e ui i lea,", "nevertheless,"], ["sa ou vaai o le ekalesia a le Tamai Mamoe,", "I beheld that the church of the Lamb,"], ["o i latou ia o le au paia a le Atua,", "who were the saints of God,"], ["ua i ai foi i latou i luga o le lalolagi atoa;", "were also upon all the face of the earth;"], ["ma sa itiiti a latou pule'aga i luga o le lalolagi,", "and their dominions upon the face of the earth were small,"], ["ona o le amioleaga o le fafine talitane tele o lē sa ou vaai i ai.", "because of the wickedness of the great whore whom I saw."]]},
  {num:13,words:[["Ma sa oo ina ou vaai atu ua faapotopoto faatasi e le tinā tele o mea inosia,", "And it came to pass that I beheld that the great mother of abominations did gather together multitudes upon the face of all the earth,"], ["motu o tagata i luga o le lalolagi atoa, i totonu o atunuu uma o Nuuese,", "among all the nations of the Gentiles,"], ["e tau faasaga i le Tamai Mamoe a le Atua.", "to fight against the Lamb of God."]]},
  {num:14,words:[["Ma sa oo ina a'u,", "And it came to pass that I,"], ["vaai a'u o Nifae,", "Nephi,"], ["i le mana o le Tamai Mamoe a le Atua,", "beheld the power of the Lamb of God,"], ["ua alu ifo i luga o le au paia o le ekalesia a le Tamai Mamoe,", "that it descended upon the saints of the church of the Lamb,"], ["ma luga o tagata o le feagaiga a le Alii,", "and upon the covenant people of the Lord,"], ["o e sa faataapeapeina i luga o le lalolagi atoa;", "who were scattered upon all the face of the earth;"], ["ma sa faaauupegaina i latou i le amiotonu ma le mana o le Atua i le mamalu tele.", "and they were armed with righteousness and with the power of God in great glory."]]},
  {num:15,words:[["Ma sa oo ina ou vaai ua sasaa ifo le toasa o le Atua i luga o lena ekalesia tele ma le inosia,", "And it came to pass that I beheld that the wrath of God was poured out upon that great and abominable church,"], ["sa oo ina i ai taua ma tala o taua i totonu o atunuu ma ituaiga uma o le lalolagi.", "insomuch that there were wars and rumors of wars among all the nations and kindreds of the earth."]]},
  {num:16,words:[["Ma ina ua amata ona i ai o taua ma tala o taua i totonu o atunuu uma e a le tinā o mea inosia,", "And as there began to be wars and rumors of wars among all the nations which belonged to the mother of abominations,"], ["sa fetalai mai le agelu ia te a'u,", "the angel spake unto me,"], ["fai mai:", "saying:"], ["Faauta,", "Behold,"], ["ua i ai i luga o le tinā o fafine talitane le toasa o le Atua;", "the wrath of God is upon the mother of harlots;"], ["ma faauta,", "and behold,"], ["ua e vaai i nei mea uma—", "thou seest all these things—"]]},
  {num:17,words:[["Ma a oo mai le aso e sasaa ifo ai le toasa o le Atua i luga o le tinā o fafine talitane,", "And when the day cometh that the wrath of God is poured out upon the mother of harlots,"], ["le ekalesia tele ma le inosia lea o le lalolagi atoa,", "which is the great and abominable church of all the earth,"], ["o lona faavae o le tiapolo,", "whose founder is the devil,"], ["ona,", "then,"], ["amata ai lea, i lena aso,", "at that day,"], ["le galuega a le Tamā,", "the work of the Father shall commence,"], ["i le sauniaina o le ala mo le faataunuuina o ana feagaiga ,", "in preparing the way for the fulfilling of his covenants,"], ["ia na ia faia i lona nuu o e o le aiga o Isaraelu.", "which he hath made to his people who are of the house of Israel."]]},
  {num:18,words:[["Ma sa oo ina fetalai mai le agelu ia te a'u,", "And it came to pass that the angel spake unto me,"], ["fai mai:", "saying:"], ["Vaai ia!", "Look!"]]},
  {num:19,words:[["Ma sa ou vaai ma iloa atu se tagata,", "And I looked and beheld a man,"], ["ma sa ofu o ia i se ofu talaloa pa'epa'e.", "and he was dressed in a white robe."]]},
  {num:20,words:[["Ma sa fetalai mai le agelu ia te a'u:", "And the angel said unto me:"], ["Faauta i se tasi o aposetolo e toasefululua a le Tamai Mamoe.", "Behold one of the twelve apostles of the Lamb."]]},
  {num:21,words:[["Faauta,", "Behold,"], ["o ia o le a vaai ma tusia le vaega o totoe o nei mea;", "he shall see and write the remainder of these things;"], ["ioe,", "yea,"], ["ma le tele foi o mea sa i ai.", "and also many things which have been."]]},
  {num:22,words:[["Ma o le a tusi foi o ia e uiga i le iuga o le lalolagi.", "And he shall also write concerning the end of the world."]]},
  {num:23,words:[["O le mea lea,", "Wherefore,"], ["o mea o le a tusia e ia ua tonu ma moni;", "the things which he shall write are just and true;"], ["ma faauta,", "and behold they are written in the book which thou beheld proceeding out of the mouth of the Jew;"], ["ua tusia ia mea i le tusi sa e vaai ua sau mai le fofoga o le Iutaia;", "and at the time they proceeded out of the mouth of the Jew,"], ["ma i le taimi na o mai ai ia mea mai le fofoga o le Iutaia, po o,", "or,"], ["i le taimi na sau ai le tusi mai le fofoga o le Iutaia,", "at the time the book proceeded out of the mouth of the Jew,"], ["o mea sa tusia ai sa malamalama ma manino,", "the things which were written were plain and pure,"], ["ma sili ona pele ma faigofie i le malamalamaaga o tagata uma.", "and most precious and easy to the understanding of all men."]]},
  {num:24,words:[["Ma faauta,", "And behold,"], ["o mea o le a tusia e lenei aposetolo a le Tamai Mamoe o le tele ia o mea na e vaai i ai;", "the things which this apostle of the Lamb shall write are many things which thou hast seen;"], ["ma faauta,", "and behold,"], ["o mea o totoe o le a e vaai i ai.", "the remainder shalt thou see."]]},
  {num:25,words:[["Ae o mea o le a e vaai i ai pe a mavae le taimi nei aua ne'i e tusia;", "But the things which thou shalt see hereafter thou shalt not write;"], ["ona ua faauuina e le Alii le Atua le aposetolo a le Tamai Mamoe a le Atua e tatau ona tusia i latou e ia.", "for the Lord God hath ordained the apostle of the Lamb of God that he should write them."]]},
  {num:26,words:[["Ma o isi foi o e sa i ai,", "And also others who have been,"], ["sa faaali atu i ai e ia ia te i latou mea uma,", "to them hath he shown all things,"], ["ma ua latou tusia i latou;", "and they have written them;"], ["ma ua faamauina i latou ina ia oo mai i lo latou manino,", "and they are sealed up to come forth in their purity,"], ["e tusa ma le upumoni o loo i ai i le Tamai Mamoe,", "according to the truth which is in the Lamb,"], ["i le taimi tatau ai a le Alii lava ia,", "in the own due time of the Lord,"], ["i le aiga o Isaraelu.", "unto the house of Israel."]]},
  {num:27,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa ou faalogo ma ou molimauina, o le igoa o le aposetolo a le Tamai Mamoe,", "heard and bear record,"], ["o Ioane ,", "that the name of the apostle of the Lamb was John,"], ["e tusa ma le fetalaiga a le agelu.", "according to the word of the angel."]]},
  {num:28,words:[["Ma faauta,", "And behold,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["ua faasa ona ou tusia o mea ua totoe o mea sa ou vaai i ai ma faalogoina;", "am forbidden that I should write the remainder of the things which I saw and heard;"], ["o le mea lea o mea ua ou tusia ua lava ia te a'u;", "wherefore the things which I have written sufficeth me;"], ["ma ua ou tusia nao se vaega itiiti o mea sa ou vaai i ai.", "and I have written but a small part of the things which I saw."]]},
  {num:29,words:[["Ma ou te molimau atu sa ou vaai i mea sa vaai i ai lo'u tamā ,", "And I bear record that I saw the things which my father saw,"], ["ma o le agelu a le Alii na ia faailoa mai i latou ia te a'u.", "and the angel of the Lord did make them known unto me."]]},
  {num:30,words:[["Ma o lenei ou te faaiu le tautala atu e faatatau i mea na ou vaai i ai a'o aveese atu a'u i le agaga;", "And now I make an end of speaking concerning the things which I saw while I was carried away in the spirit;"], ["ma afai ua lē tusia mea uma na ou vaai i ai,", "and if all the things which I saw are not written,"], ["o mea ua ou tusia ua moni . Ma ua faapea lava. Amene.", "the things which I have written are true. And thus it is. Amen."]]},
];
renderVerseSet(ch_14_Verses, 'ch14-verses');

var ch_15_Verses = [
  {num:1,words:[["Ma sa oo ina ua mavae ona aveeseina atu o a'u,", "And it came to pass that after I,"], ["o Nifae,", "Nephi,"], ["i le agaga,", "had been carried a way in the spirit,"], ["ma ou vaai i nei mea uma,", "and seen all these things,"], ["sa ou toe foi mai i le faleie o lo'u tamā.", "I returned to the tent of my father."]]},
  {num:2,words:[["Ma sa oo ina ou vaai atu i o'u uso, ma sa latou fefinaua'i o le tasi ma le isi,", "And it came to pass that I beheld my brethren,"], ["e uiga i mea sa tautala atu ai lo'u tamā ia te i latou.", "and they were disputing one with another concerning the things my father had spoken unto them."]]},
  {num:3,words:[["Ona e moni e tele mea tetele sa tautala atu ai o ia ia te i latou,", "For he truly spake many great things unto them,"], ["ia sa faigata ona malamalama i ai,", "which were hard to be understood,"], ["vagana ai ua ole atu le tagata i le Alii;", "save a man should inquire of the Lord;"], ["ma ona o lo latou maaa i o latou loto,", "and they being hard in their hearts,"], ["o lea na latou lē vaai atu ai i le Alii e pei ona sa tatau ai ia te i latou.", "therefore they did not look unto the Lord as they ought."]]},
  {num:4,words:[["Ma o lenei o a'u,", "And now I,"], ["o Nifae,", "Nephi,"], ["sa 'ou faanoanoa ona o le maaa o o latou loto,", "was grieved because of the hardness of their hearts,"], ["o lenei foi,", "and also,"], ["ona o mea sa ou vaaia,", "because of the things which I had seen,"], ["ma lo'u iloa o le a lē maalofia lo latou faataunuuina ona o le amioleaga tele o le fanauga a tagata.", "and knew they must unavoidably come to pass because of the great wickedness of the children of men."]]},
  {num:5,words:[["Ma sa oo ina lofituina a'u ona o o'u puapuaga,", "And it came to pass that I was overcome because of my afflictions,"], ["ona sa ou manatu ua sili atu o'u puapuaga i luga atu o tagata uma,", "for I considered that mine afflictions were great above all,"], ["ona o le faafanoga o o'u tagata,", "because of the destruction of my people,"], ["ona sa ou vaai i lo latou pa'ū.", "for I had beheld their fall."]]},
  {num:6,words:[["Ma sa oo ina ua mavae ona ou maua o le malosi sa ou fai atu i o'u uso,", "And it came to pass that after I had received strength I spake unto my brethren,"], ["ou te fia iloa mai ia te i latou le pogai o a latou finauga.", "desiring to know of them the cause of their disputations."]]},
  {num:7,words:[["Ma sa latou fai mai:", "And they said:"], ["Faauta,", "Behold,"], ["ua lē mafai ona matou malamalama i upu na fai mai ai lo tatou tamā e faatatau i lala moni o le laau olive,", "we cannot understand the words which our father hath spoken concerning the natural branches of the olive tree,"], ["ma e uiga foi i Nuuese.", "and also concerning the Gentiles."]]},
  {num:8,words:[["Ma sa ou fai atu ia te i latou:", "And I said unto them:"], ["Ua outou ole atu ea i le Alii?", "Have ye inquired of the Lord?"]]},
  {num:9,words:[["Ma sa latou fai mai ia te a'u:", "And they said unto me:"], ["Matou te lei ole atu;", "We have not;"], ["ona e lē faailoa maia e le Alii ia te i matou se mea faapena.", "for the Lord maketh no such thing known unto us."]]},
  {num:10,words:[["Faauta,", "Behold,"], ["sa ou fai atu ia te i latou:", "I said unto them:"], ["E faapefea ona outou lē tausia o poloaiga a le Alii? E faapefea ona outou fano,", "How is it that ye do not keep the commandments of the Lord? How is it that ye will perish,"], ["ona o le maaa o o outou loto?", "because of the hardness of your hearts?"]]},
  {num:11,words:[["Tou te lē manatua ea mea na fetalai mai ai le Alii?—Afai tou te lē faamaaa o outou loto,", "Do ye not remember the things which the Lord hath said?—If ye will not harden your hearts,"], ["ma ole mai ia te a'u i le faatuatua,", "and ask me in faith,"], ["ma le talitonu o le a outou maua,", "believing that ye shall receive,"], ["faatasi ma le filiga i le tausiga o a'u poloaiga,", "with diligence in keeping my commandments,"], ["e moni o le a faailoa mai nei mea ia te outou.", "surely these things shall be made known unto you."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["sa faatusaina le aiga o Isaraelu i se laau olive,", "that the house of Israel was compared unto an olive– tree,"], ["e le Agaga o le Alii lea sa i lo tatou tamā;", "by the Spirit of the Lord which was in our father;"], ["ma faauta pe lei fa'iesea ea i tatou mai le aiga o Isaraelu,", "and behold are we not broken off from the house of Israel,"], ["ma pe lē o i tatou ea o se lala o le aiga o Isaraelu?", "and are we not a branch of the house of Israel?"]]},
  {num:13,words:[["Ma o lenei,", "And now,"], ["o le uiga o le mea na fai mai ai lo tatou tamā e uiga i le suluina o lala moni e ala i le atoatoaga o Nuuese,", "the thing which our father meaneth concerning the grafting in of the natural branches through the fulness of the Gentiles,"], ["o le,", "is,"], ["i aso e gata ai,", "that in the latter days,"], ["pe a mavae ona faaitiitia a tatou fanau i le lē talitonu,", "when our seed shall have dwindled in unbelief,"], ["ioe,", "yea,"], ["mo le va o tausaga e tele,", "for the space of many years,"], ["ma tupulaga e tele pe a mavae ona faaali mai o le Mesia i le tino i le fanauga a tagata,", "and many generations after the Messiah shall be manifested in body unto the children of men,"], ["ona oo atu ai lea o le atoatoaga o le talalelei a le Mesia i Nuuese,", "then shall the fulness of the gospel of the Messiah come unto the Gentiles,"], ["ma mai Nuuese i le toe vaega o a tatou fanau—", "and from the Gentiles unto the remnant of our seed—"]]},
  {num:14,words:[["Ma i lena aso o le a iloa ai e le toe vaega o a tatou fanau ,", "And at that day shall the remnant of our seed know that they are of the house of Israel,"], ["o i latou o lo le aiga o Isaraelu,", "and that they are the covenant people of the Lord;"], ["ma o i latou o tagata o le feagaiga a le Alii;", "and then shall they know and come to the knowledge of their forefathers,"], ["ma ona latou iloa ai lea ma o mai i le malamalama e uiga i o latou muātua'ā,", "and also to the knowledge of the gospel of their Redeemer,"], ["ma i le malamalama foi o le talalelei a lo latou Togiola, lea sa tauaao atu e ia i o latou tamā;", "which was ministered unto their fathers by him;"], ["o le mea lea,", "wherefore,"], ["o le a latou malamalama ai i lo latou Togiola ma matāutu tonu lava o Lana mataupu faavae,", "they shall come to the knowledge of their Redeemer and the very points of his doctrine,"], ["ina ia mafai ona latou iloa le ala e o mai ai ia te ia ma faaolaina.", "that they may know how to come unto him and be saved."]]},
  {num:15,words:[["Ma ona oo lea,", "And then at that day will they not rejoice and give praise unto their everlasting God,"], ["i lena lava aso, pe o le a latou lē olioli ea ma avatu le viiga i lo latou Atua tumau-faavavau,", "their rock and their salvation? Yea,"], ["o lo latou papa ma lo latou olataga? Ioe,", "at that day,"], ["i lena aso, pe o le a latou lē maua ea le malosi ma le tausiga mai le vine moni? Ioe,", "will they not receive the strength and nourishment from the true vine? Yea,"], ["pe o le a latou lē o mai ea i le lotoa moni a le Atua?", "will they not come unto the true fold of God?"]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["Ioe;", "Yea;"], ["o le a toe manatua i latou i totonu o le aiga o Isaraelu;", "they shall be remembered again among the house of Israel;"], ["o le a sulu i latou i totonu,", "they shall be grafted in,"], ["ona o i latou o se lala moni o le laau olive,", "being a natural branch of the olive – tree,"], ["i totonu o le laau olive moni.", "into the true olive–tree."]]},
  {num:17,words:[["Ma o le uiga lenei o le tala a lo tatou tamā;", "And this is what our father meaneth;"], ["ma o le uiga o lana tala o le a lē oo mai seia mavae ona faataapeapeina o i latou e Nuuese;", "and he meaneth that it will not come to pass until after they are scattered by the Gentiles;"], ["ma o le uiga o lana tala o le a oo mai e ala mai i Nuuese,", "and he meaneth that it shall come by way of the Gentiles,"], ["ina ia mafai ona faaalia e le Alii lona mana i Nuuese,", "that the Lord may show his power unto the Gentiles,"], ["o le pogai tonu ona o le a teena o ia e tagata Iutaia,", "for the very cause that he shall be rejected of the Jews,"], ["po o le aiga o Isaraelu.", "or of the house of Israel."]]},
  {num:18,words:[["O le mea lea,", "Wherefore,"], ["e lē nao a tatou fanau sa tautala i ai lo tatou tamā,", "our father hath not spoken of our seed alone,"], ["ae o le aiga uma foi o Isaraelu,", "but also of all the house of Israel,"], ["e faasino i le feagaiga lea o le a faataunuuina i aso e gata ai;", "pointing to the covenant which should be fulfilled in the latter days;"], ["o le feagaiga lea na faia e le Alii i lo tatou tamā o Aperaamo,", "which covenant the Lord made to our father Abraham,"], ["fai mai:", "saying:"], ["O lau fanau o le a manuia ai aiga uma o le lalolagi.", "In thy seed shall all the kindreds of the earth be blessed."]]},
  {num:19,words:[["Ma sa oo ina tele ona ou tautala atu o a'u,", "And it came to pass that I,"], ["o Nifae ia te i latou e uiga i nei mea;", "Nephi,"], ["ioe,", "spake much unto them concerning these things; yea,"], ["sa ou tautala atu ia te i latou e uiga i le toefuataiga o tagata Iutaia i aso e gata ai.", "I spake unto them concerning the restoration of the Jews in the latter days."]]},
  {num:20,words:[["Ma sa ou faamatala atu ia te i latou upu a Isaia ,", "And I did rehearse unto them the words of Isaiah,"], ["o lē sa tautala mai e uiga i le toefuataiga o tagata Iutaia,", "who spake concerning the restoration of the Jews,"], ["po o le aiga o Isaraelu;", "or of the house of Israel;"], ["ma a uma ona toefuatai o i latou o le a lē toe feleiloana'i i latou,", "and after they were restored they should no more be confounded,"], ["pe toe faataapeapeina i latou. Ma sa oo ina tele upu sa ou tautala atu ai i o'u uso,", "neither should they be scattered again. And it came to pass that I did speak many words unto my brethren,"], ["ma sa faamalilieina i latou ma latou faamaualalaloina i latou lava i luma o le Alii.", "that they were pacified and did humble themselves before the Lord."]]},
  {num:21,words:[["Ma sa oo ina latou toe fai mai ia te a'u,", "And it came to pass that they did speak unto me again,"], ["fai mai:", "saying:"], ["O le a le uiga o lenei mea sa vaai i ai lo tatou tamā i se miti? O le a le uiga o le laau sa vaai i ai o ia?", "What meaneth this thing which our father saw in a dream? What meaneth the tree which he saw?"]]},
  {num:22,words:[["Ma sa ou fai atu ia te i latou:", "And I said unto them:"], ["O se faatusa lea o le laau o le ola.", "It was a representation of the tree of life."]]},
  {num:23,words:[["Ma sa latou fai mai ia te a'u:", "And they said unto me:"], ["O le a le uiga o le ai u'amea lea sa vaai i ai lo tatou tamā,", "What meaneth the rod of iron which our father saw,"], ["lea sa tau atu i le laau?", "that led to the tree?"]]},
  {num:24,words:[["Ma sa ou fai atu ia te i latou o le afioga lea a le Atua;", "And I said unto them that it was the word of God,"], ["ma ai se e faalogo i le afioga a le Atua,", "and whose would hearken unto the word of God,"], ["ma pipiimau i ai,", "and would hold fast unto it,"], ["e lē fano lava i latou;", "they would never perish;"], ["pe mafai foi e faaosoosoga ma ufanafana mu a le fili ona faatoilaloina i latou i le faatauasoina,", "neither could the temptations and the fiery darts of the adversary overpower them unto blindness,"], ["e taitai ese atu ai i latou i le faafanoga.", "to lead them away to destruction."]]},
  {num:25,words:[["O le mea lea,", "Wherefore,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["sa ou apoapoai atu ia te i latou ia ua'i atu i le afioga a le Alii;", "did exhort them to give heed unto the word of the Lord;"], ["ioe,", "yea,"], ["sa ou apoapoai atu ia te i latou ma le malosi uma o lo'u agaga,", "I did exhort them with all the energies of my soul,"], ["ma le mafaufau uma sa ia te a'u,", "and with all the faculty which I possessed,"], ["ia latou ua'i atu i le afioga a le Atua ma manatua ia tausi pea i ana poloaiga i mea uma.", "that they would give heed to the word of God and remember to keep his commandments always in all things."]]},
  {num:26,words:[["Ma sa latou fai mai ia te a'u:", "And they said unto me:"], ["O le a le uiga o le vaitafe sa vaai i ai lo tatou tamā?", "What meaneth the river of water which our father saw?"]]},
  {num:27,words:[["Ma sa ou fai atu ia te i latou o le vai lea sa vaai i ai lo'u tamā o le eleelea lea;", "And I said unto them that the water which my father saw was filthiness;"], ["ma sa matua tele lava le tofatumoanaina o lona mafaufau i isi mea sa lē iloa atu ai e ia le eleelea o le vai.", "and so much was his mind swallowed up in other things that he beheld not the filthiness of the water."]]},
  {num:28,words:[["Ma sa ou fai atu ia te i latou o se to leaga mata'utia lea,", "And I said unto them that it was an awful gulf,"], ["ua vavae ese ai e amioleaga mai le laau o le ola,", "which separated the wicked from the tree of life,"], ["ma mai le au paia foi a le Atua.", "and also from the saints of God."]]},
  {num:29,words:[["Ma sa ou fai atu ia te i latou o se faatusa lea o lena seoli leaga mata'utia,", "And I said unto them that it was a representation of that awful hell,"], ["lea sa fetalai mai ai le agelu ia te a'u ua saunia mo e amioleaga.", "which the angel said unto me was prepared for the wicked."]]},
  {num:30,words:[["Ma sa ou fai atu ia te i latou sa vaai foi lo matou tamā ua vavae ese foi e le faamasinotonu o le Atua e amioleaga mai e amiotonu;", "And I said unto them that our father also saw that the justice of God did also divide the wicked from the righteous;"], ["ma o lona susulu ua pei o le susulu o se afi mumū,", "and the brightness thereof was like unto the brightness of a flaming fire,"], ["lea e alu a'e i le Atua e faavavau faavavau lava,", "which ascendeth up unto God forever and ever,"], ["ma ua leai se iuga.", "and hath no end."]]},
  {num:31,words:[["Ma sa latou fai mai ia te a'u:", "And they said unto me:"], ["O le uiga ea o lenei mea o le mafatia lea o le tino i aso o le vaavaaiga ,", "Doth this thing mean the torment of the body in the days of probation,"], ["po o lona uiga o le tulaga mulimuli lea o le agaga pe a mavae le oti o le tino faaletino,", "or doth it mean the final state of the soul after the death of the temporal body,"], ["pe o tautala e uiga i mea faaletino?", "or doth it speak of the things which are temporal?"]]},
  {num:32,words:[["Ma sa oo ina ou fai atu ia te i latou o se faatusa lea o mea faaletino atoa ma mea faaleagaga;", "And it came to pass that I said unto them that it was a representation of things both temporal and spiritual;"], ["ona e oo mai le aso e faamasino ai i latou ia latou galuega ,", "for the day should come that they must be judged of their works,"], ["ioe,", "yea,"], ["galuega lava ia sa faia e le tino faaletino i o latou aso o le vaavaaiga.", "even the works which were done by the temporal body in their days of probation."]]},
  {num:33,words:[["O le mea lea,", "Wherefore,"], ["afai latou te oti a'o latou i ai i lo latou amioleaga o le a tutuli ese foi i latou,", "if they should die in their wickedness they must be cast off also,"], ["e faatatau i mea faaleagaga,", "as to the things which are spiritual,"], ["ia ua faatatau i le amiotonu;", "which are pertaining to righteousness;"], ["o le mea lea,", "wherefore,"], ["e ao ai lava ina aumai o i latou e tutu i luma o le Atua,", "they must be brought to stand before God,"], ["ia faamasinoina mo a latou galuega ;", "to be judged of their works;"], ["ma afai sa eleelea a latou galuega ua tatau foi ona latou eleelea ;", "and if their works have been filthiness they must needs be filthy;"], ["ma afai ua latou eleelea e tatau ona lē mafai ona latou nonofo i le malo o le Atua;", "and if they be filthy it must needs be that they cannot dwell in the kingdom of God;"], ["afai e mafai,", "if so,"], ["po ua tatau foi ona eleelea le malo o le Atua.", "the kingdom of God must be filthy also."]]},
  {num:34,words:[["Ae faauta,", "But behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua le eleelea le malo o le Atua,", "the kingdom of God is not filthy,"], ["ma e le mafai e se mea eleelea ona ulu atu i le malo o le Atua;", "and there cannot any unclean thing enter into the kingdom of God;"], ["o le mea lea e tatau ai ona i ai o se nofoaga eleelea ua saunia mo mea ua eleelea.", "wherefore there must needs be a place of filthiness prepared for that which is filthy."]]},
  {num:35,words:[["Ma ua i ai se nofoaga ua saunia,", "And there is a place prepared,"], ["ioe,", "yea,"], ["o le seoli leaga mata'utia lava lena sa ou tautala atu ai,", "even that awful hell of which I have spoken,"], ["ma o le tiapolo o ia lea ua na sauniaina;", "and the devil is the preparator of it;"], ["o le mea lea o le tulaga mulimuli o agaga o tagata o le nonofo lea i le malo o le Atua,", "wherefore the final state of the souls of men is to dwell in the kingdom of God,"], ["po o le tutuli ese i fafo ona o lena faamasinotonu sa ou tautala atu ai.", "or to be cast out because of that justice of which I have spoken."]]},
  {num:36,words:[["O le mea lea,", "Wherefore,"], ["e tutuli ese e amioleaga mai e amiotonu,", "the wicked are rejected from the righteous,"], ["ma mai le laau foi lena o le ola,", "and also from that tree of life,"], ["lea o ona fua ua silisili ona pele ma silisili ona manaomia i lo o isi fua uma lava;", "whose fruit is most precious and most desirable above all other fruits;"], ["ioe,", "yea,"], ["ma o le aupito silisili lea o meaalofa uma a le Atua. Ma sa faapea ona ou tautala atu i o'u uso. Amene.", "and it is the greatest of all the gifts of God. And thus I spake unto my brethren. Amen."]]},
];
renderVerseSet(ch_15_Verses, 'ch15-verses');

var ch_16_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona faaiu e a'u,", "And now it came to pass that after I,"], ["o Nifae,", "Nephi,"], ["le tautala atu i o'u uso,", "had made an end of speaking to my brethren,"], ["faauta sa latou fai mai ia te a'u:", "behold they said unto me:"], ["Ua e ta'u mai ia te i matou ni mea faigata,", "Thou hast declared unto us hard things,"], ["ua sili atu nai lo mea e mafai ona matou gafatia.", "more than we are able to bear."]]},
  {num:2,words:[["Ma sa oo ina ou fai atu ia te i latou,", "And it came to pass that I said unto them that I knew that I had spoken hard things against the wicked,"], ["ua ou iloa ua ou tautala atu i mea faigata e faasaga i e amioleaga,", "according to the truth;"], ["e tusa ma le upumoni;", "and the righteous have I justified,"], ["ma ua ou taumamāina e amiotonu, ma molimau atu o le a sii a'e i latou i luga i le aso gataaga;", "and testified that they should be lifted up at the last day;"], ["o le mea lea,", "wherefore,"], ["e ave e tagata ua sala le upumoni o se mea faigata,", "the guilty taketh the truth to be hard,"], ["ona e tuia ai i latou i le totonugalemu lava.", "for it cutteth them to the very center."]]},
  {num:3,words:[["Ma o lenei o'u uso e,", "And now my brethren,"], ["a na fai ua outou amiotonu ma fia faalogologo i le upumoni,", "if ye were righteous and were willing to hearken to the truth,"], ["ma ua'i atu i ai,", "and give heed unto it,"], ["ina ia mafai ona outou savavali tonu i luma o le Atua,", "that ye might walk uprightly before God,"], ["po ua outou lē muimui ona o le upumoni,", "then ye would not murmur because of the truth,"], ["ma fai mai:", "and say:"], ["Ua e tautala mai mea faigata e faasaga ia te i matou.", "Thou speakest hard things against us."]]},
  {num:4,words:[["Ma sa oo ina apoapoai atu a'u o Nifae,", "And it came to pass that I,"], ["sa 'ou i o'u uso,", "Nephi,"], ["ma le filiga atoa,", "did exhort my brethren, with all diligence,"], ["ia tausi i poloaiga a le Alii.", "to keep the commandments of the Lord."]]},
  {num:5,words:[["Ma sa oo ina latou faamaualalaloina i latou lava i luma o le Alii;", "And it came to pass that they did humble themselves before the Lord;"], ["sa oo ina ou maua ai le olioli ma faamoemoega tetele mo i latou,", "insomuch that I had joy and great hopes of them,"], ["o le a latou savavali i ala o le amiotonu.", "that they would walk in the paths of righteousness."]]},
  {num:6,words:[["O lenei,", "Now,"], ["o nei mea uma sa tautalaina ma faia a'o nofo lo'u tamā i se faleie i le vanu na ia faaigoaina o Lemuelu.", "all these things were said and done as my father dwelt in a tent in the valley which he called Lemuel."]]},
  {num:7,words:[["Ma sa oo ina ave e a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["se tasi o afafine o Isamaeli e fai ma a'u ava ;", "took one of the daughters of Ishmael to wife;"], ["o lenei foi,", "and also,"], ["sa ave e o'u uso ni isi o afafine o Isamaeli e faiava i ai;", "my brethren took of the daughters of Ishmael to wife;"], ["ma sa ave foi e Sorama le afafine ulumatua o Isamaeli e faiava i ai.", "and also Zoram took the eldest daughter of Ishmael to wife."]]},
  {num:8,words:[["Ma sa faapea ona faataunuuina e lo'u tamā poloaiga uma a le Alii sa tuu mai ia te ia.", "And thus my father had fulfilled all the commandments of the Lord which had been given unto him."], ["Ma o a'u foi,", "And also,"], ["o Nifae,", "I, Nephi,"], ["sa faamanuiaina tele lava e le Alii.", "had been blessed of the Lord exceedingly."]]},
  {num:9,words:[["Ma sa oo ina fetalai mai le siufofoga o le Alii i lo'u tamā i le po,", "And it came to pass that the voice of the Lord spake unto my father by night,"], ["ma poloaiina o ia e tatau ia te ia ona alu lana malaga i le vao i le aso na sosoo ai.", "and commanded him that on the morrow he should take his journey into the wilderness."]]},
  {num:10,words:[["Ma sa oo ina ua tulai a'e lou tamā i le taeao, ma alu atu i le faitotoa o le faleie,", "And it came to pass that as my father arose in the morning,"], ["sa vaaia e ia i luga o le eleele,", "and went forth to the tent door,"], ["ma lona ofo tele,", "to his great astonishment he beheld upon the ground a round ball of curious workmanship;"], ["se polo lapotopoto sa uiga ese lava lona gaosiga; ma sa gaosia lea polo i le apamemea sili ona lelei.", "and it was of fine brass."], ["Ma i totonu o le polo sa i ai ni vae se lua;", "And within the ball were two spindles;"], ["ma o le tasi vae sa faasino mai ai le ala e tatau ona matou o ai i le vao.", "and the one pointed the way whither we should go into the wilderness."]]},
  {num:11,words:[["Ma sa oo ina matou faaputuputu faatasi soo se mea sa tatau ona matou ave i le vao,", "And it came to pass that we did gather together whatsoever things we should carry into the wilderness,"], ["ma le vaega uma na totoe o a matou tapenapenaga na foai mai e le Alii ia te i matou;", "and all the remainder of our provisions which the Lord had given unto us;"], ["ma sa matou ave fatu o ituaiga eseese uma ina ia mafai ona matou avea i le vao.", "and we did take seed of every kind that we might carry into the wilderness."]]},
  {num:12,words:[["Ma sa oo ina matou ave o matou faleie ma malaga atu i le vao,", "And it came to pass that we did take our tents and depart into the wilderness,"], ["e sopo atu i le vaitafe o Lamana.", "across the river Laman."]]},
  {num:13,words:[["Ma sa oo ina matou malaga mo le va o aso e fa,", "And it came to pass that we traveled for the space of four days,"], ["toeitiiti ane lava agai atu i le itu i saute-sautesasa'e,", "nearly a south– southeast direction,"], ["ma sa matou toe faatutu o matou faleie;", "and we did pitch our tents again;"], ["ma sa matou ta'ua le igoa o le nofoaga o Sasera.", "and we did call the name of the place Shazer."]]},
  {num:14,words:[["Ma sa oo ina matou ave a matou aufana ma a matou ufanafana,", "And it came to pass that we did take our bows and our arrows,"], ["ma o atu i le vao e fasi mai ni meaai mo o matou aiga;", "and go forth into the wilderness to slay food for our families;"], ["ma ina ua uma ona matou fasi o meaai mo o matou aiga sa matou toe foi mai i o matou aiga i le vao,", "and after we had  slain food for our families we did return again to our families in the wilderness,"], ["i le nofoaga o Sasera. Ma sa matou toe o atu i le vao,", "to the place of Shazer. And we did go forth again in the wilderness,"], ["e mulimuli agai i le itu lava e tasi,", "following the same direction,"], ["ma tausisi i vaega aupito sili ona lafulemu o le vao,", "keeping in the most fertile parts of the wilderness,"], ["sa i tuaoi lata ane i le Sami Ulaula.", "which were in the borders near the Red Sea."]]},
  {num:15,words:[["Ma sa oo ina matou malaga mo le va o aso e tele,", "And it came to pass that we did travel for the space of many days,"], ["ma fasi meaai i le ala,", "slaying food by the way,"], ["ia matou aufana ma a matou ufanafana ma a matou maa ma a matou maata.", "with our bows and our arrows and our stones and our slings."]]},
  {num:16,words:[["Ma sa matou mulimuli i faasinoga a le polo,", "And we did follow the directions of the ball,"], ["ia sa taitaia ai i matou i vaega aupito sili ona lafulemu o le vao.", "which led us in the more fertile parts of the wilderness."]]},
  {num:17,words:[["Ma ina ua mavae ona matou malaga mo le va o aso e tele,", "And after we had traveled for the space of many days,"], ["sa matou faatutu o matou faleie mo se vaitaimi,", "we did pitch our tents for the space of a time,"], ["ina ia mafai ona matou toe malolo ma maua mai ni meaai mo o matou aiga.", "that we might again rest ourselves and obtain food for our families."]]},
  {num:18,words:[["Ma sa oo a'o alu atu a'u,", "And it came to pass that as I,"], ["o Nifae,", "Nephi,"], ["e fasi meaai,", "went forth to slay food,"], ["faauta,", "behold,"], ["sa gau la'u aufana,", "I did break my bow,"], ["lea sa gaosia i le sila e sili ona lelei;", "which was made of fine steel;"], ["ma ina ua mavae ona gau o la'u aufana,", "and after I did break my bow,"], ["faauta,", "behold,"], ["sa feitai o'u uso ia te a'u ona ua lē aoga la'u aufana,", "my brethren were angry with me because of the loss of my bow,"], ["ona sa matou lē maua se meaai.", "for we did obtain no food."]]},
  {num:19,words:[["Ma sa oo ina matou foi mai i o matou aiga e aunoa ma ni meaai,", "And it came to pass that we did return without food to our families,"], ["ma ona sa vaivai tele,", "and being much fatigued,"], ["ona o la latou malaga,", "because of their journeying,"], ["sa mafatia tele i latou i le fia aai.", "they did suffer much for the want of food."]]},
  {num:20,words:[["Ma sa oo ina amata ona muimui tele Lamana ma Lemuelu ma atalii o Isamaeli,", "And it came to pass that Laman and Lemuel and the sons of Ishmael did begin to murmur exceedingly,"], ["ona o o latou mafatiaga ma puapuaga i le vao;", "because of their sufferings and afflictions in the wilderness;"], ["ma sa amata foi ona muimui o lo'u tamā e faasaga i le Alii lona Atua;", "and also my father began to murmur against the Lord his God;"], ["ioe,", "yea,"], ["ma sa faanoanoa tele i latou uma,", "and they were all exceedingly sorrowful,"], ["sa oo lava ina latou muimui e faasaga i le Alii.", "even that they did murmur against the Lord."]]},
  {num:21,words:[["O lenei sa oo ina o puapuagatia a'u,", "Now it came to pass that I,"], ["o Nifae,", "Nephi,"], ["faatasi ma o'u uso ona ua lē aoga la'u aufana,", "having been afflicted with my brethren because of the loss of my bow,"], ["ma sa vaivai foi le meme'i o a latou aufana,", "and their bows having lost their springs,"], ["sa amata ona matua faigata tele,", "it began to be exceedingly difficult,"], ["ioe,", "yea,"], ["sa oo ina lē mafai ona matou maua o se meaai.", "inso–  much that we could obtain no food."]]},
  {num:22,words:[["Ma sa oo ina,", "And it came to pass that I,"], ["sa tele ona tautala atu a'u o Nifae,", "Nephi,"], ["i o'u uso,", "did speak much unto my brethren,"], ["ona ua latou toe faamaaa o latou loto,", "because they had hardened their hearts again,"], ["na oo lava i le tomumumu e faasaga i le Alii lo latou Atua.", "even unto complaining against the Lord their God."]]},
  {num:23,words:[["Ma sa oo ina faia e a'u o Nifae mai se laau se aufana,", "And it came to pass that I,"], ["ma mai i se laau sa'o,", "Nephi, did make out of wood a bow,"], ["se ufanafana;", "and out of a straight stick,"], ["o le mea lea,", "an arrow;"], ["sa ou faaauupegaina ai a'u lava i se aufana ma se ufanafana,", "wherefore, I did arm myself with a bow and an arrow,"], ["faatasi ma se maata ma ni maa.", "with a sling and with stones."], ["Ma sa ou fai atu i lo'u tamā :", "And I said unto my father:"], ["O fea ou te alu i ai e maua mai ai ni meaai?", "Whither shall I go to obtain food?"]]},
  {num:24,words:[["Ma sa oo ina ole atu o ia i le Alii,", "And it came to pass that he did inquire of the Lord,"], ["ona ua latou faamaualalaloina i latou lava ona o a'u upu;", "for they had humbled themselves because of my words;"], ["ona e tele mea sa ou fai atu ai ia te i latou i le malosi o lo'u agaga.", "for I did say many things unto them in the energy of my soul."]]},
  {num:25,words:[["Ma sa oo ina tulei mai le siufofoga o le Alii i lo'u tamā;", "And it came to pass that the voice of the Lord came unto my father;"], ["ma sa aoaiina moni lava o ia ona o lona muimui e faasaga i le Alii,", "and he was truly chastened because of his murmuring against the Lord,"], ["sa oo ina ave ifo o ia i lalo i le loloto o le faanoanoa.", "insomuch that he was brought down into the depths of sorrow."]]},
  {num:26,words:[["Ma sa oo ina fetalai mai le siufofoga o le Alii ia te ia:", "And it came to pass that the voice of the Lord said unto him:"], ["Inā vaai ia i le polo,", "Look upon the ball,"], ["ma vaai i mea ua tusia ai.", "and behold the things which are written."]]},
  {num:27,words:[["Ma sa oo ina ua vaai atu lo'u tamā i mea na tusia i le polo,", "And it came to pass that when my father beheld the things which were written upon the ball,"], ["sa fefe o ia ma gatete tele lava,", "he did fear and tremble exceedingly,"], ["ma sa faapea foi o'u uso ma atalii o Isamaeli ma a matou ava.", "and also my brethren and the sons of Ishmael and our wives."]]},
  {num:28,words:[["Ma sa oo ina vaai atu a'u o Nifae,", "And it came to pass that I,"], ["sa 'ou vaai i vae sa i totonu o le polo,", "Nephi, beheld the pointers which were in the ball,"], ["ua ola i laua e tusa ma le faatuatua ma le filiga ma le gaua'i sa matou tuu atu i ai.", "that they did work according to the faith and diligence and heed which we did give unto them."]]},
  {num:29,words:[["Ma sa tusia foi i o laua luga se tusitusiga fou,", "And there was also written upon them a new writing,"], ["lea na manino i le faitau,", "which was plain to be read,"], ["lea na tuu mai ai ia te i matou le malamalamaaga e uiga i ala o le Alii;", "which did give us understanding concerning the ways of the Lord;"], ["ma sa tusia ma suia ia tusitusiga mai lea taimi i lea taimi,", "and it was written and changed from time to time,"], ["e tusa ma le faatuatua ma le filiga sa matou tuu atu i ai. Ma ua faapea ona tatou vaai ai e mafai e le Alii ona faataunuu mea tetele i ala faatauvaa.", "according to the faith and diligence which we gave unto it. And thus we see that by small means the Lord can bring about great things."]]},
  {num:30,words:[["Ma sa oo ina alu atu a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["i luga i le tumutumu o le mauga,", "did go forth up into the top of the mountain,"], ["e tusa ma faatonuga sa tuuina mai i le polo.", "according to the directions which were given upon the ball."]]},
  {num:31,words:[["Ma sa oo ina ou fasi manu 'aivao,", "And it came to pass that I did slay wild beasts,"], ["sa oo ina ou maua ai meaai mo o matou aiga.", "insomuch that I did obtain food for our families."]]},
  {num:32,words:[["Ma sa oo ina ou foi mai i o matou faleie,", "And it came to pass that I did return to our tents,"], ["ma faafuata mai manu na ou fasia;", "bearing the beasts which I had slain;"], ["ma o lenei ina ua latou vaai mai ua ou maua ni meaai,", "and now when they beheld that I had obtained food,"], ["sa latou olioli lava! Ma sa oo ina latou faamaualalalo i latou lava i luma o le Alii,", "how great was their joy! And it came to pass that they did humble themselves before the Lord,"], ["ma avatu le faafetai ia te ia.", "and did give thanks unto him."]]},
  {num:33,words:[["Ma sa oo ina matou toe ave la matou malaga,", "And it came to pass that we did again take our journey,"], ["ma alu toeitiiti ane i le ala e tasi e pei o le amataga;", "traveling nearly the same course as in the beginning;"], ["ma ina ua mavae ona matou malaga mo le va o aso e tele sa matou toe faatutu o matou faleie,", "and after we had traveled for the space of many days we did pitch our tents again,"], ["ina ia mafai ona matou malolo mo le va o se taimi.", "that we might tarry for the space of a time."]]},
  {num:34,words:[["Ma sa oo ina maliu Isamaeli ,", "And it came to pass that Ishmael died,"], ["ma sa lagomau o ia i le nofoaga sa ta'ua o Naoma.", "and was buried in the place which was called Nahom."]]},
  {num:35,words:[["Ma sa oo ina faanoanoa tele lava afafine o Isamaeli,", "And it came to pass that the daughters of Ishmael did mourn exceedingly,"], ["ona o le maliu o lo latou tamā,", "because of the loss of their father,"], ["ma ona o o latou puapuaga i le vao;", "and because of their afflictions in the wilderness;"], ["ma sa latou muimui faasaga i lo'u tamā,", "and they did murmur against my father,"], ["ona ua ia aumai i latou i fafo o le laueleele o Ierusalema,", "because he had brought them out of the land of Jerusalem,"], ["fai mai:", "saying:"], ["Ua oti lo matou tamā;", "Our father is dead;"], ["ioe,", "yea,"], ["ma ua tele ona matou feoa'i solo i le vao,", "and we have wandered much in the wilderness,"], ["ma ua matou mafatia i le tele o puapuaga,", "and we have suffered much affliction,"], ["le fia aai,", "hunger,"], ["le fia inu,", "thirst,"], ["ma le vaivai;", "and fatigue;"], ["ma a mavae atu nei mafatiaga uma o le a matou fano lava i le vao i le fia aai.", "and after all these sufferings we must perish in the wilderness with hunger."]]},
  {num:36,words:[["Ma sa faapea ona latou muimui faasaga i lo'u tamā,", "And thus they did murmur against my father,"], ["ma faasaga mai foi ia te a'u;", "and also against me;"], ["ma sa latou mananao e toe foi atu i Ierusalema.", "and they were desirous to return again to Jerusalem."]]},
  {num:37,words:[["Ma sa fai atu Lamana ia Lemuelu ma atalii foi o Isamaeli:", "And Laman said unto Lemuel and also unto the sons of Ishmael:"], ["Faauta,", "Behold,"], ["ia tatou fasioti lo matou tamā,", "let us slay our father,"], ["ma lo matou uso foi o Nifae,", "and also our brother Nephi,"], ["o lē ua ia ave i ona luga e fai ma o tatou pule ma o tatou aoao,", "who has taken it upon him to be our ruler and our teacher,"], ["o e o ona uso matutua.", "who are his elder brethren."]]},
  {num:38,words:[["O lenei,", "Now,"], ["ua fai mai o ia na fetalai mai le Alii ia te ia,", "he says that the Lord has talked with him,"], ["ma na auauna mai foi agelu ia te ia. Ae faauta,", "and also that angels have ministered unto him. But behold,"], ["ua tatou iloa ua pepelo o ia ia te i tatou;", "we know that he lies unto us;"], ["ma ua ia ta'u mai nei mea ia te i tatou,", "and he tells us these things,"], ["ma ua ia faia le tele o mea i lona poto faitogafiti,", "and he worketh many things by his cunning arts,"], ["ina ia mafai ona ia faasese o tatou mata,", "that he may deceive our eyes,"], ["i lona manatu,", "thinking,"], ["atonu,", "perhaps,"], ["ia mafai ai ona ia taitai ese atu i tatou i se vao uiga ese;", "that he may lead us away into some strange wilderness;"], ["ma a uma ona ia taitai ese atu o i tatou,", "and after he has led us away,"], ["ua manatu o ia e fai o ia ma tupu ma pule ia i tatou,", "he has thought to make himself a king and a ruler over us,"], ["ina ia mafai ona ia faia ia te i tatou e tusa ma lona loto ma lona manao. Ma sa faapea le ala na faaoso a'e ai e lo'u uso o Lamana o latou loto i le ita.", "that he may do with us according to his will and pleasure. And after this manner did my brother Laman stir up their hearts to anger."]]},
  {num:39,words:[["Ma sa oo ina faatasi mai le Alii ia te i matou,", "And it came to pass that the Lord was with us,"], ["ioe,", "yea,"], ["sa oo ina oo mai lava le siufofoga o le Alii ma fetalai mai upu e tele ia te i latou,", "even the voice of the Lord came and did speak many words unto them,"], ["ma sa aoaiina malosi lava i latou;", "and did chasten them exceedingly;"], ["ma ina ua uma ona aoaiina o i latou e le siufofoga o le Alii, sa latou liliu ese lo latou ita,", "and after they were chastened by the voice of the Lord they did turn away their anger,"], ["ma salamo ia latou agasala,", "and did repent of their sins,"], ["sa oo ina toe faamanuiaina i matou e le Alii i meaai,", "insomuch that the Lord did bless us again with food,"], ["na matou lē fano ai.", "that we did not perish."]]},
];
renderVerseSet(ch_16_Verses, 'ch16-verses');

var ch_17_Verses = [
  {num:1,words:[["Ma sa oo ina matou toe ave la matou malaga i le vao;", "And it came to pass that we did again take our journey in the wilderness;"], ["ma sa matou malaga toeitiiti ane agai i le itu i sasae mai le taimi lena. Ma sa matou malaga ma asa atu i puapuaga e tele i le vao;", "and we did travel nearly eastward from that time forth. And we did travel and wade through much affliction in the wilderness;"], ["ma sa fanauina e o matou fafine fanau i le vao.", "and our women did bear children in the wilderness."]]},
  {num:2,words:[["Ma sa matua tele lava faamanuiaga a le Alii i luga o i matou,", "And so great were the blessings of the Lord upon us,"], ["e ui ina sa matou ola i aano mata o manu i le vao,", "that while we did live upon raw meat in the wilderness,"], ["sa lava le suasusu o o matou fafine mo a latou fanau,", "our women did give plenty of suck for their children,"], ["ma sa malolosi,", "and were strong,"], ["ioe,", "yea,"], ["e pei lava o tane;", "even like unto the men;"], ["ma sa amata ona latou tauave a latou malaga e aunoa ma le muimui.", "and they began to bear their journeyings without murmurings."]]},
  {num:3,words:[["Ma ua faapea ona tatou vaai ai e faataunuuina lava poloaiga a le Atua.", "And thus we see that the command– ments of God must be fulfilled."], ["Ma afai e tausi e le fanauga a tagata poloaiga a le Atua,", "And if it so be that the children of men keep the command– ments of God he doth nourish them,"], ["e tausi o ia ia te i latou,", "and strengthen them,"], ["ma faamalolosi i latou, ma fai ala e mafai ai ona latou faataunuuina o le mea ua ia poloaiina ai i latou;", "and provide means whereby they can accomplish the thing which he has commanded them;"], ["o le mea lea,", "wherefore,"], ["sa faia ai e ia ala mo i matou a'o matou aumau i le vao.", "he did provide means for us while we did sojourn in the wilderness."]]},
  {num:4,words:[["Ma sa matou aumau mo le va o tausaga e tele,", "And we did sojourn for the space of many years,"], ["ioe,", "yea,"], ["i le valu lava o tausaga i le vao.", "even eight years in the wilderness."]]},
  {num:5,words:[["Ma sa matou oo mai i le laueleele sa matou ta'ua o Nuumau,", "And we did come to the land which we called Bountiful,"], ["ona o le tele o ona fualaau 'aina ma le meli vao foi;", "because of its much fruit and also wild honey;"], ["ma o ia mea uma sa saunia e le Alii ina ia matou lē fano. Ma sa matou vaai i le sami,", "and all these things were prepared of the Lord that we might not perish. And we beheld the sea,"], ["lea sa matou ta'ua o Ireanetuma,", "which we called Irreantum,"], ["lea o lona uiga,", "which,"], ["pe a faamatalaina,", "being interpreted,"], ["o vai e tele.", "is many waters."]]},
  {num:6,words:[["Ma sa oo ina matou faatutu o matou faleie i tafatafa o le matafaga;", "And it came to pass that we did pitch our tents by the seashore;"], ["ma e ui lava ina sa matou mafatia i puapuaga e tele ma faigata e tele,", "and notwithstanding we had suffered many afflictions and much difficulty,"], ["ioe,", "yea,"], ["sa matua tele lava e le mafai ona matou tusia uma,", "even so much that we cannot write them all,"], ["sa matou matua fiafia lava ina ua matou oo mai i le matafaga;", "we were exceedingly rejoiced when we came to the sea– shore;"], ["ma sa matou ta'ua le nofoaga o Nuumau,", "and we called the place Bountiful,"], ["ona o le tele o ona fualaau 'aina.", "because of its much fruit."]]},
  {num:7,words:[["Ma sa oo,", "And it came to pass that after I,"], ["ina ua mavae ona i ai o a'u, o Nifae,", "Nephi,"], ["i le laueleele o Nuumau,", "had been in the land of Bountiful for the space of many days,"], ["mo le va o aso e tele,", "the voice of the Lord came unto me,"], ["sa oo mai le siufofoga o le Alii ia te a'u,", "saying:"], ["ua fetalai mai: Tulai ia,", "Arise,"], ["ma ia e alu a'e i le mauga.", "and get thee into the mountain."], ["Ma sa oo ina ou tulai ma alu a'e i luga i le mauga,", "And it came to pass that I arose and went up into the mountain,"], ["ma tagi atu i le Alii.", "and cried unto the Lord."]]},
  {num:8,words:[["Ma sa oo ina fetalai mai le Alii ia te a'u,", "And it came to pass that the Lord spake unto me,"], ["fai mai:", "saying:"], ["Ia e fausia se vaa,", "Thou shalt construct a ship,"], ["e tusa ma le ala o le a ou faaali atu ia te oe,", "after the manner which I shall show thee,"], ["ina ia mafai ona Ou ave o ou tagata i tala atu o nei vai.", "that I may carry thy people across these waters."]]},
  {num:9,words:[["Ma sa ou fai atu:", "And I said:"], ["Le Alii e,", "Lord,"], ["o fea ou te alu i ai e mafai ona ou maua mai ai le 'oa e faaliusuavai,", "whither shall I go that I may find ore to molten,"], ["ina ia mafai ona ou faia mai ai ni meafaigaluega e fau ai le vaa e tusa ai ma le ala ua e faaali mai ia te a'u?", "that I may make tools to construct the ship after the manner which thou hast shown unto me?"]]},
  {num:10,words:[["Ma sa oo ina ta'u mai e le Alii ia te a'u le mea ou te alu i ai e maua ai le 'oa,", "And it came to pass that the Lord told me whither I should go to find ore,"], ["ina ia mafai ona ou faia ai o ni meafaigaluega.", "that I might make tools."]]},
  {num:11,words:[["Ma sa oo ina fai e a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["se tapili i pa'u o manu,", "did make a bellows wherewith to blow the fire,"], ["e tapili ai le afi;", "of the skins of beasts;"], ["ma ina ua uma ona ou faia o se tapili,", "and after I had made a bellows,"], ["ina ia ou maua se mea e tapili ai le afi,", "that I might have wherewith to blow the fire,"], ["sa ou faafeto'aia ni maa se lua ina ia mafai ona ou faia ai se afi.", "I did smite two stones together that I might make fire."]]},
  {num:12,words:[["Ona sa lei tuu maia e le Alii e oo mai i le taimi lea,", "For the Lord had not hitherto suffered that we should make much fire,"], ["ia matou faia ni afi e tele,", "as we journeyed in the wilderness;"], ["a'o matou malaga i le vao; ona sa fetalai mai o ia:", "for he said:"], ["O le a Ou faia au meaai ia suamalie,", "I will make thy food become sweet,"], ["ina ia outou lē faavelaina;", "that ye cook it not;"]]},
  {num:13,words:[["Ma o le a avea foi A'u ma o outou sulu i le vao;", "And I will also be your light in the wilderness;"], ["ma o le a Ou saunia le ala i o outou luma,", "and I will prepare the way before you,"], ["e tusa ma tou tausiga o a'u poloaiga; o le mea lea,", "if it so be that ye shall keep my commandments;"], ["afai tou te tausia a'u poloaiga,", "wherefore,"], ["o le a taitaia outou agai i le laueleele na folafolaina;", "inasmuch as ye shall keep my command– ments ye shall be led towards the promised land;"], ["ma o le a outou iloa ai o a'u lava ua taitaia outou.", "and ye shall know that it is by me that ye are led."]]},
  {num:14,words:[["Ioe,", "Yea,"], ["ma sa fetalai mai foi le Alii:", "and the Lord said also that:"], ["A mavae ona outou taunuu i le laueleele na folafolaina,", "After ye have arrived in the promised land,"], ["o le a outou iloa o A'u,", "ye shall know that I,"], ["o le Alii,", "the Lord, am God;"], ["o le Atua ;", "and that I,"], ["ma o A'u o le Alii,", "the Lord,"], ["na lavea'ia outou mai le faafanoga;", "did deliver you from destruction;"], ["ioe,", "yea,"], ["ma o A'u na aumaia outou i fafo o le laueleele o Ierusalema.", "that I did bring you out of the land of Jerusalem."]]},
  {num:15,words:[["O le mea lea,", "Wherefore,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["sa ou taumafai ai e tausi poloaiga a le Alii,", "did strive to keep the commandments of the Lord,"], ["ma sa ou apoapoai atu i o'u uso ia faamaoni ma filiga.", "and I did exhort my brethren to faithfulness and diligence."]]},
  {num:16,words:[["Ma sa oo ina ou faia ni meafaigaluega mai 'oa na ou faaliusuavaia mai le papa.", "And it came to pass that I did make tools of the ore which I did molten out of the rock."]]},
  {num:17,words:[["Ma ina ua vaai mai o'u uso o le a ou fauina se vaa,", "And when my brethren saw that I was about to build a ship,"], ["sa amata ona laua muimui faasaga mai ia te a'u,", "they began to murmur against me,"], ["fai mai:", "saying:"], ["O lo tatou uso o se vale,", "Our brother is a fool,"], ["ona ua ia manatu e mafai ona ia fauina se vaa;", "for he thinketh that he can build a ship;"], ["ioe,", "yea,"], ["ma ua manatu foi o ia e mafai ona ia sopoia nei vai e tele.", "and he also thinketh that he can cross these great waters."]]},
  {num:18,words:[["Ma sa faapea ona tomumumu o'u uso ia te a'u,", "And thus my brethren did complain against me,"], ["ma sa mananao ia laua lē galulue,", "and were desirous that they might not labor,"], ["ona sa laua lē talitonu e mafai ona ou fauina se vaa;", "for they did not believe that I could build a ship;"], ["pe la te fia talitonu foi sa faatonuina ai a'u e le Alii.", "neither would they believe that I was instructed of the Lord."]]},
  {num:19,words:[["Ma o lenei sa oo,", "And now it came to pass that I,"], ["o a'u,", "Nephi,"], ["o Nifae, sa ou faanoanoa tele ona o le maaa o o laua loto;", "was exceedingly sorrowful because of the hardness of their hearts;"], ["ma o lenei,", "and now when they saw that I began to be sorrowful they were glad in their hearts,"], ["ina ua laua vaai mai ua amata ona ou faanoanoa sa laua fiafia i o laua loto,", "inso– much that they did rejoice over me,"], ["sa oo ina laua olioli i o'u luga,", "saying:"], ["fai mai:", "We knew that ye could not construct a  ship,"], ["Sa matou iloa lava e lē mafai ona e fauina se vaa, ona ua matou iloa ua leai se faautaga o ia te oe;", "for we knew that ye were lacking in judgment;"], ["o le mea lea,", "wherefore,"], ["e lē mafai ai ona e faia o se galuega tele faapena.", "thou canst not accomplish so great a work."]]},
  {num:20,words:[["Ma ua pei oe o lo tatou tamā,", "And thou art like unto our father,"], ["ua taitai ese e mafaufauga valea o lona loto;", "led away by the foolish imaginations of his heart;"], ["ioe,", "yea,"], ["ua ia taitai ese i tatou i fafo o le laueleele o Ierusalema,", "he hath led us out of the land of Jerusalem,"], ["ma ua tatou feoa'i ai i le vao i nei tausaga e tele;", "and we have wandered in the wilderness for these many years;"], ["ma galulue o tatou fafine,", "and our women have toiled,"], ["a'o mamafa i latou i fanau;", "being big with child;"], ["ma ua latou fanauina fanau i le vao ma mafatia i mea uma,", "and they have borne children in the wilderness and suffered all things,"], ["vagana ai le oti;", "save it were death;"], ["ma sa sili ona lelei pe ana latou feoti ae latou te lei o ese mai i fafo o Ierusalema nai lo le mafatia i nei puapuaga.", "and it would have been better that they had died before they came out of Jerusalem than to have suffered these afflictions."]]},
  {num:21,words:[["Faauta,", "Behold,"], ["ua tatou mafatia i le vao i nei tausaga e tele,", "these many years we have suffered in the wilderness,"], ["o se taimi lea po o tatou olioli ai ia tatou mea ua maua ma le laueleele o lo tatou tofi;", "which time we might have enjoyed our possessions and the land of our inheritance;"], ["ioe,", "yea,"], ["ma po o tatou fiafia.", "and we might have been happy."]]},
  {num:22,words:[["Ma ua matou iloa o tagata sa i le laueleele o Ierusalema o ni tagata amiotonu ;", "And we know that the people who were in the land of Jerusalem were a righteous people;"], ["ona sa latou tausia tulafono ma faamasinoga a le Alii,", "for they kept the statutes and judgments of the Lord,"], ["ma ana poloaiga uma,", "and all his commandments,"], ["e tusa ma le tulafono a Mose;", "accord– ing to the law of Moses;"], ["o le mea lea,", "wherefore,"], ["ua matou iloa ai o i latou o ni tagata amiotonu;", "we know that they are a righteous people;"], ["ma ua faamasino lo tatou tamā ia te i latou,", "and our father hath judged them,"], ["ma ua ia taitai ese i tatou ona ua tatou faalogologo i ana upu;", "and hath led us away because we would hearken unto his words;"], ["ioe,", "yea,"], ["ma ua faapei lo tatou uso o ia. Ma sa faapea le ituaiga o gagana sa muimui ma tomumumu ai o'u uso faasaga mai ia te i ma'ua.", "and our brother is like unto him. And after this manner of language did my brethren murmur and complain against us."]]},
  {num:23,words:[["Ma sa oo ina tautala atu a'u o Nifae,", "And it came to pass that I,"], ["ia te i laua,", "Nephi,"], ["ua fai atu:", "spake unto them,"], ["Tou te talitonu ea e taitai ese i fafo o tatou tamā,", "saying:"], ["o e o le fanauga a Isaraelu,", "Do ye believe that our fathers,"], ["mai lima o tagata Aikupito,", "who were the children of Israel,"], ["pe a na latou lē faalogologo i fetalaiga a le Alii?", "would have been led away out of the hands of the Egyptians if they had not hearkened unto the words of the Lord?"]]},
  {num:24,words:[["Ioe,", "Yea,"], ["tou te manatu ea e mafai ona taitai ese i latou i fafo mai le nofopologa,", "do ye suppose that they would have been led out of bondage,"], ["pe a na lē poloaiina Mose e le Alii e tatau ona ia taitai ese i latou i fafo mai le nofopologa?", "if the Lord had not commanded Moses that he should lead them out of bondage?"]]},
  {num:25,words:[["O lenei ua outou iloa sa i ai le fanauga a Isaraelu i le pologa ;", "Now ye know that the children of Israel were in bondage;"], ["ma ua outou iloa foi sa faafafa ia te i latou galuega ,", "and ye know that they were laden with tasks,"], ["sa faigata ona tauaveina;", "which were grievous to be borne;"], ["o le mea lea,", "wherefore,"], ["ua outou iloa sa tatau ona avea ma mea lelei mo i latou,", "ye know that it must needs be a good thing for them,"], ["le tatau ai ona aumai o i latou i fafo mai le nofopologa.", "that they should be brought out of bondage."]]},
  {num:26,words:[["O lenei ua outou iloa sa poloaiina Mose e le Alii e faia lena galuega tele;", "Now ye know that Moses was commanded of the Lord to do that great work;"], ["ma ua outou iloa o lana upu , na vaelua ai vai o le Sami Ulaula i lea itu ma lea itu,", "and ye know that by his word the waters of the Red Sea were divided hither and thither,"], ["ma latou ui atu ai i luga o le eleele matutu.", "and they passed through on dry ground."]]},
  {num:27,words:[["Ae ua outou iloa sa malelemo i le Sami Ulaula tagata Aikupito,", "But ye know that the Egyptians were drowned in the Red Sea,"], ["o e o 'au a Farao.", "who were the armies of Pharaoh."]]},
  {num:28,words:[["Ma ua outou iloa foi sa fafaga i latou i le manai i le vao.", "And ye also know that they were fed with manna in the wilderness."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["ma ua outou iloa foi sa ta e Mose le papa e ala i lana upu,", "and ye also know that Moses,"], ["e tusa ma le mana o le Atua sa ia te ia,", "by his word according to the power of God which was in him, smote the rock,"], ["ma sau ai le vai,", "and there came forth  water,"], ["ina ia mafai ona faamalilie ai e le fanauga a Isaraelu lo latou fia feinu.", "that the children of Israel might quench their thirst."]]},
  {num:30,words:[["Ma e ui lava ina sa taitaia i latou i le mua'au o le Alii lo latou Atua,", "And notwithstanding they being led,"], ["lo latou Togiola,", "the Lord their God,"], ["i o latou luma,", "their Redeemer,"], ["ma taitai i latou i le ao ma tuu mai le malamalama ia te i latou i le po,", "going before them, leading them by day and giving light unto them by night,"], ["ma faia mo i latou mea uma sa tatau ai mo se tagata ona ia maua,", "and doing all things for them which were expedient for man to receive,"], ["sa latou faamaaa o latou loto ma faatauaso o latou mafaufau,", "they hardened their hearts and blinded their minds,"], ["ma faifai faasaga ia Mose ma faasaga i le Atua moni ma soifua.", "and reviled against Moses and against the true and living God."]]},
  {num:31,words:[["Ma sa oo ina faaumatia i latou e ia e tusa ma lana afioga;", "And it came to pass that according to his word he did destroy them;"], ["ma sa ia taitaia i latou e tusa ma lana afioga;", "and according to his word he did lead them;"], ["ma sa ia faia mea uma mo i latou e tusa ma lana afioga;", "and according to his word he did do all things for them;"], ["ma sa leai se mea e tasi na faia vagana ai na faia i lana afioga.", "and there was not anything done save it were by his word."]]},
  {num:32,words:[["Ma ina ua mavae ona latou sopoia o le vaitafe o Ioritana sa faia e ia ia latou malolosi tele i le tutulieseina i fafo o fanau o le laueleele,", "And after they had crossed the river Jordan he did make them mighty unto the driving out of the children of the land,"], ["ioe,", "yea,"], ["i le faataapeapeina o i latou i le faafanoga.", "unto the scattering them to destruction."]]},
  {num:33,words:[["Ma o lenei,", "And now,"], ["tou te manatu ea o fanau o lenei laueleele,", "do ye suppose that the children of this land,"], ["o e sa i le laueleele o le folafolaga,", "who were in the land of promise,"], ["o e na tutuli ese i fafo e o tatou tamā,", "who were driven out by our fathers,"], ["pe tou te manatu ea sa amiotonu i latou? Faauta,", "do ye suppose that they were righteous? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E leai.", "Nay."]]},
  {num:34,words:[["Tou te manatu ea e sili atu ona lelei o tatou tamā nai lo i latou pe a na latou amiotonu? 'Ou te fai atu ia te outou,", "Do ye suppose that our fathers would have been more choice than they if they had been righteous? I say unto you,"], ["E leai.", "Nay."]]},
  {num:35,words:[["Faauta,", "Behold,"], ["ua tasi tagata uma i le finagalo o le Alii;", "the Lord esteemeth all flesh in one;"], ["o lē ua amiotonu ua faapitoa e le Atua. Ae faauta,", "he that is righteous is favored of God. But behold,"], ["sa teena e ia tagata afioga uma a le Atua,", "this people had rejected every word of God,"], ["ma sa matua i latou i le agasala;", "and they were ripe in iniquity;"], ["ma sa i ai i o latou luga le atoatoa o le toasa o le Atua;", "and the fulness of the wrath of God was upon them;"], ["ma sa fetuu e le Alii le laueleele e faasaga ia te i latou,", "and the Lord did curse the land against them,"], ["ma faamanuiaina mo o tatou tamā;", "and bless it unto our fathers;"], ["ioe,", "yea,"], ["sa fetuu e ia e faasaga ia te i latou mo lo latou faafanoga,", "he did curse it against them unto their destruction,"], ["ma sa faamanuia e ia mo o tatou tamā i lo latou mauaina o le pule i luga o lea laueleele.", "and he did bless it unto our fathers unto their obtaining power over it."]]},
  {num:36,words:[["Faauta,", "Behold,"], ["ua foafoa e le Alii le lalolagi ina ia 'ainā ;", "the Lord hath created the earth that it should be inhabited;"], ["ma ua ia foafoaina ana fanau ina ia latou mauaina.", "and he hath created his children that they should possess it."]]},
  {num:37,words:[["Ma e faatu mai e ia se atunuu amiotonu,", "And he raiseth up a righteous nation,"], ["ma faaumatia atunuu o e ua amioleaga.", "and destroyeth the nations of the wicked."]]},
  {num:38,words:[["Ma e taitai ese atu e ia e amiotonu i laueleele peleina,", "And he leadeth away the righteous into precious lands,"], ["ma o e amioleaga e faaumatia e ia,", "and the wicked he destroyeth,"], ["ma fetuu le laueleele ia te i latou ona o i latou.", "and curseth the land unto them for their sakes."]]},
  {num:39,words:[["Ua pule maualuga o ia i le lagi,", "He ruleth high in the heavens,"], ["ona o lona nofoalii lea,", "for it is his throne,"], ["ma o le lalolagi lenei o lona tuugaaao.", "and this earth is his footstool."]]},
  {num:40,words:[["Ma e alofa o ia ia te i latou o e e mananao e avea o ia ma o latou Atua. Faauta,", "And he loveth those who will have him to be their God. Behold,"], ["sa alofa o ia i o tatou tamā,", "he loved our fathers,"], ["ma sa osifeagaiga o ia ma i latou,", "and he covenanted with them,"], ["ioe,", "yea,"], ["o Aperaamo lava,", "even Abraham,"], ["Isaako ,", "Isaac,"], ["ma Iakopo ;", "and Jacob;"], ["ma sa manatua e ia feagaiga na ia faia;", "and he remembered the covenants which he had made;"], ["o le mea lea,", "wherefore,"], ["na aumai ai e ia i latou i fafo mai le laueleele o Aikupito .", "he did bring them out of the land of Egypt."]]},
  {num:41,words:[["Ma sa faasa'osa'oina e ia i latou i le vao i lona tootoo;", "And he did straiten them in the wilderness with his rod;"], ["ona sa latou faamaaa o latou loto,", "for they hardened their hearts,"], ["e pei lava o outou;", "even as ye have;"], ["ma sa faasa'osa'oina i latou e le Alii ona o lo latou amioletonu.", "and the Lord straitened them because of their iniquity."], ["Sa auina mai e ia ia i latou gata lele mumū;", "He sent fiery flying serpents among them;"], ["ma ina ua mavae ona utia o i latou sa saunia e ia se ala e mafai ai ona faamaloloina i latou;", "and after they were bitten he prepared a way that they might be healed;"], ["ma o le galuega sa ia te i latou e fai, o le vaai lea;", "and the labor which they had to perform was to look;"], ["ma ona o le faatauvaa o le ala,", "and because of the simpleness of the way,"], ["po o lona faigofie tele,", "or the easiness of it,"], ["sa i ai le toatele o e na fano.", "there were many who perished."]]},
  {num:42,words:[["Ma sa latou faamaaa o latou loto mai lea taimi i lea taimi,", "And they did harden their hearts from time to time,"], ["ma sa latou faifai faasaga ia Mose ,", "and they did revile against Moses,"], ["ma faasaga foi i le Atua;", "and also against God;"], ["e ui i lea,", "nevertheless,"], ["ua outou iloa sa taitai atu i latou i luma e lona mana lē mafaatusalia i le laueleele o le folafolaga.", "ye know that they were led forth by his matchless power into the land of promise."]]},
  {num:43,words:[["Ma o lenei,", "And now,"], ["e ui i nei mea uma,", "after all these things,"], ["ua oo mai le taimi ua avea ai i latou ma e amioleaga,", "the time has come that they have become wicked,"], ["ioe,", "yea,"], ["ua toeitiiti matutua i le agasala;", "nearly unto ripeness;"], ["ma ou te lē iloa ae atonu ua lata ona faaumatia o i latou i le aso nei;", "and I know not but they are at this day about to be destroyed;"], ["ona ua ou iloa e oo moni mai lava le aso e faaumatia ai i latou,", "for I know that the day must surely come that they must be destroyed,"], ["vagana ai nao se toaitiiti,", "save a few only,"], ["o e o le a taitai ese atu i le faatagataotauaina.", "who shall be led away into captivity."]]},
  {num:44,words:[["O le mea lea,", "Wherefore,"], ["na poloaiina ai e le Alii lo'u tamā e tatau ona alu ese atu o ia i le vao;", "the Lord commanded my father that he should depart into the wilderness;"], ["ma sa saili foi tagata Iutaia e aveese lona ola;", "and the Jews also sought to take away his life;"], ["ioe,", "yea,"], ["sa oulua saili foi e aveese lona ola;", "and ye also have sought to take away his life;"], ["o le mea lea,", "wherefore,"], ["o oulua o ni tagata fasioti tagata i o oulua loto ma ua pei oulua o i latou.", "ye are murderers in your hearts and ye are like unto them."]]},
  {num:45,words:[["Ua vave ona oulua fai o le amioletonu ae gese ona oulua manatua o le Alii lo oulua Atua. Ua oulua vaai i se agelu ,", "Ye are swift to do iniquity but slow to remember the Lord your God. Ye have seen an angel,"], ["ma sa fetalai mai o ia ia te oulua;", "and he spake unto you;"], ["ioe,", "yea,"], ["sa oulua faalogo i lona siufofoga mai lea taimi i lea taimi;", "ye have heard his voice from time to time;"], ["ma sa fetalai mai foi o ia ia te oulua i se leo filemu itiiti,", "and he hath spoken unto you in a still small voice,"], ["peitai ua oulua te'a atu ma le toe lagonaina,", "but ye were past feeling,"], ["na oulua lē mafafai ai ona lagona ana fetalaiga;", "that ye could not feel his words;"], ["o le mea lea,", "wherefore,"], ["na fetalai mai ai o ia ia te oulua e pei o le leo o le faititili,", "he has spoken unto you like unto the voice of thunder,"], ["lea na mafua ona luluina ai o le eleele e pei a vaeluaina.", "which did cause the earth to shake as if it were to divide asunder."]]},
  {num:46,words:[["Ma ua oulua iloa foi e mafai e ala i le mana o lana fetalaiga mamana aoao ona faia e ia ia mavae atu le lalolagi;", "And ye also know that by the power of his almighty word he can cause the earth that it shall pass away;"], ["ioe,", "yea,"], ["ma ua oulua iloa e mafai i lana fetalaiga ona ia faia o mea gaoā ia laugatasi,", "and ye know that by his word he can cause the rough places to be made smooth,"], ["ma mea laugatasi ia vetevete. O lea,", "and smooth places shall be broken up. O,"], ["la,", "then,"], ["aisea ea,", "why is it,"], ["ua mafai ai ona oulua maaa tele faapea i o oulua loto?", "that ye can be so hard in your hearts?"]]},
  {num:47,words:[["Faauta,", "Behold,"], ["ua saeia lo'u agaga i le mafatia ona o oulua,", "my soul is rent with anguish because of you,"], ["ma ua tiga lo'u loto;", "and my heart is pained;"], ["ou te fefe ne'i lafoai ese oulua e faavavau. Faauta,", "I fear lest ye shall be cast off forever. Behold,"], ["ua tumu a'u i le Agaga o le Atua,", "I am full of the Spirit of God,"], ["ua oo ina leai se malosi i lo'u tino.", "insomuch that my frame has no strength."]]},
  {num:48,words:[["Ma o lenei,", "And now it came to pass that when I had spoken these words,"], ["sa oo ina ua uma ona ou tautala atu o ia upu sa laua feitai mai ia te a'u,", "they were angry with me,"], ["ma mananao e lafo a'u i le loloto o le sami;", "and were desirous to throw me into the depths of the sea;"], ["ma a'o laua o mai i luma e fetagofi mai o laua lima ia te a'u sa ou tautala atu ia te i laua,", "and as they came forth to lay their hands upon me I spake unto them,"], ["ua ou fai atu:", "saying:"], ["I le suafa o le Atua Malosi Aoao,", "In the name of the Almighty God,"], ["ou te faatonu atu ia te oulua ia aua lua te pa'i mai ia te a'u,", "I command you that ye touch me not,"], ["ona ua tumu a'u i le mana o le Atua,", "for I am filled with the power of God,"], ["e oo lava i le faaumatiaina o lo'u tino;", "even unto the consuming of my flesh;"], ["ma ai se tasi e pa'i mai ona lima ia te a'u o le a mamae e pei lava o se utuutu mago;", "and whoso shall lay his hands upon me shall wither even as a dried reed;"], ["ma o le a tusa o ia o se meanoa i luma o le mana o le Atua,", "and he shall be as naught before the power of God,"], ["ona o le a taia o ia e le Atua.", "for God shall smite him."]]},
  {num:49,words:[["Ma sa oo ina fai atu a'u o Nifae,", "And it came to pass that I,"], ["ia te i laua e lē tatau ona laua toe muimui e faasaga i lo laua tamā;", "Nephi,"], ["pe tatau foi ona laua taofi mai ia te a'u lo laua galulue,", "said unto them that they should murmur no more against their father; neither should they withhold their labor from me,"], ["ona ua poloaiina a'u e le Atua ia ou fausia se vaa.", "for God had commanded me that I should build a ship."]]},
  {num:50,words:[["Ma sa ou fai atu ia te i laua: Afai na poloaiina a'u e le Atua ou te faia mea uma,", "And I said unto them:"], ["e mafai ona ou faia.", "If God had commanded me to do all things I could do them."], ["Afai na te poloaiina a'u ia ou fai atu i lenei vai,", "If he should command me that I should say unto this water,"], ["ia eleele oe,", "be thou earth,"], ["e eleele lava;", "it should be earth;"], ["ma afai ou te fai atu ai,", "and if I should say it,"], ["o le a faia lava.", "it would be done."]]},
  {num:51,words:[["Ma o lenei,", "And now,"], ["afai ua i ai i le Alii se mana tele faapea,", "if the Lord has such great power,"], ["ma e tele vavega ua faia e ia i totonu o le fanauga a tagata,", "and has wrought so many miracles among the children of men,"], ["e faapefea la ona lē mafai ona ia a'oa'oina o a'u,", "how is it that he cannot instruct me,"], ["ia 'ou fausia se vaa?", "that I should build a ship?"]]},
  {num:52,words:[["Ma sa oo o a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["sa tele mea sa ou fai atu ai i o'u uso, sa oo ina laua maasiasi,", "said many things unto my brethren,"], ["ma lē mafafai ona finau faasaga mai ia te a'u;", "insomuch that they were confounded and could not contend against me;"], ["pe na totoa e fetagofi mai o laua lima ia te a'u pe pa'i mai ia te a'u i o laua tamatamailima,", "neither durst they lay their hands upon me nor touch me with their fingers,"], ["mo le va o aso e tele.", "even for the space of many days."], ["O lenei sa fefefe i laua e fai lenei mea ne'i o laua mamae i o'u luma,", "Now they durst not do this lest they should wither before me,"], ["ona o le malosi tele o le Agaga o le Atua;", "so powerful was the Spirit of God;"], ["ma sa faapea ona galue i luga o i laua.", "and thus it had wrought upon them."]]},
  {num:53,words:[["Ma sa oo ina fetalai mai le Alii ia te a'u:", "And it came to pass that the Lord said unto me:"], ["Ia toe faaloaloa atu lou lima i ou uso,", "Stretch forth thine hand again unto thy brethren,"], ["ma o le a laua lē mamae ai i ou luma,", "and they shall not wither before thee,"], ["ae o le a Ou faateia i laua,", "but I will shock them,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["ma o le a Ou faia lenei mea,", "and this will I do,"], ["ina ia iloa ai o A'u o le Alii o lo laua Atua lea.", "that they may know that I am the Lord their God."]]},
  {num:54,words:[["Ma sa oo ina ou faaloaloa atu lo'u lima i o'u uso,", "And it came to pass that I stretched forth my hand unto my brethren,"], ["ma sa lei mamae i laua ai i o'u luma,", "and they did not wither before me;"], ["ae sa luluina i laua e le Alii,", "but the Lord did shake them,"], ["e tusa lava ma le fetalaiga na fetalai mai ai o ia.", "even according to the word which he had spoken."]]},
  {num:55,words:[["Ma o lenei,", "And now,"], ["sa fai mai i laua:", "they said:"], ["Ua ma iloa ma le mautinoa ua faatasi le Alii ma oe,", "We know of a surety that the Lord is with thee,"], ["ona ua ma iloa o le mana o le Alii na luluina i maua. Ma sa la faapauu i lalo i o'u luma,", "for we know that it is the power of the Lord that has shaken us. And they fell down before me,"], ["ma fai o le a ifo mai ia te a'u,", "and were about to worship me,"], ["peitai sa ou lē tuua i laua,", "but I would not suffer them,"], ["ua ou fai atu:", "saying:"], ["O a'u o lo oulua uso,", "I am thy brother,"], ["ioe,", "yea,"], ["o lo oulua lava uso laitiiti;", "even thy younger brother;"], ["o le mea lea,", "wherefore,"], ["ifo atu i le Alii lo oulua Atua,", "worship the Lord thy God,"], ["ma ava i lo oulua tamā ma lo oulua tinā,", "and honor thy father and thy mother,"], ["ina ia faalevaleva ai o oulua aso i le laueleele o le a foaiina mai e le Alii lo oulua Atua ia te oulua.", "that thy days may be long in the land which the Lord thy God shall give thee."]]},
];
renderVerseSet(ch_17_Verses, 'ch17-verses');

var ch_18_Verses = [
  {num:1,words:[["Ma sa oo ina laua ifo atu i le Alii,", "And it came to pass that they did worship the Lord,"], ["ma o atu faatasi ma a'u;", "and did go forth with me;"], ["ma sa matou ta laau i gaosiga uiga ese. Ma sa faaali mai e le Alii ia te a'u i lea taimi ma lea taimi le ala e tatau ona ou ta ai laau o le vaa.", "and we did work timbers of curious workmanship. And the Lord did show me from time to time after what manner I should work the timbers of the ship."]]},
  {num:2,words:[["O lenei,", "Now I,"], ["o a'u o Nifae,", "Nephi,"], ["sa ou lē taina laau i le ala sa a'oa'oina e tagata,", "did not work the timbers after the manner which was learned by men,"], ["pe sa ou fauina le vaa i ala a tagata;", "neither did I build the ship after the manner of men;"], ["ae sa ou fauina i le ala na faaali mai e le Alii ia te a'u;", "but I did build it after the manner which the Lord had shown unto me;"], ["o le mea lea,", "wherefore,"], ["sa lei tusa ai ma le ala a tagata.", "it was not after the manner of men."]]},
  {num:3,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa ou alu soo i le mauga,", "did go into the mount oft,"], ["ma sa ou tatalo soo atu i le Alii;", "and I did pray oft unto the Lord;"], ["o le mea lea na faaali mai ai e le Alii ia te a'u mea tetele.", "wherefore the Lord showed unto me great things."]]},
  {num:4,words:[["Ma sa oo ina ua uma ona ou faia o le vaa,", "And it came to pass that after I had finished the ship,"], ["e tusa ma le afioga a le Alii,", "according to the word of the Lord,"], ["sa vaai o'u uso ua lelei,", "my brethren beheld that it was good,"], ["ma o lona gaosiga sa matua lelei lava;", "and that the workmanship thereof was exceedingly fine;"], ["o le mea lea,", "wherefore,"], ["sa laua toe faamaualalalo ai i laua lava i luma o le Alii.", "they did humble themselves again before the Lord."]]},
  {num:5,words:[["Ma sa oo ina oo mai le siufofoga o le Alii i lo'u tamā,", "And it came to pass that the voice of the Lord came unto my father,"], ["ia matou tutulai ma o ifo i lalo i totonu o le vaa.", "that we should arise and go down into the ship."]]},
  {num:6,words:[["Ma sa oo i le aso na sosoo ai,", "And it came to pass that on the morrow,"], ["ina ua uma ona matou saunia o mea uma,", "after we had prepared all things,"], ["o fualaau 'aina e tele ma aano o manu mai le vao,", "much fruits and meat from the wilderness,"], ["ma le meli e tele,", "and honey in abundance,"], ["ma tapenapenaga e tusa ma mea na poloaiina ai i matou e le Alii,", "and provisions according to that which the Lord had commanded us,"], ["sa matou o ifo i lalo i le vaa,", "we did go down into the ship,"], ["ma a matou uta uma ma a matou fatu,", "with all our loading and our seeds,"], ["ma mea uma na matou aumai faatasi ma i matou,", "and whatsoever thing we had brought with us,"], ["e taitasi le tagata e tusa ma ona tausaga;", "every one according to his age;"], ["o le mea lea,", "wherefore,"], ["sa matou o ifo uma i lalo i totonu o le vaa,", "we did all go down into the ship,"], ["faatasi ma a matou ava ma a matou fanau.", "with our wives and our children."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["sa fanaua e lo'u tamā i le vao ni atalii e toalua;", "my father had begat two sons in the wilderness;"], ["o le matua sa faaigoa o Iakopo a'o le itiiti o Iosefa .", "the elder was called Jacob and the younger Joseph."]]},
  {num:8,words:[["Ma sa oo ina ua uma ona matou o ifo uma i lalo i totonu o le vaa,", "And it came to pass after we had all gone down into the ship,"], ["ma ua ave faatasi ma i matou a matou tapenapenaga ma mea sa poloaiina ai i matou,", "and had taken with us our provisions and things which had been commanded us,"], ["sa matou tuuvaa atu loa i le sami ma tulei atu i luma o le matagi agai i le laueleele na folafolaina.", "we did put forth into the sea and were driven forth before the wind towards the promised land."]]},
  {num:9,words:[["Ma ina ua mavae ona tuleia o i matou i luma o le matagi mo le va o aso e tele,", "And after we had been driven forth before the wind for the space of many days,"], ["faauta,", "behold,"], ["sa amata e o'u uso ma atalii o Isamaeli ma a latou ava foi ona faafiafia i latou lava,", "my brethren and the sons of Ishmael and also their wives began to make themselves merry,"], ["sa oo ina amata ona latou sisiva,", "insomuch that they began to dance,"], ["ma pepese,", "and to sing,"], ["ma tautatala ma le lē migao tele,", "and to speak with much rudeness,"], ["ioe,", "yea,"], ["sa oo lava ina galo ia te i latou le mana na aumai ai i latou iina;", "even that they did forget by what power they had been brought thither;"], ["ioe,", "yea,"], ["sa faaosofia lava i latou i luga i le lē migao tele.", "they were lifted up unto exceeding rudeness."]]},
  {num:10,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa amata ona ou mata'u tele ne'i toatamai le Alii ia te i matou,", "began to fear exceedingly lest the Lord should be angry with us,"], ["ma taia ai i matou ona o lo matou amioletonu,", "and smite us because of our iniquity,"], ["ma tofatumoanaina ai i matou i le loloto o le sami;", "that we should be swallowed up in the depths of the sea;"], ["o le mea lea,", "wherefore,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["sa amata ona ou tautala atu ia te i latou ma le faamamalu tele;", "began to speak to them with much soberness;"], ["ae faauta sa latou feitai mai ia te a'u,", "but behold they were angry with me,"], ["fai mai:", "saying:"], ["Matou te lē mananao ia avea lo ma uso laitiiti o se pule ia i matou.", "We will not that our younger brother shall be a ruler over us."]]},
  {num:11,words:[["Ma sa oo ina ave a'u e Lamana ma Lemuelu ma saisai a'u i maea,", "And it came to pass that Laman and Lemuel did take me and bind me with cords,"], ["ma sa la faia ia te a'u ma le saua tele;", "and they did treat me with much harshness;"], ["e ui i lea,", "nevertheless,"], ["sa tuu lava e le Alii ina ia mafai ona ia faaali mai ai lona mana,", "the Lord did suffer it that he might show forth his power,"], ["e faataunuu ai lana fetalaiga na ia fetalai mai e uiga i e amioleaga.", "unto the fulfilling of his word which he had spoken concerning the wicked."]]},
  {num:12,words:[["Ma sa oo ina ua uma ona laua noatia o a'u seia lē mafai ona ou gaoioi,", "And it came to pass that after they had bound me insomuch that I could not move,"], ["o le tapasa ,", "the compass,"], ["lea sa saunia e le Alii,", "which had been prepared of the Lord,"], ["ua le ola.", "did cease to work."]]},
  {num:13,words:[["O le mea lea,", "Wherefore,"], ["sa latou le iloa ai le mea e uli i ai le vaa,", "they knew not whither they should steer the ship,"], ["sa oo ina oso mai se timuga tele,", "insomuch that there arose a great storm,"], ["ioe,", "yea,"], ["o se afa tele lava ma mata'utia,", "a great and terrible tempest,"], ["ma sa toe tuleia ai i matou i tua i luga o le vasa i le va o aso e tolu;", "and we were driven back upon the waters for the space of three days;"], ["ma sa amata ona latou matata'u tele ne'i o latou malelemo i le sami;", "and they began to be frightened exceedingly lest they should be drowned in the sea;"], ["e ui i lea sa latou le tatalaina lava a'u.", "nevertheless they did not loose me."]]},
  {num:14,words:[["Ma i le aso lona fa,", "And on the fourth day,"], ["lea na toe tuleia ai i matou i tua,", "which we had been driven back,"], ["sa amata ona matua faateteleina o le afa.", "the tempest began to be exceedingly sore."]]},
  {num:15,words:[["Ma sa oo ina toetoe a tofatumoanaina i matou i le loloto o le sami.", "And it came to pass that we were about to be swallowed up in the depths of the sea."], ["Ma ina ua mavae ona toe tuleia o i matou i tua i luga o le vasa mo le va o aso e fa,", "And after we had been driven back upon the waters for the space of four days,"], ["sa amata ona vaai o'u uso ua i luga o i latou faamasinoga a le Atua,", "my brethren began to see that the judgments of God were upon them,"], ["ma o le a latou fano vagana ai ua latou salamo ia latou amioletonu;", "and that they must perish save that they should repent of their iniquities;"], ["o le mea lea,", "wherefore,"], ["na la o mai ai ia te a'u, ma tatala fusi sa i luga o o'u tapulima,", "they came unto me,"], ["ma faauta,", "and loosed the bands which were upon my wrist,"], ["sa fulafula tetele lava;", "and behold they had swollen exceedingly;"], ["ma sa fulafula tetele foi o'u tapuvae,", "and also mine ankles were much swollen,"], ["ma sa matua tiga tele lava.", "and great was the soreness thereof."]]},
  {num:16,words:[["E ui i lea,", "Nevertheless,"], ["sa ou tepa taulai a'e i lo'u Atua,", "I did look unto my God,"], ["ma sa ou viia o ia i le aso atoa;", "and I did praise him all the day long;"], ["ma sa ou lē muimui e faasaga i le Alii ona o o'u puapuaga.", "and I did not murmur against the Lord because of mine afflictions."]]},
  {num:17,words:[["O lenei o lo'u tamā o Liae,", "Now my father,"], ["sa tele mea sa ia fai atu ia te i laua,", "Lehi,"], ["ma i atalii foi o Isamaeli ;", "had said many things unto them,"], ["peitai,", "and also unto the sons of Ishmael;"], ["faauta,", "but,"], ["sa laua manava mai faamata'uga e tele e faasaga i soo se tasi e tautala atu mo a'u;", "behold,"], ["ma o o'u matua,", "they did breathe out much threatenings against anyone that should speak for me;"], ["ona sa mafatia i le tele o o laua tausaga,", "and my parents being stricken in years,"], ["ma ona sa mafatia foi i le faanoanoa tele ona o a laua fanau,", "and having suffered much grief because of their children,"], ["sa ave ifo i laua i lalo,", "they were brought down,"], ["ioe,", "yea,"], ["i luga lava o o laua tofaga-gasegase.", "even upon their sick– beds."]]},
  {num:18,words:[["Ona o lo laua faavauvau ma le faanoanoa tele,", "Because of their grief and much sorrow,"], ["ma le amioletonu o o'u uso,", "and the iniquity of my brethren,"], ["sa toetoe ina aumai i laua e aveina atu i lea lava taimi e fetaia'i ma lo laua Atua;", "they were brought near even to be carried out of this time to meet their God;"], ["ioe,", "yea,"], ["sa toetoe ina ave ifo i lalo o laua lauulu sinasina e faataooto maualalalo i le eleele;", "their grey hairs were about to be brought down to lie low in the dust;"], ["ioe,", "yea,"], ["sa toetoe lava foi a lafoina i laua ma le faanoanoa i totonu o se tuugamau vai.", "even they were near to be cast with sorrow into a watery grave."]]},
  {num:19,words:[["Ma o Iakopo ma Iosefa foi,", "And Jacob and Joseph also,"], ["ona sa laiti,", "being young,"], ["ma ona sa laua mananaomia se tausiga tele,", "having need of much nourishment,"], ["sa faanoanoa i puapuaga o lo laua tinā;", "were grieved because of the afflictions of their mother;"], ["ma o la'u ava foi ma ona loimata ma ana talosaga,", "and also my wife with her tears and prayers,"], ["ma la'u fanau foi,", "and also my children,"], ["sa le faamaluluina ai lava loto o o'u uso ina ia la tatalaina a'u.", "did not soften the hearts of my brethren that they would loose me."]]},
  {num:20,words:[["Ma sa leai se mea vagana ai le mana o le Atua,", "And there was nothing save it were the power of God,"], ["lea sa faamata'uina ai i laua i le faafanoga,", "which threatened them with destruction,"], ["sa mafai ona faamaluluina ai o laua loto; o le mea lea,", "could soften their hearts;"], ["ina ua laua vaai ua tauau ina tofatumoanaina i latou i le loloto o le sami,", "wherefore,"], ["sa la salamo ai i le mea na laua faia,", "when they saw that they were about to be swallowed up in the depths of the sea they repented of the thing which they had done,"], ["sa oo ina laua tatalaina a'u.", "insomuch that they loosed me."]]},
  {num:21,words:[["Ma sa oo ina ua uma ona laua tatalaina o a'u,", "And it came to pass after they had loosed me,"], ["faauta,", "behold,"], ["sa ou ave le tapasa,", "I took the compass,"], ["ma sa ola e pei ona ou manao i ai. Ma sa oo ina ou tatalo atu i le Alii;", "and it did work whither I desired it. And it came to pass that I prayed unto the Lord;"], ["ma ina ua uma ona ou tatalo atu sa uma le matagi,", "and after I had prayed the winds did cease,"], ["ma sa uma timuga,", "and the storm did cease,"], ["ma sa oo mai se malū tele.", "and there was a great calm."]]},
  {num:22,words:[["Ma sa oo o a'u,", "And it came to pass that I,"], ["o Nifae,", "Nephi,"], ["sa ou tautaia le vaa,", "did guide the ship,"], ["sa oo ina matou toe folau atu agai i le laueleele na folafolaina.", "that we sailed again towards the promised land."]]},
  {num:23,words:[["Ma sa oo ina ua mavae ona matou folau mo le va o aso e tele, sa matou taunuu i le laueleele na folafolaina;", "And it came to pass that after we had sailed for the space of many days we did arrive at the promised land;"], ["ma sa matou o atu i luga o le laueleele,", "and we went forth upon the land,"], ["ma faatutu o matou faleie;", "and did pitch our tents;"], ["ma sa matou ta'ua, o le laueleele na folafolaina.", "and we did call it the promised land."]]},
  {num:24,words:[["Ma sa oo ina amata ona matou galueaiina le eleele,", "And it came to pass that we did begin to till the earth,"], ["ma amata ona matou toto fatu;", "and we began to plant seeds;"], ["ioe,", "yea,"], ["sa matou tuuina i le eleele a matou fatu uma,", "we did put all our seeds into the earth,"], ["ia sa matou aumai mai le laueleele o Ierusalema. Ma sa oo ina tutupu tetele i latou;", "which we had brought from the land of Jerusalem. And it came to pass that they did grow exceedingly;"], ["o le mea lea,", "wherefore,"], ["sa faamanuiaina ai i matou i le mau tele.", "we were blessed in abundance."]]},
  {num:25,words:[["Ma sa oo ina matou maua i luga o le laueleele o le folafolaga,", "And it came to pass that we did find upon the land of promise,"], ["a'o matou malaga i le vao,", "as we journeyed in the wilderness,"], ["sa i ai i le vao ituaiga o manu eseese,", "that there were beasts in the forests of every kind,"], ["o le povi fafine ma le povi poa,", "both the cow and the ox,"], ["ma le asini ma le solofanua,", "and the ass and the horse,"], ["o le 'oti ma le 'oti vao,", "and the goat and the wild goat,"], ["ma ituaiga uma o manu aivao,", "and all manner of wild animals,"], ["ia sa i ai mo le faaaogaina e tagata. Ma sa matou maua ituaiga uma o 'oa,", "which were for the use of men. And we did find all manner of ore,"], ["o le auro,", "both of gold,"], ["ma le ario,", "and of silver,"], ["ma le apamemea.", "and of copper."]]},
];
renderVerseSet(ch_18_Verses, 'ch18-verses');

var ch_19_Verses = [
  {num:1,words:[["Ma sa oo ina poloaiina a'u e le Alii,", "And it came to pass that the Lord commanded me,"], ["o le mea lea na ou faia ai papatusi mai le 'oa ina ia mafai ona ou togitogia ai i luga o i latou le talafaamaumau o o'u tagata. Ma o luga o papatusi na ou faia ua ou togitogia ai le talafaamaumau a lo'u tamā ,", "wherefore I did make plates of ore that I might engraven upon them the record of my people. And upon the plates which I made I did engraven the record of my father,"], ["ma a matou malaga foi i le vao,", "and also our journeyings in the wilderness,"], ["ma valoaga a lo'u tamā;", "and the prophecies of my father;"], ["ma o le tele foi o a'u lava valoaga ua ou togitogia i luga o i latou.", "and also many of mine own prophecies have I engraven upon them."]]},
  {num:2,words:[["Ma sa ou le iloa i le taimi na ou faia ai ia papatusi o le a poloaiina a'u e le Alii ia faia papatusi nei;", "And I knew not at the time when I made them that I should be commanded of the Lord to make these plates;"], ["o le mea lea,", "wherefore,"], ["o le talafaamaumau a lo'u tamā,", "the record of my father,"], ["ma le gafa o ona tamā,", "and the genealogy of his fathers,"], ["ma le vaega tele o a matou taualumaga i le vao, ua togitogia i luga o papatusi muamua ia sa ou tautala atu ai;", "and the more part of all our proceedings in the wilderness are engraven upon those first plates of which I have spoken;"], ["o le mea lea,", "wherefore,"], ["o mea na tutupu ae ou te lei faia papatusi nei,", "the things which transpired before I made these plates are,"], ["o le mea moni lava,", "of a truth,"], ["ua faapitoa ona ta'ua i luga o papatusi muamua.", "more particularly made mention upon the first plates."]]},
  {num:3,words:[["Ma ina ua uma ona ou faia o papatusi nei e ala i le poloaiga,", "And after I had made these plates by way of commandment,"], ["o a'u o Nifae,", "I,"], ["sa ou maua se poloaiga e faapea o le auaunaga ma valoaga,", "Nephi,"], ["o vaega silisili ona manino ma pele o i latou,", "received a commandment that the ministry and the prophecies,"], ["e tatau ona tusia i luga o papatusi nei;", "the more plain and precious parts of them, should be written upon these plates;"], ["ma o mea ua tusia e tatau ona tausia mo le aoaoga o o'u tagata,", "and that the things which were written should be kept for the instruction of my people,"], ["o e o le a latou mauaina le laueleele,", "who should possess the land,"], ["ma mo isi foi faamoemoega poto,", "and also for otherwise purposes,"], ["o faamoemoega ia ua silafia e le Alii.", "which purposes are known unto the Lord."]]},
  {num:4,words:[["O le mea lea,", "Wherefore,"], ["o a'u o Nifae,", "I,"], ["na ou faia ai se talafaamaumau i luga o isi papatusi,", "Nephi, did make a record upon the other plates,"], ["ia ua tuuina atu ai se tala,", "which gives an account,"], ["po o ia ua tuuina atu ai se tala tele atu o taua ma finauga ma faafanoga o o'u tagata.", "or which gives a greater account of the wars and contentions and destructions of my people."], ["Ma ua ou faia lenei mea,", "And this have I done,"], ["ma poloaiina o'u tagata i le mea e tatau ona latou faia pe a mavae ona ou alu;", "and commanded my people what they should do after I was gone;"], ["ma ia tuulima faasolo atu i lalo nei papatusi mai le tasi tupulaga i le tasi,", "and that these plates should be handed down from one generation to another,"], ["pe mai le isi perofeta i le isi,", "or from one prophet to another,"], ["seia toe maua ni isi poloaiga mai i le Alii.", "until further commandments of the Lord."]]},
  {num:5,words:[["Ma o se tala o lo'u faia o papatusi nei o le a tuu atu i se taimi o mulimuli mai;", "And an account of my making these plates shall be given hereafter;"], ["ma faauta,", "and then,"], ["ona ou faaauau ai lea ona faia e tusa ai ma le mea ua ou tautala atu ai;", "behold, I proceed according to that which I have spoken;"], ["ma ua ou faia lenei mea ina ia mafai ona tausia o mea silisili ona paia mo le malamalama o o'u tagata.", "and this I do that the more sacred things may be kept for the knowledge of my people."]]},
  {num:6,words:[["E ui i lea,", "Nevertheless,"], ["ou te lē tusia se mea i luga o papatusi vagana ai o se mea ua ou manatu ua paia . Ma o lenei,", "I do not write anything upon plates save it be that I think it be sacred. And now,"], ["afai ua ou sese,", "if I do err,"], ["sa sese foi i latou anamua;", "even did they err of old;"], ["e le faapea ou te sisi'o ai ia te a'u lava ia ona o isi tagata,", "not that I would excuse myself because of other men,"], ["ae ona o le vaivai ua ia te a'u,", "but because of the weakness which is in me,"], ["e tusa ma la le tino,", "according to the flesh,"], ["ou te sisi'o ai ia te a'u lava ia.", "I would excuse myself."]]},
  {num:7,words:[["Ona o mea ua manatu ni isi tagata ua taua tele,", "For the things which some men esteem to be of great worth,"], ["i la le tino ma la le agaga,", "both to the body and soul,"], ["ua tuu faameanoa e isi ma soli i lalo o o latou vae. Ioe,", "others set at naught and trample under their feet. Yea,"], ["e oo i le Atua lava o Isaraelu e soli i lalo e tagata i o latou vae;", "even the very God of Israel do men trample under their feet;"], ["ua ou fai atu,", "I say,"], ["e soli i lalo i o latou vae ae ou te fai atu i ni isi upu—latou te tuu ese o ia o se meanoa,", "trample under their feet but I would speak in other words—they set him at naught,"], ["ma lē faalogologo i le siufofoga o ana fautuaga.", "and hearken not to the voice of his counsels."]]},
  {num:8,words:[["Ma faauta,", "And behold he cometh,"], ["e afio mai o ia, e tusa ma fetalaiga a le agelu,", "according to the words of the angel,"], ["i le ono selau tausaga mai le taimi na tuua ai e lo'u tamā Ierusalema.", "in six hundred years from the time my father left Jerusalem."]]},
  {num:9,words:[["Ma o le lalolagi,", "And the world,"], ["ona o lo latou amioletonu,", "because of their iniquity,"], ["o le a faamasino ia te ia o se meanoa;", "shall judge him to be a thing of naught;"], ["o le mea lea latou te sasa ai ia te ia,", "wherefore they scourge him,"], ["ae tuu atu e ia i ai;", "and he suffereth it;"], ["ma latou taia o ia,", "and they smite him,"], ["ae tuu atu e ia i ai. Ioe,", "and he suffereth it. Yea,"], ["latou te tuufeanu ia te ia,", "they spit upon him,"], ["ae tuu atu e ia i ai,", "and he suffereth it,"], ["ona o lona agalelei alofa ma lona tali-tiga i le fanauga a tagata.", "because of his loving kindness and his long– suffering towards the children of men."]]},
  {num:10,words:[["Ma o le Atua o o tatou tamā,", "And the God of our fathers,"], ["o e na taitai ese i fafo mai Aikupito,", "who were led out of Egypt,"], ["i fafo mai le nofopologa,", "out of bon– dage,"], ["ma sa faasaoina foi e ia i le vao,", "and also were preserved in the wilderness by him,"], ["ioe,", "yea,"], ["o le Atua o Aperaamo,", "the God of Abraham,"], ["ma Isaako,", "and of Isaac,"], ["ma le Atua o Iakopo,", "and the God of Jacob,"], ["e tuu atu e ia o ia lava,", "yieldeth himself,"], ["e tusa ma fetalaiga a le agelu,", "according to the words of the angel,"], ["e pei o se tagata,", "as a man,"], ["i lima o e amioleaga,", "into the hands of wicked men,"], ["ia sii a'e i luga,", "to be lifted up,"], ["e tusa ma upu a Senoka ,", "according to the words of Zenock,"], ["ma ia faasatauroina ,", "and to be crucified,"], ["e tusa ma upu a Neuma,", "according to the words of Neum,"], ["ma ia tanumia i se tuugamau ,", "and to be buried in a sepulchre,"], ["e tusa ma upu a Senosa ,", "according to the words of Zenos,"], ["ia na fetalaia e ia e uiga i aso e tolu o le pogisa ,", "which he spake concerning the three days of darkness,"], ["ia o le a avea o se faailoga o lona maliu ia te i latou o e o le a 'ainā motu o le sami,", "which should be a sign given of his death unto those who should inhabit the isles of the sea,"], ["ua faapitoa lava ona tuuina mai ia te i latou o e o le aiga o Isaraelu.", "more especially given unto those who are of the house of Israel."]]},
  {num:11,words:[["Ona ua faapea ona fetalai mai o le perofeta:", "For thus spake the prophet:"], ["O le a mautinoa lava ona asiasi mai o le Alii le Atua i le aiga uma o Isaraelu i lena aso,", "The Lord God surely shall visit all the house of Israel at that day,"], ["o ni isi i lona siufofoga,", "some with his voice,"], ["ona o lo latou amiotonu,", "because of their righteousness,"], ["mo lo latou olioli tele ma olataga,", "unto their great joy and salvation,"], ["a'o isi i faititili ma uila o lona mana,", "and others with the thunderings and the lightnings of his power,"], ["i afa,", "by tempest,"], ["i le afi,", "by fire,"], ["ma le asu,", "and by smoke,"], ["ma le puao o le pogisa ,", "and vapor of darkness,"], ["ma i le veteina o le eleele ,", "and by the opening of the earth,"], ["ma i mauga o le a aveina a'e i luga.", "and by mountains which shall be carried up."]]},
  {num:12,words:[["Ma o nei mea uma o le a mautinoa lava ona oo mai,", "And all these things must surely come,"], ["ua fai mai ai le perofeta o Senosa . Ma o papa o le eleele o le a mavaevae;", "saith the prophet Zenos. And the rocks of the earth must rend;"], ["ma ona o le oi o le eleele,", "and because of the groanings of the earth,"], ["e toatele tupu o motu o le sami o le a galue i ai i luga le Agaga o le Atua,", "many of the kings of the isles of the sea shall be wrought upon by the Spirit of God,"], ["e alalaga:", "to exclaim:"], ["Ua mafatia le Atua o le natura.", "The God of nature suffers."]]},
  {num:13,words:[["Ma o i latou o e o i Ierusalema,", "And as for those who are at Jerusalem,"], ["ua fetalai mai le perofeta,", "saith the prophet,"], ["o le a sasaina i latou e tagata uma,", "they shall be scourged by all people,"], ["ona ua latou faasatauroina le Atua o Isaraelu,", "because they crucify the God of Israel,"], ["ma liliu ese o latou loto,", "and turn  their hearts aside,"], ["ma teena faailoga ma mea ofoofogia,", "rejecting signs and wonders,"], ["ma le mana ma le mamalu o le Atua o Isaraelu.", "and the power and glory of the God of Israel."]]},
  {num:14,words:[["Ma ona latou te liliu ese o latou loto,", "And because they turn their hearts aside,"], ["ua fetalai mai ai le perofeta,", "saith the prophet,"], ["ma inosia le Paia e Toatasi o Isaraelu,", "and have despised the Holy One of Israel,"], ["o le a latou maumausolo i la le tino,", "they shall wander in the flesh,"], ["ma fano,", "and perish,"], ["ma avea ma tauemuga ma upufaifai ,", "and become a hiss and a byword,"], ["ma inosia i totonu o atunuu uma.", "and be hated among all nations."]]},
  {num:15,words:[["E ui i lea,", "Nevertheless,"], ["a oo mai lena aso,", "when that day cometh,"], ["ua fetalai mai ai le perofeta,", "saith the prophet,"], ["latou te lē toe liliu ese ai o latou loto e faasaga i le Paia e Toatasi o Isaraelu,", "that they no more turn aside their hearts against the Holy One of Israel,"], ["ona manatua ai lea e ia o feagaiga na ia faia i o latou tamā.", "then will he remember the covenants which he made to their fathers."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["ona manatua ai lea e ia o motu o le sami;", "then will he remember the isles of the sea;"], ["ioe,", "yea,"], ["ma o tagata uma o e o le aiga o Isaraelu,", "and all the people who are of the house of Israel,"], ["o le a Ou faapotopoto mai,", "will I gather in,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["e tusa ma upu a le perofeta o Senosa,", "according to the words of the prophet Zenos,"], ["mai i itu e fa o le lalolagi.", "from the four quarters of the earth."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["ma o le a vaai le lalolagi uma i le olataga a le Alii, ua fetalai mai ai le perofeta;", "and all the earth shall see the salvation of the Lord,"], ["o atunuu uma,", "saith the prophet;"], ["ituaiga,", "every nation,"], ["gagana, ma nuu,", "kindred,"], ["o le a faamanuiaina.", "tongue and people shall be blessed."]]},
  {num:18,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["ua ou tusia nei mea mo o'u tagata,", "have written these things unto my people,"], ["atonu e mafai ai ona ou faatauanauina o i latou ia latou manatua le Alii lo latou Togiola.", "that perhaps I might persuade them that they would remember the Lord their Redeemer."]]},
  {num:19,words:[["O le mea lea,", "Wherefore,"], ["ou te tautala atu ai i le aiga uma o Isaraelu,", "I speak unto all the house of Israel,"], ["pe afai latou te maua nei mea.", "if it so be that they should obtain these things."]]},
  {num:20,words:[["Aua faauta,", "For behold,"], ["ua ia te a'u ni lagona malolosi i le agaga,", "I have workings in the spirit,"], ["ia ua ou vaivai ai ua oo lava ina vaivai ai o'u soogaivi uma,", "which doth weary me even that all my joints are weak,"], ["mo i latou o e o i Ierusalema;", "for those who are at Jerusalem;"], ["ona a na lē alofa mutimutivale le Alii,", "for had not the Lord been merciful,"], ["e faaali mai ia te a'u e uiga ia te i latou,", "to show unto me concerning them,"], ["e pei lava ona ia faaalia i perofeta anamua,", "even as he had prophets of old,"], ["po ua ou fano foi.", "I should have perished also."]]},
  {num:21,words:[["Ma sa faaalia moni lava e ia i perofeta anamua mea uma e uiga ia te i latou;", "And he surely did show unto the prophets of old all things concerning them;"], ["ma sa faaalia foi e ia i le toatele e uiga ia te i matou;", "and also he did show unto many concerning us;"], ["o le mea lea,", "wherefore,"], ["ua tatau ai ona matou iloa e uiga ia te i latou ona ua tusia ia mea i luga o papatusi apamemea.", "it must needs be that we know concerning them for they are written upon the plates of brass."]]},
  {num:22,words:[["O lenei sa oo ina aoao atu e a'u o Nifae,", "Now it came to pass that I,"], ["nei mea i o'u uso;", "Nephi,"], ["ma sa oo ina ou faitau atu ia te i latou mea e tele,", "did teach my brethren these things; and it came to pass that I did read many things to them,"], ["sa togitogia i luga o papatusi apamemea,", "which were engraven upon the plates of brass,"], ["ina ia mafai ona latou iloa e uiga i galuega a le Alii i isi laueleele,", "that they might know concerning the doings of the Lord in other lands,"], ["i totonu o tagata anamua.", "among people of old."]]},
  {num:23,words:[["Ma sa ou faitau atu ia te i latou le tele o mea sa tusia i totonu o tusi a Mose;", "And I did read many things unto them which were written in the books of Moses;"], ["ae ina ia mafai ona ou faatauanau atili atoatoa i latou ia talitonu i le Alii lo latou Togiola,", "but that I might more fully persuade them to believe in the Lord their Redeemer I did read unto them that which was written by the prophet Isaiah;"], ["o lea na ou faitau atu ai ia te i latou mea na tusia e le perofeta o Isaia ; ona sa ou faatatauina tusitusiga paia uma ia te i matou,", "for I did liken all scriptures unto us,"], ["ina ia avea ma o matou manuia ma aoaoga.", "that it might be for our profit and learning."]]},
  {num:24,words:[["O le mea lea na ou tautala atu ai ia te i latou,", "Wherefore I spake unto them,"], ["ua ou fai atu:", "saying:"], ["Inā outou faalogo mai ia i upu a le perofeta,", "Hear ye the words of the prophet,"], ["outou o e o se toe vaega o le aiga o Isaraelu,", "ye who are a remnant of the house of Israel,"], ["o se lala o e ua fa'iesea;", "a branch who have been broken off;"], ["inā outou faalogo mai ia i upu a le perofeta,", "hear ye the words of the prophet,"], ["ia ua tusia i le aiga uma o Isaraelu,", "which were written unto all the house of Israel,"], ["ma faatatau ia te outou lava,", "and liken them unto yourselves,"], ["ina ia mafai ona outou maua le faamoemoe e pei o outou uso o e na fa'i ese mai ai outou;", "that ye may have hope as well as your brethren from  whom ye have been broken off;"], ["ona o le ala lenei ua faapea ona tusi ai le perofeta.", "for after this manner has the prophet written."]]},
];
renderVerseSet(ch_19_Verses, 'ch19-verses');

var ch_20_Verses = [
  {num:1,words:[["Inā faalogo mai ia ma faafofoga mai i le mea lenei,", "Hearken and hear this,"], ["le aiga e o Iakopo,", "O house of Jacob,"], ["o e ua ta'ua i le igoa o Isaraelu,", "who are called by the name of Israel,"], ["ma ua o mai i fafo nai vai o Iuta,", "and are come forth out of the waters of Judah,"], ["po o mai i fafo o vai o le papatisoga ,", "or out of the waters of baptism,"], ["o e ua tauto i le suafa o le Alii,", "who swear by the name of the Lord,"], ["ma ta'uta'u atu le Atua o Isaraelu,", "and make mention of the God of Israel,"], ["a ua latou lē tauto i le faamaoni po o le amiotonu.", "yet they swear not in truth nor in righteousness."]]},
  {num:2,words:[["E ui i lea,", "Nevertheless,"], ["ua latou ta'ua i latou lava o le aai paia,", "they call them– selves of the holy city,"], ["ae ua latou lē faalagolago i le Atua o Isaraelu,", "but they do not stay themselves upon the God of Israel,"], ["o lē o le Alii o 'Au;", "who is the Lord of Hosts;"], ["ioe,", "yea,"], ["o le Alii o 'Au o lona suafa lea.", "the Lord of Hosts is his name."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["ua Ou tautino atu mea sa i ai muamua mai le amataga;", "I have declared the former things from the beginning;"], ["ma sa alu atu ia mea mai lo'u gutu,", "and they went forth out of my mouth,"], ["ma sa Ou faailoa atu i latou. Sa faafuasei ona Ou faailoa atu o i latou.", "and I showed them. I did show them suddenly."]]},
  {num:4,words:[["Ma sa Ou faia lenei mea ona sa Ou iloa ua e finauvale ma o lou ua o se uaua u'amea,", "And I did it because I knew that thou art obstinate, and thy neck is an iron sinew,"], ["ma o lou muaulu o se apamemea;", "and thy brow brass;"]]},
  {num:5,words:[["Ma sa Ou ta'u atu lava ia te oe mai le amataga;", "And I have even from the beginning declared to thee;"], ["ae lei oo mai ia mea sa Ou faailoa atu lava i latou ia te oe;", "before it came to pass I showed them thee;"], ["ma sa Ou faailoa atu i latou i le fefe ne'i e fai ane: O lo'u tupua na faia i latou,", "and I showed them for fear lest thou shouldst say—mine idol hath done them,"], ["ma o lo'u tupua ta,", "and my graven image,"], ["ma lo'u tupua gaosi na poloaiina i latou.", "and my molten image hath commanded them."]]},
  {num:6,words:[["Sa e vaai ma faalogo i nei mea uma;", "Thou hast seen and heard all this;"], ["ma e te lē tauina atu ea i latou? Ma sa Ou faaali atu foi ia te oe mea fou mai le taimi lea,", "and will ye not declare them? And that I have showed thee new things from this time,"], ["o mea natia lava,", "even hidden things,"], ["ae sa e lē iloaina i latou.", "and thou didst not know them."]]},
  {num:7,words:[["Ua foafoaina nei i latou,", "They are created now,"], ["ma ua lē mai i le amataga,", "and not from the beginning,"], ["ae sa ta'u atu lava i latou ia te oe ae lei oo i le aso na e lē faalogo ai ia te i latou,", "even before the day when thou heardest them not they were declared unto thee,"], ["ne'i e fai ane—Faauta sa Ou iloaina i latou.", "lest thou shouldst say—Behold I knew them."]]},
  {num:8,words:[["Ioe,", "Yea,"], ["ma sa e lē faalogo lava;", "and thou heardest not;"], ["ioe,", "yea,"], ["sa e lē iloaina lava;", "thou knewest not;"], ["ioe,", "yea,"], ["mai lena taimi sa lē tatalaina lou taliga;", "from that time thine ear was not opened;"], ["ona sa Ou iloa o le a e fai mea faalata tele,", "for I knew that thou wouldst deal very treacherously,"], ["ma sa ta'ua oe o se solitulafono mai i le manava.", "and wast called a transgressor from the womb."]]},
  {num:9,words:[["E ui i lea,", "Nevertheless,"], ["o le a Ou taofi lo'u ita ona o lo'u igoa ,", "for my name's sake will I defer mine anger,"], ["ma ona o lo'u viiga o le a Ou taofi ai a'u mai ia te oe,", "and for my praise will I refrain from thee,"], ["ina ia Ou lē vavaeeseina oe.", "that I cut thee not off."]]},
  {num:10,words:[["Aua faauta,", "For,"], ["ua Ou faamamāina oe,", "behold, I have refined thee,"], ["ua Ou filifilia oe mai i le ogaumu o puapuaga .", "I have chosen thee in the furnace of affliction."]]},
  {num:11,words:[["Ona o a'u lava,", "For mine own sake,"], ["ioe,", "yea,"], ["ona o a'u lava o le a Ou faia ai lenei mea,", "for mine own sake will I do this,"], ["ona o le a Ou lē tuua lo'u igoa ia faaeleeleaina,", "for I will not suffer my name to be polluted,"], ["ma o le a Ou lē tuu atu lo'u mamalu i se tasi.", "and I will not give my glory unto another."]]},
  {num:12,words:[["Faalogo mai ia ia te a'u,", "Hearken unto me,"], ["Iakopo e,", "O Jacob,"], ["ma Isaraelu la'u valaaulia,", "and Israel my called,"], ["ona o A'u o ia;", "for I am he;"], ["o A'u o lē e muamua ,", "I am the first,"], ["ma o A'u foi o lē e mulimuli .", "and I am also the last."]]},
  {num:13,words:[["O lo'u lima foi na faataotoina faavae o le lalolagi,", "Mine hand hath also laid the foundation of the earth,"], ["ma o lo'u lima taumatau na folasia le lagi. Ou te valaau atu ia te i latou ma latou tutu mai i luga faatasi.", "and my right hand hath spanned the heavens. I call unto them and they stand up together."]]},
  {num:14,words:[["Outou uma e,", "All ye,"], ["ia outou faapotopoto outou lava,", "assemble yourselves,"], ["ma faalogo mai;", "and hear;"], ["o ai se o i totonu ia te i latou na ia ta'u atu nei mea ia te i latou? Sa alofa le Alii ia te ia;", "who among them hath declared these things unto them? The Lord hath loved him;"], ["ioe,", "yea,"], ["ma o le a faataunuuina e ia lana fetalaiga na ia ta'u mai e ala mai ia te i latou;", "and he will fulfill his word which he hath declared by them;"], ["ma o le a fai e ia lona finagalo i luga o Papelonia ,", "and he will do his pleasure on Babylon,"], ["ma o le a oo mai lona aao i luga o Kaletaia.", "and his arm shall come upon the Chaldeans."]]},
  {num:15,words:[["O lenei foi,", "Also,"], ["ua fetalai mai le Alii:", "saith the Lord;"], ["O A'u o le Alii,", "I the Lord,"], ["ioe,", "yea,"], ["ua Ou tautala atu;", "I have spoken;"], ["ioe,", "yea,"], ["ua Ou valaaulia o ia e ta'u atu,", "I have called him to declare,"], ["ua Ou aumai o ia,", "I have brought him,"], ["ma o le a fai e ia lona ala ia manuia.", "and he shall make his way prosperous."]]},
  {num:16,words:[["Ia outou o mai faalatalata mai ia te a'u;", "Come ye near unto me;"], ["Ou te lei tautala atu faalilolilo ;", "I have not spoken in secret;"], ["mai lava i le amataga,", "from the beginning,"], ["mai le taimi sa ta'u atu ai lenei mea sa Ou tautala atu ai;", "from the time that it was declared have I spoken;"], ["ma o le Alii le Atua,", "and the Lord God,"], ["ma lona Agaga,", "and his Spirit,"], ["na auina mai a'u.", "hath sent me."]]},
  {num:17,words:[["Ma ua faapea ona fetalai mai o le Alii,", "And thus saith the Lord,"], ["lou Togiola ,", "thy Redeemer,"], ["le Paia e Toatasi o Isaraelu;", "the Holy One of Israel;"], ["ua Ou auina atu o ia,", "I have sent him,"], ["le Alii lou Atua o lē na te aoao ia te oe ia e manuia,", "the Lord thy God who teacheth thee to profit,"], ["o lē e taitai ia te oe i le ala e tatau ona e alu ai,", "who leadeth thee by the way thou shouldst go,"], ["na ia faia ia mea.", "hath done it."]]},
  {num:18,words:[["E, pe a na e faalogo mai i a'u poloaiga —manū po ua pei lou filemu o se vaitafe,", "O that thou hadst hearkened to my command ments— then had thy peace been as a river,"], ["ma pei lou amiotonu o galu o le sami;", "and thy righteousness as the waves of the sea."]]},
  {num:19,words:[["O lau fanau foi po ua pei o le oneone;", "Thy seed also had been as the sand;"], ["o fanau foi a lou manava po ua pei o ona iliili;", "the offspring of thy bowels like the gravel thereof;"], ["ma po ua lē vavaeesea pe soloiesea foi lona igoa mai i o'u luma.", "his name should not have been cut off nor destroyed from before me."]]},
  {num:20,words:[["Ia outou o ese atu ia mai Papelonia,", "Go ye forth of Babylon,"], ["ia outou sosola ese atu ia mai Kaletaia,", "flee ye from the Chaldeans,"], ["ma faatasi ma le leo o pesega ia outou ta'u atu,", "with a voice of singing declare ye,"], ["ta'u atu lenei mea,", "tell this,"], ["ia logo atu i tuluiga o le lalolagi;", "utter to the end of the earth;"], ["ia outou fai atu:", "say ye:"], ["Ua togiolaina e le Alii lana auauna o Iakopo.", "The Lord hath redeemed his servant Jacob."]]},
  {num:21,words:[["Ma sa latou lē fia feinu;", "And they thirsted not;"], ["sa taitaiina e ia i latou e ala atu i toafa;", "he led them through the deserts;"], ["sa faia e ia ia tafe mai le vai i fafo mai le papa mo i latou;", "he caused the waters to flow out of the rock for them;"], ["sa vavae foi e ia le papa ma puna mai ai le vai i fafo.", "he clave the rock also and the waters gushed out."]]},
  {num:22,words:[["Ma e ui ina sa faia e ia nei mea uma,", "And notwithstanding he hath done all this,"], ["ma mea tetele atu foi,", "and greater also,"], ["ua leai se filemu ,", "there is no peace,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["i e ua amioleaga.", "unto the wicked."]]},
];
renderVerseSet(ch_20_Verses, 'ch20-verses');

var ch_21_Verses = [
  {num:1,words:[["O lenei foi:", "And again:"], ["Faalogo mai ia,", "Hearken,"], ["outou e le aiga o Isaraelu,", "O ye house of Israel,"], ["outou uma o e ua fa'iesea ma tutuliesea i fafo ona o le amioleaga o faifeau o lo'u nuu;", "all ye that are broken off and are driven out because of the wickedness of the pastors of my people;"], ["ioe,", "yea,"], ["outou uma o e ua fa'iesea,", "all ye that are broken off,"], ["o e ua faataapeapeina solo,", "that are scattered abroad,"], ["o e o lo'u nuu,", "who are of my people,"], ["le aiga e o Isaraelu. Faalogo mai ia,", "O house of Israel. Listen,"], ["ia te a'u,", "O isles,"], ["outou e motu ,", "unto me,"], ["ma faalogo mai ia outou e tagata mai nuu mamao;", "and hearken ye people from far;"], ["na valaauina a'u e le Alii mai le manava;", "the Lord hath called me from the womb;"], ["na ia ta'ua lo'u igoa mai le manava o lo'u tinā.", "from the bowels of my mother hath he made mention of my name."]]},
  {num:2,words:[["Ma ua faia e ia lo'u gutu e pei o se pelu ma'ai;", "And he hath made my mouth like a sharp sword;"], ["o le paolo o lona aao na natia ai e ia a'u,", "in the shadow of his hand hath he hid me,"], ["ma faia a'u o se ufanafana ua faaiilaina,", "and made me a polished shaft;"], ["ma natia a'u e ia i lana utu;", "in his quiver hath he hid me;"]]},
  {num:3,words:[["Ma sa fetalai mai ia te a'u:", "And said unto me:"], ["O la'u auauna oe,", "Thou art my servant,"], ["Isaraelu e,", "O Israel,"], ["o lē o le a faamamaluina ai a'u.", "in whom I will be glorified."]]},
  {num:4,words:[["Ona Ou fai atu lea,", "Then I said,"], ["ua leai se aoga na Ou galue ai,", "I have labored in vain,"], ["ua Ou faaalu lo'u malosi mo meanoa ma mea lē aoga;", "I have spent my strength for naught and in vain;"], ["e moni lava ua i ai i le Alii lo'u faamasinoga,", "surely my judgment is with the Lord,"], ["ma o la'u galuega ua i ai i lo'u Atua.", "and my work with my God."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["ua fetalai mai le Alii—o lē na faia a'u mai le manava ina ia avea a'u ma ana auauna,", "saith the Lord—that formed me from the womb that I should be his servant,"], ["e toe aumai Iakopo ia te ia—e ui ina lei faapotopotoina Isaraelu,", "to bring Jacob again to him—though Israel be not gathered,"], ["ae o le a Ou mamalu i fofoga o le Alii,", "yet shall I be glorious in the eyes of the Lord,"], ["ma o lo'u Atua o le a avea ma o'u malosi.", "and my God shall be my strength."]]},
  {num:6,words:[["Ma sa fetalai mai o ia:", "And he said:"], ["O se mea māmā le avea o oe ma a'u auauna e faatutulai i luga ituaiga o Iakopo,", "It is a light thing that thou shouldst be my servant to raise up the tribes of Jacob,"], ["ma toefuatai faapolopolo o Isaraelu. O le a Ou tuu atu foi oe mo se malamalama i Nuuese ,", "and to restore the preserved of Israel. I will also give thee for a light to the Gentiles,"], ["ina ia mafai ona avea oe ma a'u olataga i tuluiga o le lalolagi.", "that thou mayest be my salvation unto the ends of the earth."]]},
  {num:7,words:[["Ua faapea ona fetalai mai o le Alii,", "Thus saith the Lord,"], ["le Togiola o Isaraelu,", "the Redeemer of Israel,"], ["lana Paia e Toatasi,", "his Holy One,"], ["ia te ia o lē ua itagia e tagata,", "to him whom man despiseth,"], ["ia te ia o lē ua inosia e atunuu,", "to him whom the nation abhorreth,"], ["i le auauna a e ua pule:", "to servant of rulers:"], ["O le a vaai tupu ma tutulai,", "Kings shall see and arise,"], ["o le a ifo foi aloalii,", "princes also shall worship,"], ["ona o le Alii o lē ua faamaoni.", "because of the Lord that is faithful."]]},
  {num:8,words:[["Ua faapea ona fetalai mai o le Alii:", "Thus saith the Lord:"], ["I se taimi sa tatau ai sa Ou faalogo atu ai ia te oe,", "In an acceptable time have I heard thee,"], ["motu e o le sami,", "O isles of the sea,"], ["ma i se aso o le olataga sa Ou fesoasoani atu ai ia te oe;", "and in a day of salvation have I helped thee;"], ["ma o le a Ou faasaoina oe,", "and I will preserve thee,"], ["ma tuu atu ia te oe la'u auauna mo se feagaiga a le nuu,", "and give thee my servant for a covenant of the people,"], ["e faatuina ai le eleele,", "to establish the earth,"], ["e fai ia avea ma tofi fanua tuufua;", "to cause to inherit the desolate heritages;"]]},
  {num:9,words:[["Ina ia mafai ona e fai atu i pagota :", "That thou mayest say to the prisoners:"], ["O atu ia;", "Go forth;"], ["ia i latou o e o nonofo i le pouliuli :", "to them that sit in darkness:"], ["Faaali atu outou lava. O le a latou aai i ala,", "Show yourselves. They shall feed in the ways,"], ["ma o o latou taaga o le a i ai i mea maualuluga uma.", "and their pastures shall be in all high places."]]},
  {num:10,words:[["O le a latou lē fia aai pe fia feinu,", "They shall not hunger nor thirst,"], ["pe taia foi i latou i le vevela po o le la;", "neither shall the heat nor the sun smite them;"], ["ona o ia o lē ua alofa mutimutivale ia te i latou o le a taitaia i latou,", "for he that hath mercy on them shall lead them,"], ["o tafatafa lava o puna o vai o le a taitai atu ai e ia i latou.", "even by the springs of water shall he guide them."]]},
  {num:11,words:[["Ma o le a Ou faia o'u mauga uma o se auala,", "And I will make all my mountains a way,"], ["ma o le a faamaualulugaina o'u ala tele.", "and my highways shall be exalted."]]},
  {num:12,words:[["Ona oo lea,", "And then,"], ["le aiga e o Isaraelu,", "O house of Israel,"], ["faauta,", "behold,"], ["o le a o mai i latou ia mai mea mamao;", "these shall come from far;"], ["ma faauta,", "and lo,"], ["i latou ia mai matu ma mai sisifo;", "these from the north and from the west;"], ["ma i latou ia mai le laueleele o Sainima.", "and these from the land of Sinim."]]},
  {num:13,words:[["Ia pepese ia,", "Sing,"], ["le lagi e;", "O heavens;"], ["ma olioli ia,", "and be joyful,"], ["le lalolagi e;", "O earth;"], ["ona o le a faamaututuina vae o i latou o e o i sasa'e;", "for the feet of those who are in the east shall be established;"], ["ma alalaga atu i pesega,", "and break forth into singing,"], ["mauga e,", "O mountains;"], ["ona o le a lē toe taiaina i latou,", "for they shall be smitten no more;"], ["ona ua faamafanafanaina e le Alii lona nuu,", "for the Lord hath comforted his people,"], ["ma o le a alofa mutimutivale i luga o ona tagata puapuagatia.", "and will have mercy upon his afflicted."]]},
  {num:14,words:[["Ae faauta,", "But,"], ["ua fai mai Siona:", "behold,"], ["Ua tuulafoaiina a'u e le Alii,", "Zion hath said:"], ["ma ua faagaloina a'u e lo'u Alii;", "The Lord hath forsaken me,"], ["peitai o le a faaali mai e ia e leai.", "and my Lord hath forgotten me—but he will show that he hath not."]]},
  {num:15,words:[["Aua pe mafai ea ona galo i se fafine lana tama o susu,", "For can a woman forget her sucking child,"], ["ina ia lē alofa o ia i le tama a lona manava? Ioe,", "that she should not have compassion on the son of her womb? Yea,"], ["atonu e galo ia te i latou,", "they may forget,"], ["ae o le a le galo ia te a'u oe,", "yet will I not forget thee,"], ["le aiga e o Isaraelu.", "O house of Israel."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ua Ou togitogia oe i luga o alofilima o o'u lima;", "I have graven thee upon the palms of my hands;"], ["o ou pa ua i ai pea i o'u luma.", "thy walls are continually before me."]]},
  {num:17,words:[["O le a faataalise atu au fanau e faasaga i ou tagata faaumatia mai;", "Thy children shall make haste against thy destroyers;"], ["ma o i latou na faatafunaina oe o le a o ese atu mai ia te oe.", "and they that made thee waste shall go forth of thee."]]},
  {num:18,words:[["Sii a'e ia ou mata ma vaavaai solo ma faauta;", "Lift up thine eyes round about and behold;"], ["ua faapotopoto faatasi e i latou uma nei i latou lava,", "all these gather themselves together,"], ["ma o le a latou o mai ia te oe. Ma e pei ona Ou ola,", "and they shall come to thee. And as I live,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["o le a e faaofuina moni oe faatasi ma i latou uma,", "thou  shalt surely clothe thee with them all,"], ["e pei o se mea teuteu,", "as with an ornament,"], ["ma fusi i latou e pei lava o se faatoanofotane.", "and bind them on even as a bride."]]},
  {num:19,words:[["Ona o ou gaogao ma ou nofoaga tuufua,", "For thy waste and thy desolate places,"], ["ma le laueleele o lou faafanoga,", "and the land of thy destruction,"], ["o le a lauitiiti tele lava i le taimi nei ona o e o nonofo ai;", "shall even now be too narrow by reason of the inhabitants;"], ["ma o le a mamao ese i latou na tofatumoanaina oe.", "and they that swallowed thee up shall be far away."]]},
  {num:20,words:[["O fanau o e o le a e maua,", "The children whom thou shalt have,"], ["ina ua mavae ona toesea mai ia te oe fanau muamua,", "after thou hast lost the first,"], ["o le a toe fai atu i ou taliga:", "shall again in thine ears say:"], ["Ua lauitiiti tele le nofoaga mo a'u;", "The place is too strait for me;"], ["tuu mai se nofoaga ia te a'u e mafai ona ou nofo ai.", "give place to me that I may dwell."]]},
  {num:21,words:[["Ona e fai ifo lea i lou loto:", "Then shalt thou say in thine heart:"], ["O ai ea na fanauina i latou nei ia te a'u,", "Who hath begotten me these,"], ["talu ai ona ua toesea a'u fanau mai ia te a'u,", "seeing I have lost my children,"], ["ma ua ou pa ,", "and am desolate,"], ["o se pagota,", "a captive,"], ["ma ua fesiitai solo i lea mea ma lea mea? Ma o ai ea na ia tausia a'e i latou nei? Faauta,", "and removing to and fro? And who hath brought up these? Behold,"], ["sa tu'ua a'u nao a'u;", "I was left alone;"], ["o i latou nei,", "these,"], ["sa i fea ea i latou?", "where have they been?"]]},
  {num:22,words:[["Ua faapea ona fetalai mai o le Alii le Atua:", "Thus saith the Lord God:"], ["Faauta,", "Behold,"], ["o le a Ou sii a'e lo'u lima i Nuuese ,", "I will lift up mine hand to the Gentiles,"], ["ma faatu la'u tagavai i le nuu;", "and set up my standard to the people;"], ["ma o le a latou aumai ou atalii i o latou lima ,", "and they shall bring thy sons in their arms,"], ["ma o ou afafine o le a tauaveina i luga o o latou tau'au.", "and thy daughters shall be carried upon their shoulders."]]},
  {num:23,words:[["Ma o le a avea tupu ma ou tamā tausitama ,", "And kings shall be thy nursing fathers,"], ["ma a latou masiofo ma ou tinā faafailele;", "and their queens thy nursing mothers;"], ["o le a latou ifo i lalo ia te oe ma o latou mata e faasaga i le eleele,", "they shall bow down to thee with their face towards the earth,"], ["ma etoeto ese le pefu o ou vae;", "and lick up the dust of thy feet;"], ["ma o le a e iloa o A'u o le Alii;", "and thou shalt know that I am the Lord;"], ["ona o le a lē maasiasi i latou o e e faatalitali ia te a'u.", "for they shall not be ashamed that wait for me."]]},
  {num:24,words:[["Ona e faoa ea le vete mai lē ua malosi,", "For shall the prey be taken from the mighty,"], ["pe laveaiina i latou ua faatagataotauaina tatau i le tulafono ?", "or the lawful captives delivered?"]]},
  {num:25,words:[["Peitai ua faapea ona fetalai mai o le Alii,", "But thus saith the Lord,"], ["e oo i e faatagataotauaina a lē ua malosi o le a aveese,", "even the captives of the mighty shall be taken away,"], ["ma o le vete a lē ua mata'utia o le a lavea'ia;", "and the prey of the terrible shall be delivered;"], ["ona o le a Ou finau ma ia e finau ma oe,", "for I will contend with him that contendeth with thee,"], ["ma o le a Ou faaolaina au fanau.", "and I will save thy children."]]},
  {num:26,words:[["Ma o le a Ou fafagaina i latou o e e faasaua ia te oe i o latou lava aano;", "And I will feed them that oppress thee with their own flesh;"], ["o le a latou onanā i o latou lava toto e pei ona onanā i le uaina suamalie;", "they shall be drunken with their own blood as with sweet wine;"], ["ma o le a iloa e tagata uma o A'u,", "and all flesh shall know that I,"], ["o le Alii,", "the Lord,"], ["o lou Faaola ma lou Togiola,", "am thy Savior and thy Redeemer,"], ["le Malosi e Toatasi o Iakopo.", "the Mighty One of Jacob."]]},
];
renderVerseSet(ch_21_Verses, 'ch21-verses');

var ch_22_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona faitau atu e a'u,", "And now it came to pass that after I,"], ["o Nifae,", "Nephi,"], ["nei mea sa togitogia i luga o papatusi apamemea,", "had read these things which were engraven upon the plates of brass,"], ["sa o mai o'u uso ia te a'u ma fai mai ia te a'u: O le a le uiga o nei mea na e faitau mai? Faauta,", "my brethren came unto me and said unto me:"], ["pe tatau ea ona malamalama i ai e tusa ma mea ua faaleagaga,", "What meaneth these things which ye have read? Behold,"], ["ia o le a faataunuuina e tusa ma le agaga,", "are they to be understood according to things which are spiritual,"], ["ae lē o la le tino?", "which shall come to pass according to the spirit and not the flesh?"]]},
  {num:2,words:[["Ma o a'u,", "And I,"], ["o Nifae,", "Nephi,"], ["sa ou fai atu ia te i latou:", "said unto them:"], ["Faauta sa faaali mai ia mea i le perofeta e le siufofoga o le Agaga ;", "Behold they were manifest unto the prophet by the voice of the Spirit;"], ["ona o le Agaga e ala mai ai le faaali mai o mea uma i perofeta ,", "for by the Spirit are all things made known unto the prophets,"], ["ia o le a oo mai i luga o le fanauga a tagata e tusa ai ma la le tino.", "which shall come upon the children of men according to the flesh."]]},
  {num:3,words:[["O le mea lea,", "Wherefore,"], ["o mea na ou faitauina o mea ia e faatatau i mea faaletino ma mea faaleagaga;", "the things of which I have read are things pertaining to things both temporal and spiritual;"], ["ona e foliga mai o le aiga o Isaraelu, o le a faataapeapeina lava,", "for it appears that the house of Israel,"], ["i se taimi,", "sooner or later,"], ["i luga o le lalolagi atoa,", "will be scattered upon all the face of the earth,"], ["ma i totonu foi o atunuu uma.", "and also among all nations."]]},
  {num:4,words:[["Ma faauta,", "And behold,"], ["e i ai le toatele ua uma ona leiloa mai le malamalama o i latou o e o i Ierusalema. Ioe,", "there are many who are already lost from the knowledge of those who are at Jerusalem. Yea,"], ["o le vaega tele o ituaiga uma ua taitaieseina atu;", "the more part of all the tribes have been led away;"], ["ma ua faataapeapeina i latou i lea mea ma lea mea i luga o motu o le sami;", "and they are scattered to and fro upon the isles of the sea;"], ["ma o le mea o latou i ai e leai se tasi o i tatou na te iloa,", "and whither they are none of us knoweth,"], ["ae ua tatou iloa ua taitaieseina atu i latou.", "save that we know that they have been led away."]]},
  {num:5,words:[["Ma talu ai ona ua taitaieseina atu o i latou,", "And since they have been led away,"], ["o mea nei ua valoia e faatatau ia te i latou,", "these things have been prophesied concerning them,"], ["ma e faatatau foi ia te i latou uma o e o le a faataapeapeina ma faafefilona'i pe a mavae le taimi nei,", "and also concerning all those who shall hereafter be scattered and be confounded,"], ["ona o le Paia e Toatasi o Isaraelu;", "because of the Holy One of Israel;"], ["ona o le a latou faamaaa o latou loto e faasaga ia te ia;", "for against him will they harden their hearts;"], ["o le mea lea,", "wherefore,"], ["o le a faataapeapeina ai i latou i totonu o atunuu uma ma o le a itagia e tagata uma.", "they shall be scattered among all nations and shall be hated of all men."]]},
  {num:6,words:[["E ui i lea,", "Nevertheless,"], ["a uma ona faafaileleina i latou e Nuuese ,", "after they shall be nursed by the Gentiles,"], ["ma uma ona sii atu e le Alii lona aao i luga o Nuuese ma faatutu i latou i luga e avea ma se tagavai,", "and the Lord has lifted up his hand upon the Gentiles and set them up for a standard,"], ["ma uma ona tauaveina a latou fanau i o latou lima,", "and their children have been carried in their arms,"], ["ma uma ona tauaveina o latou afafine i luga o o latou tau'au,", "and their daughters have been carried upon their shoulders,"], ["faauta o nei mea ua tautalagia ua faaletino;", "behold these things of which are spoken are temporal;"], ["ona ua faapea feagaiga a le Alii ma o tatou tamā;", "for thus are the covenants of the Lord with our fathers;"], ["ma ua uiga ia i tatou i aso o le a oo mai,", "and it meaneth us in the days to come,"], ["ma o tatou uso uma foi o e o le aiga o Isaraelu.", "and also all our brethren who are of the house of Israel."]]},
  {num:7,words:[["Ma o lona uiga e oo mai le taimi,", "And it meaneth that the time cometh that after all the house of Israel have been scattered and confounded,"], ["a uma ona faataapeapeina ma faafefilona'i o le aiga uma o Isaraelu,", "that the Lord God will raise up a mighty nation among the Gentiles,"], ["o le a faatu mai e le Alii le Atua se atunuu malosi i totonu o Nuuese , ioe,", "yea,"], ["i luga o lenei lava laueleele;", "even upon the face of this land;"], ["ma o i latou ia o le a faataapeapeina a tatou fanau.", "and by them shall our seed be scattered."]]},
  {num:8,words:[["Ma a uma ona faataapeapeina o a tatou fanau o le a alo atu le Alii le Atua e faia se galuega ofoofogia i totonu o Nuuese ,", "And after our seed is scattered the Lord God will proceed to do a marvelous work among the Gentiles,"], ["lea o le a taua tele ia tatou fanau;", "which shall be of great worth unto our seed;"], ["o le mea lea,", "wherefore,"], ["ua faatusaina lenei galuega i le tausia o i latou e Nuuese ma le tauaveina o i latou i o latou lima ma luga o o latou tau'au.", "it is likened unto their being nourished by the Gentiles and being carried in their arms and upon their shoulders."]]},
  {num:9,words:[["Ma o le a taua tele foi lenei galuega i Nuuese;", "And it shall also be of worth unto the Gentiles;"], ["ma e lē nao Nuuese ae o le aiga uma o Isaraelu,", "and not only unto the Gentiles but unto all the house of Israel,"], ["e faailoa atu ai feagaiga a le Tamā o le lagi na faia ia Aperaamo,", "unto the making known of the covenants of the Father of heaven unto Abraham,"], ["fai mai:", "saying:"], ["O lau fanau o le a manuia ai ituaiga uma o le lalolagi.", "In thy seed shall all the kindreds of the earth be blessed."]]},
  {num:10,words:[["Ma ou te manao,", "And I would,"], ["o'u uso e,", "my brethren,"], ["ia outou iloa e lē mafai ona manuia ituaiga uma o le lalolagi sei vagana ai ua afe e ia lona aao i mata o atunuu.", "that ye should know that all the kindreds of the earth cannot be blessed unless he shall make bare his arm in the eyes of the nations."]]},
  {num:11,words:[["O le mea lea,", "Wherefore,"], ["o le a alo atu ai le Alii le Atua e afe lona aao i mata o atunuu uma,", "the Lord God will proceed to make bare his arm in the eyes of all the nations,"], ["i le faataunuuina o ana feagaiga ma lana talalelei ia i latou o e o le aiga o Isaraelu.", "in bringing about his covenants and his gospel unto those who are of the house of Israel."]]},
  {num:12,words:[["O le mea lea,", "Wherefore,"], ["o le a toe aumai ai e ia i latou i fafo mai le faatagataotauaina,", "he will bring them again out of captivity,"], ["ma o le a faapotopotoina faatasi i latou i laueleele o o latou tofi;", "and they shall be gathered together to the lands of their inheritance;"], ["ma o le a aumai i latou i fafo mai le lē mailoa ma i fafo o le pogisa ;", "and they shall be brought out of obscurity and out of darkness;"], ["ma o le a latou iloa o le Alii o lo latou Faaola lea ma lo latou Togiola,", "and they shall know that the Lord is their Savior and their Redeemer,"], ["le Malosi Silisili e Toatasi o Isaraelu.", "the Mighty One of Israel."]]},
  {num:13,words:[["Ma o le toto o lena ekalesia tele ma le inosia,", "And the blood of that great and abominable church,"], ["le fafine talitane lea o le lalolagi uma,", "which is the whore of all the earth,"], ["o le a liliu ifo i luga o o latou lava ulu;", "shall turn upon their own heads;"], ["ona o le a latou fetaua'i i totonu o i latou lava,", "for they shall war among themselves,"], ["ma o le pelu a o latou lava lima o le a pa'ū ifo i luga o o latou lava ulu,", "and the sword of their own hands shall fall upon their own heads,"], ["ma o le a latou onanā i o latou lava toto.", "and they shall be drunken with their own blood."]]},
  {num:14,words:[["Ma o atunuu uma e tau faasaga mai ia te oe,", "And every nation which shall war against thee,"], ["le aiga e o Isaraelu,", "O house of Israel,"], ["o le a toe liliu faasaga i le tasi,", "shall be turned one against another,"], ["ma o le a latou pauu i i totonu o le lua na latou elia e mailei ai tagata o le Alii. Ma o i latou uma o e tau faasaga mai ia Siona o le a faaumatia,", "and they shall fall into the pit which they digged to ensnare the people of the Lord. And all that fight against Zion shall be destroyed,"], ["ma o lena fafine talitane tele,", "and that great whore,"], ["o lē ua ia faapi'opi'oina ala sa'o o le Alii,", "who hath perverted the right ways of the Lord,"], ["ioe,", "yea,"], ["lena ekalesia tele ma le inosia,", "that great and abominable church,"], ["o le a solo i le efuefu ma o le a tele lava lona pa'ū.", "shall tumble to the dust and great shall be the fall of it."]]},
  {num:15,words:[["Aua faauta,", "For behold,"], ["ua fetalai mai le perofeta,", "saith the prophet,"], ["ua vave ona oo mai o le taimi o le a lē toe maua ai e Satani se pule i loto o le fanauga a tagata;", "the time cometh speedily that Satan shall have no more power over the hearts of the children of men;"], ["ona ua lata ona oo mai o le aso e avea ai e pei o tagutugutu o saito i latou uma o e faamaualuluga ma i latou o e fai amioleaga;", "for the day soon cometh that all the proud and they who do wickedly shall be as stubble;"], ["ma e oo mai le aso o le a susunu ai i latou.", "and the day cometh that they must be burned."]]},
  {num:16,words:[["Ona ua lata ona oo mai o le taimi e sasaa mai ai le atoatoa o le toasa o le Atua i luga o le fanauga uma a tagata;", "For the time soon cometh that the fulness of the wrath of God shall be poured out upon all the children of men;"], ["ona o le a lē tuua e ia 'ia faaumatia e e amioleaga e amiotonu.", "for he will not suffer that the wicked shall destroy the righteous."]]},
  {num:17,words:[["O le mea lea,", "Wherefore,"], ["o le a faasao ai e ia e ua amiotonu i lona mana,", "he will preserve the righteous by his power,"], ["e tusa pe afai o le a tatau ona oo mai ai o le atoatoa o lona toasa,", "even if it so be that the fulness of his wrath must come,"], ["ma faasao ai e ua amiotonu,", "and the righteous be preserved,"], ["e oo lava i le faaumatiaina o o latou fili i le afi. O le mea lea,", "even unto the destruction of their enemies by fire. Wherefore,"], ["e lē tatau ai i e amiotonu ona fefefe;", "the righteous need not fear;"], ["ona ua fetalai mai le perofeta,", "for thus saith the prophet,"], ["o le a faaolaina i latou,", "they shall be saved,"], ["e tusa pe tatau ai ona faia faapea i le afi.", "even if it so be as by fire."]]},
  {num:18,words:[["Faauta o'u uso e,", "Behold,"], ["ou te fai atu ia te outou,", "my brethren,"], ["ua vave ona oo mai o nei mea;", "I say unto you,"], ["ioe,", "that these things must shortly come;"], ["e oo i le toto,", "yea,"], ["ma le afi,", "even blood,"], ["ma le puao o le asu,", "and fire,"], ["o le a oo mai;", "and vapor of smoke must come;"], ["ma e ao ina oo mai i luga o lenei lalolagi;", "and it must needs be upon the face of this earth;"], ["ma e oo mai i tagata e tusa ai ma la le tino pe afai latou te faamaaa o latou loto e faasaga i le Paia e Toatasi o Isaraelu.", "and it cometh unto men according to the flesh if it so be that they will harden their hearts against the Holy One of Israel."]]},
  {num:19,words:[["Aua faauta,", "For behold,"], ["o le a lē fano e amiotonu;", "the righteous shall not perish;"], ["ona o le a oo moni mai lava le taimi e vavae ese ai i latou uma o e e faasagatau mai ia Siona.", "for the time surely must come that all they who fight against Zion shall be cut off."]]},
  {num:20,words:[["Ma o le a saunia moni lava e le Alii se ala mo ona tagata,", "And the Lord will surely prepare a way for his people,"], ["i le faataunuuina o upu a Mose,", "unto the fulfill– ing of the words of Moses,"], ["ia na fetalai mai e ia,", "which he spake,"], ["fai mai:", "saying:"], ["O le a faatu mai e le Alii lo outou Atua se perofeta mo outou,", "A prophet shall the Lord your God raise up unto you,"], ["e pei o a'u;", "like unto me;"], ["o ia ia outou faalogo i ai i mea uma e fai mai ai o ia ia te outou.", "him shall ye hear in all things whatsoever he shall say unto you."], ["Ma o le a oo mai foi, o i latou uma o e e lē faalogo i lena perofeta, o le a vavae ese mai totonu o le nuu.", "And it shall come to pass that all those who will not hear that prophet shall be cut off from among the people."]]},
  {num:21,words:[["Ma o lenei,", "And now I,"], ["o a'u,", "Nephi,"], ["o Nifae, ou te ta'u atu ia te outou,", "declare unto you,"], ["o lenei perofeta na tautala i ai Mose o le Paia e Toatasi lea o Isaraelu;", "that this prophet of whom Moses spake was the Holy One of Israel;"], ["o le mea lea,", "wherefore,"], ["o le a faia e ia faamasinoga i le amiotonu.", "he shall execute judgment in righteousness."]]},
  {num:22,words:[["Ma o e amiotonu e lē tatau ona matata'u,", "And the righteous need not fear,"], ["ona o i latou ia o le a lē faaumatiaina. Ae o le malo o le tiapolo,", "for they are those who shall not be confounded. But it is the kingdom of the devil,"], ["lea o le a ati a'e i totonu o le fanauga a tagata,", "which shall be built up among the children of men,"], ["le malo lea ua faatuina i totonu o i latou o e o i la le tino—", "which kingdom is established among them which are in the flesh—"]]},
  {num:23,words:[["Ona ua vave ona oo mai o le taimi,", "For the time speedily shall come that all churches which are built up to get gain,"], ["o ekalesia uma ua ati a'e i luga ia maua ai le 'oa,", "and all those who are built up to get power over the flesh,"], ["ma o i latou uma o e ua ati a'e i luga ia maua ai le mana i la le tino,", "and those who are built up to become popular in the eyes of the world,"], ["ma i latou o e ua ati a'e i luga ina ia tausaafia ai i mata o le lalolagi, ma i latou o e ua saili tuinanau o le tino ma mea o le lalolagi,", "and those who seek the lusts of the flesh and the things of the world,"], ["ma fai ituaiga uma o amioletonu;", "and to do all manner of iniquity;"], ["ioe,", "yea,"], ["i se aotelega,", "in fine,"], ["o i latou uma o e ua auai i le malo o le tiapolo,", "all those who belong to the kingdom of the devil are they who need fear,"], ["o i latou ia e tatau ona matata'u,", "and tremble,"], ["ma tetete, ma galulu ;", "and quake;"], ["o i latou ia o i latou o le a ave ifo maualalalo i le efuefu;", "they are those who must be brought low in the dust;"], ["o i latou ia o i latou o e o le a susunuina e pei o tagutugutu o saito;", "they are those who must be consumed as stubble;"], ["ma ua tusa lenei ma upu a le perofeta.", "and this is according to the words of the prophet."]]},
  {num:24,words:[["Ma ua vave ona oo mai o le taimi e ao ai ina taitai a'e e amiotonu e pei o ni tamaipovi o le lotoa,", "And the time cometh speedily that the righteous must be led up as calves of the stall,"], ["ma ao ai ina nofotupu le Paia e Toatasi o Isaraelu i le pule aoao,", "and the Holy One of Israel must reign in dominion,"], ["ma le malosi,", "and might,"], ["ma le mana,", "and power,"], ["ma le mamalu tele.", "and great glory."]]},
  {num:25,words:[["Ma e faapotopoto mai e ia ana fanau mai itu e fa o le lalolagi;", "And he gathereth his children from the four quarters of the earth;"], ["ma e faitau e ia ana mamoe,", "and he numbereth his sheep,"], ["ma ua latou iloa o ia;", "and they know him;"], ["ma o le a tasi le lafu ma tasi le leoleo mamoe;", "and there shall be one fold and one shepherd;"], ["ma o le a ia fafaga i ana mamoe,", "and he shall feed his sheep,"], ["ma o le a latou maua taaga ia te ia.", "and in him they shall find pasture."]]},
  {num:26,words:[["Ma ona o le amiotonu o ona tagata,", "And because of the righteousness of his people,"], ["ua leai ai se mana o Satani ;", "Satan has no power;"], ["o le mea lea,", "wherefore,"], ["e lē mafai ai ona tatalaina o ia mo le va o tausaga e tele;", "he cannot be loosed for the space of many years;"], ["ona ua leai se mana e ia te ia i luga o loto o tagata,", "for he hath no power over the hearts of the people,"], ["ona ua latou mau i le amiotonu,", "for they dwell in righteous– ness,"], ["ma ua nofotupu le Paia e Toatasi o Isaraelu.", "and the Holy One of Israel reigneth."]]},
  {num:27,words:[["Ma o lenei faauta,", "And now behold,"], ["o a'u,", "I,"], ["o Nifae,", "Nephi,"], ["ou te fai atu ia te outou o nei mea uma o le a oo mai e tusa ma la le tino.", "say unto you that all these things must come according to the flesh."]]},
  {num:28,words:[["Ae faauta,", "But,"], ["o le a nonofo saogalemu atunuu,", "behold,"], ["ituaiga,", "all nations,"], ["gagana,", "kindreds,"], ["ma tagata uma i le Paia e Toatasi o Isaraelu,", "tongues,"], ["pe afai latou te salamo .", "and people shall dwell safely in the Holy One of Israel if it so be that they will repent."]]},
  {num:29,words:[["Ma o lenei,", "And now I,"], ["o a'u o Nifae,", "Nephi,"], ["ua faaiu a'u upu;", "make an end;"], ["ona ua ou fefe e toe tautala atili atu e uiga i nei mea.", "for I durst not speak further as yet concerning these things."]]},
  {num:30,words:[["O le mea lea,", "Wherefore,"], ["o'u uso e,", "my brethren,"], ["ou te manao ia outou iloa o mea ua tusia i luga o papatusi apamemea ua moni;", "I would that ye should consider that the things which have been written upon the plates of brass are true;"], ["ma ua latou molimau mai e ao i le tagata ona usiusitai i poloaiga a le Atua.", "and they testify that a man must be obedient to the commandments of God."]]},
  {num:31,words:[["O le mea lea,", "Wherefore,"], ["e lē tatau ona outou manatu faapea ua nao a'u ma lo'u tamā ua molimauina,", "ye need not suppose that I and my father are the only ones that have testified,"], ["ma aoao atu foi ia mea. O le mea lea,", "and also taught them. Wherefore,"], ["afai tou te usiusitai i poloaiga ,", "if ye shall be obedient to the commandments,"], ["ma tutumau e oo i le iuga,", "and endure to the end,"], ["o le a faaolaina outou i le aso gataaga. Ma ua faapea lava. Amene.", "ye shall be saved at the last day. And thus it is. Amen."]]},
];
renderVerseSet(ch_22_Verses, 'ch22-verses');

})();